-- Poems batch 120
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('fb81cd1c-ec35-495b-8c94-dc5ce6463cc6','二愛  其二','陸游','宋','宋诗','song-poetry','','[]','門外秋水深，日日集鷗鷺。',72,'全唐诗/poet.song.131000.json','["門外秋水深，日日集鷗鷺。", "是豈相與期，正以同類故。", "殘年過七十，朋舊半丘墓。", "非吾濟世心，嘆息莫予助。", "人生非金石，去日如脫兔。", "三復東野詩，獨立悲歲暮。"]'),
('d3d582d7-7f6d-4dc9-829b-ec9b30dc21f1','蜻蜓浦','陸游','宋','宋诗','song-poetry','','[]','舍北蜻蜓浦，新秋偶一來。',48,'全唐诗/poet.song.131000.json','["舍北蜻蜓浦，新秋偶一來。", "菱絲烟際老，芡觜露中開。", "漁火明還滅，沙禽去却回。", "吾行興無盡，舟子莫相催。"]'),
('947effd9-6bac-4c34-a43d-3d8fbf6d7ad0','題韓運鹽竹隱堂絕句三首  其一','陸游','宋','宋诗','song-poetry','','[]','鄴下王孫今勝流，相逢三伏凜生秋。',32,'全唐诗/poet.song.131000.json','["鄴下王孫今勝流，相逢三伏凜生秋。", "未嘗一日可無竹，似是前身王子猷。"]'),
('e318bec3-5baf-4f35-93fa-905d895ff466','題韓運鹽竹隱堂絕句三首  其二','陸游','宋','宋诗','song-poetry','','[]','塵埃車馬日駸駸，誰解從君一散襟。',32,'全唐诗/poet.song.131000.json','["塵埃車馬日駸駸，誰解從君一散襟。", "待我清秋有閑日，抱琴來寫萬龍吟。"]'),
('4e937185-e8ce-480b-9cfe-9d80832903b3','題韓運鹽竹隱堂絕句三首  其三','陸游','宋','宋诗','song-poetry','','[]','靜處知君解策勳，爐香裊裊起微雲。',32,'全唐诗/poet.song.131000.json','["靜處知君解策勳，爐香裊裊起微雲。", "岸巾不住尋青士，欹枕還應對墨君。"]'),
('f79663f3-dcda-40ca-a2f4-5ac3b4f00288','哭杜府君','陸游','宋','宋诗','song-poetry','','[]','叔高初過我，風度何玉立。',180,'全唐诗/poet.song.131000.json','["叔高初過我，風度何玉立。", "超然眾客中，可慕不待揖。", "入都多賓友，伯高數來集。", "質如琮璧潤，氣等芝蘭襲。", "晚乃過仲高，午日曬行笠。", "匆匆遽別去，悵望空怏悒。", "有如此三高，青紫何足拾。", "豈無知之者，相視莫維縶。", "窮魚雖相憫，可愧吐微溼。", "亦知尊公賢，何止蓋鄉邑。", "向風每拳拳，識面真汲汲。", "秋風忽聞訃，執書嘆以泣。", "造門不自决，追悔今何及。", "又聞著書富，手澤溢巾笈。", "哀毀要無益，遺稿勤綴緝。"]'),
('4cf5e67b-334d-46d1-9773-50377f4cb842','初秋夜坐','陸游','宋','宋诗','song-poetry','','[]','徂歲又如許，吾生真若浮。',48,'全唐诗/poet.song.131000.json','["徂歲又如許，吾生真若浮。", "露蟬鳴達曉，風葉墮先秋。", "野迥星辰大，天空河漢流。", "胡床幸亡恙，且復寄悠悠。"]'),
('e973fb17-26ce-46e8-a328-73a3fb7f064a','宴坐自午至暮','陸游','宋','宋诗','song-poetry','','[]','身外寥寥掃怨恩，胸中浩浩納乾坤。',64,'全唐诗/poet.song.131000.json','["身外寥寥掃怨恩，胸中浩浩納乾坤。", "飽經世事常高枕，慣見人情不署門。", "孤日夜分生海底，百川秋漲泝河源。", "珥貂碧落從來事，東訪蓬萊不足言。"]'),
('3babec27-fe31-47f6-b03e-7eebe718643a','舟中詠落景餘清暉輕橈弄溪渚之句蓋孟浩然耶溪泛舟詩也因以其句爲韵賦詩十首  其一','陸游','宋','宋诗','song-poetry','','[]','獨鶴還故鄉，巋然但城郭。',48,'全唐诗/poet.song.131000.json','["獨鶴還故鄉，巋然但城郭。", "出門無與遊，所至苦寂寞。", "裹飯事幽討，此計殊不惡。", "薄暮宿漁家，蒼烟带墟落。"]'),
('bfec5a33-9740-43c1-85f2-182ce367dfe4','舟中詠落景餘清暉輕橈弄溪渚之句蓋孟浩然耶溪泛舟詩也因以其句爲韵賦詩十首  其二','陸游','宋','宋诗','song-poetry','','[]','維舟入谷口，信步造異境。',48,'全唐诗/poet.song.131000.json','["維舟入谷口，信步造異境。", "隔籬雞犬聲，滿地梧楸影。", "瓦甑炊香稻，石泉汲新井。", "人間苦偪仄，愛此須臾景。"]'),
('3a53f0fc-b2d2-4f4f-9fef-0678ab710e0b','舟中詠落景餘清暉輕橈弄溪渚之句蓋孟浩然耶溪泛舟詩也因以其句爲韵賦詩十首  其三','陸游','宋','宋诗','song-poetry','','[]','老圃髮如霜，見客能廢鋤。',48,'全唐诗/poet.song.131000.json','["老圃髮如霜，見客能廢鋤。", "與坐使之年，自云八十餘。", "老身六朝民，草舍數世居。", "力守遠祖言，一字不學書。"]'),
('2643e725-5fd2-45b3-ac49-6f31c208e131','舟中詠落景餘清暉輕橈弄溪渚之句蓋孟浩然耶溪泛舟詩也因以其句爲韵賦詩十首  其四','陸游','宋','宋诗','song-poetry','','[]','沿溪得茅店，酒旗出柴荆。',48,'全唐诗/poet.song.131000.json','["沿溪得茅店，酒旗出柴荆。", "杖頭錢已空，一醉何由成。", "主人語鄭重，手把甕面清。", "勸我姑小留，溪魚亦可烹。"]'),
('2eedd814-0404-461f-a17d-a51a850d087b','舟中詠落景餘清暉輕橈弄溪渚之句蓋孟浩然耶溪泛舟詩也因以其句爲韵賦詩十首  其五','陸游','宋','宋诗','song-poetry','','[]','秦皇酒甕邊，古有釣魚磯。',48,'全唐诗/poet.song.131000.json','["秦皇酒甕邊，古有釣魚磯。", "我來必竟日，時挈雙鯉歸。", "白鷺真可人，常先孤棹飛。", "高詠江練句，令人憶玄暉。"]'),
('f7a27ea0-b85f-4b53-b274-8aab4ba561fc','舟中詠落景餘清暉輕橈弄溪渚之句蓋孟浩然耶溪泛舟詩也因以其句爲韵賦詩十首  其六','陸游','宋','宋诗','song-poetry','','[]','鏡湖三百里，風止鏡面平。',48,'全唐诗/poet.song.131000.json','["鏡湖三百里，風止鏡面平。", "持以照吾心，俗塵安得生。", "散髮鷗鷺間，萬事秋毫輕。", "誰能拂東絹，寫我孤舟橫。"]'),
('14fec00d-e76e-452e-aac5-be6b811c832c','舟中詠落景餘清暉輕橈弄溪渚之句蓋孟浩然耶溪泛舟詩也因以其句爲韵賦詩十首  其七','陸游','宋','宋诗','song-poetry','','[]','朝發雲根寺，暮宿烟際橋。',48,'全唐诗/poet.song.131000.json','["朝發雲根寺，暮宿烟際橋。", "冷螢溼不飛，潜魚驚自跳。", "菱船歌裊裊，荻浦風蕭蕭。", "平明宿鳥起，我亦理歸橈。"]'),
('adb54232-b455-4641-850a-662f8816e749','舟中詠落景餘清暉輕橈弄溪渚之句蓋孟浩然耶溪泛舟詩也因以其句爲韵賦詩十首  其八','陸游','宋','宋诗','song-poetry','','[]','古祠照滄波，老木閟雲洞。',48,'全唐诗/poet.song.131000.json','["古祠照滄波，老木閟雲洞。", "輕舟不摇檝，正用一風送。", "汲井漱甘液，掃榻寓幽夢。", "所恨山未深，城笳聽三弄。"]'),
('90957bee-c1cb-402f-a01a-90555702b515','舟中詠落景餘清暉輕橈弄溪渚之句蓋孟浩然耶溪泛舟詩也因以其句爲韵賦詩十首  其九','陸游','宋','宋诗','song-poetry','','[]','禹穴探斷簡，樵風泛清溪。',48,'全唐诗/poet.song.131000.json','["禹穴探斷簡，樵風泛清溪。", "倒影森松桂，避船散鳧鷖。", "塵中有異境，十里青玻璃。", "高塔忽招人，湖邊日未低。"]'),
('09386b77-52b7-4d53-b821-3a03d02e3734','舟中詠落景餘清暉輕橈弄溪渚之句蓋孟浩然耶溪泛舟詩也因以其句爲韵賦詩十首  其一○','陸游','宋','宋诗','song-poetry','','[]','溪行已清秋，還舍尚殘暑。',48,'全唐诗/poet.song.131000.json','["溪行已清秋，還舍尚殘暑。", "天公爲解圍，簾櫳過疏雨。", "青蔬喜小摘，紅粒亦新杵。", "一飽坐北軒，蘋花泣烟渚。"]'),
('c6517808-448f-4b1d-90bd-d140d2b24977','浮生','陸游','宋','宋诗','song-poetry','','[]','浮生真是寄郵亭，短鬢匆匆失故青。',64,'全唐诗/poet.song.131000.json','["浮生真是寄郵亭，短鬢匆匆失故青。", "睡少始知愁有力，病增方嘆藥無靈。", "謀生懶似逢秋燕，訪舊疏於欲旦星。", "自笑若爲銷此恨，濁醪聊復倒餘瓶。"]'),
('8e15f970-cc44-4408-ab85-a182b1c62f02','秋夜','陸游','宋','宋诗','song-poetry','','[]','高屐枯筇一老翁，燈前自笑髮如蓬。',64,'全唐诗/poet.song.131000.json','["高屐枯筇一老翁，燈前自笑髮如蓬。", "泠泠月浸荒庭竹，淅淅風凋古井桐。", "病思未蘇秋尚淺，醉魂初醒夜方中。", "故人萬里無消息，便擬江頭問斷鴻。"]'),
('2c136ab1-d07a-46a2-973f-9e9785ec6aaa','秋夜紀懷三首  其一','陸游','宋','宋诗','song-poetry','','[]','缺月淡欲盡，老雞鳴苦遲。',48,'全唐诗/poet.song.131000.json','["缺月淡欲盡，老雞鳴苦遲。", "聊爲待旦坐，不作感秋悲。", "魯叟一王法，豳人七月詩。", "平生經世志，老死欲誰期。"]'),
('e53cf5d7-694b-4a2e-87d8-730ea4b8960f','秋夜紀懷三首  其二','陸游','宋','宋诗','song-poetry','','[]','瞿曇起西域，老氏奮中州。',48,'全唐诗/poet.song.131000.json','["瞿曇起西域，老氏奮中州。", "談理一家說，蠹民千載憂。", "橫流當有自，獨立豈相仇。", "垂世詩書在，兒童勿外求。"]'),
('c3ab458c-cd6c-4968-a64a-454d773164f8','秋夜紀懷三首  其三','陸游','宋','宋诗','song-poetry','','[]','北斗垂莽蒼，明河浮太清。',48,'全唐诗/poet.song.131000.json','["北斗垂莽蒼，明河浮太清。", "風林一葉下，露草百蟲鳴。", "病入新凉減，詩從半睡成。", "還思散關路，炬火驛前迎。"]'),
('568e3b98-5059-49b1-91e5-5c71db4f9dbf','書懷','陸游','宋','宋诗','song-poetry','','[]','蕭颯先秋鬢，龍鍾未死身。',48,'全唐诗/poet.song.131000.json','["蕭颯先秋鬢，龍鍾未死身。", "不惟今日老，已是一生貧。", "食菜從兒瘦，關門任客嗔。", "世間餘一念，河雒尚胡塵。"]'),
('8c56fe80-93bf-4494-b8e9-3aa741df24a6','林居秋日','陸游','宋','宋诗','song-poetry','','[]','桔槔引水繞荒畦，病卧蝸廬不厭低。',64,'全唐诗/poet.song.131000.json','["桔槔引水繞荒畦，病卧蝸廬不厭低。", "小聚數家秋靄裏，平波千頃夕陽西。", "亭皋草木猶葱蒨，天上風雲已慘凄。", "逋負如山炊米盡，終年枉是把鉏犁。"]'),
('21adffe5-7ca2-44b8-9492-f94751f45643','七月二十四日作','陸游','宋','宋诗','song-poetry','','[]','閑拂青銅一惘然，此生應老海雲邊。',64,'全唐诗/poet.song.131000.json','["閑拂青銅一惘然，此生應老海雲邊。", "凉颸入袂詩初就，幽鳥呼人夢不全。", "天上鵲歸星渚冷，月中桂長露華鮮。", "射胡羽箭凋零盡，坐負心期四十年。"]'),
('a2bc8b52-5cce-4273-b440-b3589ba7b279','枕上作時聞臨海四明皆大水','陸游','宋','宋诗','song-poetry','','[]','撫枕時時猶嘆欷，阨窮已極畏兇饑。',64,'全唐诗/poet.song.131000.json','["撫枕時時猶嘆欷，阨窮已極畏兇饑。", "雨聲淅瀝孤齋冷，客夢蕭條萬里歸。", "山邑風雷移蜃穴，海城水潦半民扉。", "如雲秋稼方相賀，一飽還憂與願違。"]'),
('fc9c0158-5ac0-44db-8f86-c0875948bc0e','書懷','陸游','宋','宋诗','song-poetry','','[]','漫道年來未極衰，窮途憔悴實難支。',64,'全唐诗/poet.song.131000.json','["漫道年來未極衰，窮途憔悴實難支。", "半分臂減休文瘦，七尺軀存曼倩饑。", "尚憶青衫陪眾雋，寧期白首負明時。", "悠然萬里烟波興，除却沙鷗總不知。"]'),
('cfadc493-1121-4bcb-8c12-cdd11b0cdf19','秋陰至近村','陸游','宋','宋诗','song-poetry','','[]','村店閑尋酒，筇枝瘦倚肩。',48,'全唐诗/poet.song.131000.json','["村店閑尋酒，筇枝瘦倚肩。", "雲齊龍卷雨，野曠鶴盤天。", "露井飄桐後，清觴泛菊前。", "欲歸還小立，搔首意悠然。"]'),
('3f80c84f-cdfa-4e48-9beb-d15f020bc50b','閑居自述','陸游','宋','宋诗','song-poetry','','[]','自許山翁懶是真，紛紛外物豈關身。',64,'全唐诗/poet.song.131000.json','["自許山翁懶是真，紛紛外物豈關身。", "花如解笑還多事，石不能言最可人。", "凈掃明窗憑素几，閑穿密竹岸烏巾。", "殘年自有青天管，便是無錐也未貧。"]'),
('d54fd805-ad6d-4c00-bd08-40b122bdda02','秋雨初霽試筆','陸游','宋','宋诗','song-poetry','','[]','墨入紅絲點漆濃，閑將倦筆寫秋容。',64,'全唐诗/poet.song.131000.json','["墨入紅絲點漆濃，閑將倦筆寫秋容。", "雨聲已斷時聞滴，雲氣將歸別起峰。", "斜日半穿臨水竹，好風遥送隔城鐘。", "遠遊更動輕舟興，太息何人解見從。"]'),
('ebf99d3a-a542-496c-819b-cb87443a5cc1','幽懷','陸游','宋','宋诗','song-poetry','','[]','苫茅架竹亦吾廬，病起幽懷得小攄。',64,'全唐诗/poet.song.131000.json','["苫茅架竹亦吾廬，病起幽懷得小攄。", "愛酒已捐身外事，閉門猶讀死前書。", "鄰家人喜添新犢，小市奴歸得早蔬。", "但使身安歲中熟，敢辭老境落樵漁。"]'),
('b9d19849-0c39-49b0-a02b-54831b6a4d03','雨後出門散步二首  其一','陸游','宋','宋诗','song-poetry','','[]','細水穿沙溜，殘雲扶雨歸。',48,'全唐诗/poet.song.131000.json','["細水穿沙溜，殘雲扶雨歸。", "不成遊酒市，且作倚漁扉。", "老大徂年速，羈窮壯志違。", "破裘雖百結，猶勝泣牛衣。"]'),
('20d6ab87-f383-4a08-93a6-4a723ed75ef2','雨後出門散步二首  其二','陸游','宋','宋诗','song-poetry','','[]','病葉常先霣，寒潮只暗生。',48,'全唐诗/poet.song.131000.json','["病葉常先霣，寒潮只暗生。", "扶衰賴藥石，隨意出柴荆。", "細路牛欄溼，疏籬績火明。", "枯榮不須計，千古一棋枰。"]'),
('8f4fe834-dacb-4418-88f0-6efabf2fc493','秋夜示兒輩','陸游','宋','宋诗','song-poetry','','[]','吳下當時薄阿蒙，豈知垂老嘆途窮。',64,'全唐诗/poet.song.131000.json','["吳下當時薄阿蒙，豈知垂老嘆途窮。", "秋砧巷陌昏昏月，夜燭簾櫳裊裊風。", "縮項鳊魚收晚釣，長腰粳米出新礱。", "兒曹幸可團欒語，憂患如山一笑空。"]'),
('0ba95286-1602-402c-bdef-46cf3d335452','七十二歲吟','陸游','宋','宋诗','song-poetry','','[]','七十人言自古稀，我今過二未全衰。',64,'全唐诗/poet.song.131000.json','["七十人言自古稀，我今過二未全衰。", "讀書似走名場日，許國如騎戰馬時。", "秋晚雁來空自感，夜闌酒盡不勝悲。", "渭濱星霣逾千載，一表何人繼出師。"]'),
('fa9bfddd-b6f2-4282-b6f6-109fda73fdea','雨夜讀書二首  其一','陸游','宋','宋诗','song-poetry','','[]','風雨澒洞吞孤村，讀書擁褐不出門。',64,'全唐诗/poet.song.131000.json','["風雨澒洞吞孤村，讀書擁褐不出門。", "歷觀忠邪見肝肺，直與治亂窮根原。", "傅巖之野感帝夢，此事難以今人論。", "危冠長劍一見用，萬里耕桑吾道尊。"]'),
('2d943477-2119-468f-a297-91d19f9e01d2','雨夜讀書二首  其二','陸游','宋','宋诗','song-poetry','','[]','一燈如螢雨潺潺，老夫讀書蓬戶間。',64,'全唐诗/poet.song.131000.json','["一燈如螢雨潺潺，老夫讀書蓬戶間。", "但與古人對生面，那恨鏡裏凋朱顔。", "功名本來我輩事，人自蹭蹬天何慳。", "君看病驥瘦露骨，不思仗下思天山。"]'),
('98febf14-1148-4b26-a6ce-ac2b1caac3ac','秋晚','陸游','宋','宋诗','song-poetry','','[]','聚落蕭條古埭東，蘆藩蓬戶卧衰翁。',64,'全唐诗/poet.song.131000.json','["聚落蕭條古埭東，蘆藩蓬戶卧衰翁。", "井桐葉盡新霜後，衣杵聲繁夕照中。", "身似敗棋難復振，心如病木已中空。", "村醪酸澀君無笑，也解燈前作臉紅。"]'),
('78efebd2-083b-47a0-850d-5a18b24bb148','新菊二首  其一','陸游','宋','宋诗','song-poetry','','[]','已過重陽十日期，菊叢初破兩三枝。',32,'全唐诗/poet.song.131000.json','["已過重陽十日期，菊叢初破兩三枝。", "自憐短鬢蕭蕭白，不似黄花驛裏時。"]'),
('139417a3-8ba3-4f30-92b8-70c7c52c6f66','新菊二首  其二','陸游','宋','宋诗','song-poetry','','[]','老去流年不耐催，微霜又見菊花開。',32,'全唐诗/poet.song.131000.json','["老去流年不耐催，微霜又見菊花開。", "莫言冷落西風晚，也有飛飛小蝶來。"]'),
('b2c35a45-b411-44b8-a91f-6e011ef2275c','九月二十八日五鼓起坐抽架上書得九域志泫然有感','陸游','宋','宋诗','song-poetry','','[]','一事無成老已成，不堪歲月又崢嶸。',64,'全唐诗/poet.song.131000.json','["一事無成老已成，不堪歲月又崢嶸。", "愁生新雁寒初下，睡起殘燈曉尚明。", "天地何由容醜虜，功名正恐屬書生。", "行年七十初心在，偶展輿圖泪自傾。"]'),
('2f98301a-7507-436d-8926-a1272699000e','題橋南堂圖','陸游','宋','宋诗','song-poetry','','[]','平生不識橋南路，聞道清流带烟樹。',96,'全唐诗/poet.song.131000.json','["平生不識橋南路，聞道清流带烟樹。", "今朝開卷一欣然，恍若身親到其處。", "徐郎獨立嶷如山，招不能來麾不去。", "舊居萬瓦碧浮烟，結茅却就橋南住。", "雪盡春生水似藍，想君清嘯釣魚庵。", "道上紅塵高十丈，斷無一點到橋南。"]'),
('6219a989-ec8a-4605-a4db-4f000ba4e3cc','題吳參議達觀堂堂榜蓋朱希真所作也僕少亦辱知於朱公故尤感慨云','陸游','宋','宋诗','song-poetry','','[]','中原遺老雒川公，鬢鬚白盡雙頰紅。',96,'全唐诗/poet.song.131000.json','["中原遺老雒川公，鬢鬚白盡雙頰紅。", "揮亳爲君作齋榜，想見眼中餘子空。", "餘子碌碌何足數，獨付莊周賈生語。", "看君踐履四十年，始知此公不輕許。", "公今度世爲飛僊，開卷使我神凜然。", "清時臺省要才傑，諸公誰致雒川客。"]'),
('479742e8-88e7-4fb5-a66c-04934b03f2c0','舍北摇落景物殊佳偶作五首  其一','陸游','宋','宋诗','song-poetry','','[]','今年冬候晚，仲月始微霜。',48,'全唐诗/poet.song.131000.json','["今年冬候晚，仲月始微霜。", "野日明楓葉，江風斷雁行。", "窮塗多藉躪，老境易悲傷。", "自笑詩情懶，蕭然舊錦囊。"]'),
('e2d56093-abf8-4001-8fd4-db371f45fe08','舍北摇落景物殊佳偶作五首  其二','陸游','宋','宋诗','song-poetry','','[]','路擁新霜葉，溪餘舊漲沙。',48,'全唐诗/poet.song.131000.json','["路擁新霜葉，溪餘舊漲沙。", "栖烏初滿樹，歸鴨各知家。", "世事元堪笑，吾生固有涯。", "南村聞酒熟，試遣小僮賒。"]'),
('159ec58b-7885-4f55-8219-e7a98bdada11','舍北摇落景物殊佳偶作五首  其三','陸游','宋','宋诗','song-poetry','','[]','小聚鷗沙北，橫林蟹舍東。',48,'全唐诗/poet.song.131000.json','["小聚鷗沙北，橫林蟹舍東。", "船頭眠醉叟，牛背立村童。", "日落雲全碧，霜餘葉半紅。", "窮鱗與倦翼，終勝在池籠。"]'),
('e52bb81e-5152-4e7d-b21d-6fb1229abc67','舍北摇落景物殊佳偶作五首  其四','陸游','宋','宋诗','song-poetry','','[]','屋角成金字，溪流作穀紋。',48,'全唐诗/poet.song.131000.json','["屋角成金字，溪流作穀紋。", "斜通小橋路，半掩夕陽門。", "孤艇衝烟過，疏鐘隔塢聞。", "杜門非獨病，實自厭紛紛。"]'),
('60299c2d-e8a7-49fd-9155-c4d1ec62c13c','舍北摇落景物殊佳偶作五首  其五','陸游','宋','宋诗','song-poetry','','[]','草徑人稀到，柴扉手自開。',48,'全唐诗/poet.song.131000.json','["草徑人稀到，柴扉手自開。", "林疏鴉小泊，溪淺鷺頻來。", "簷角除瓜蔓，牆隅斸芋魁。", "東鄰膰肉至，一笑舉新醅。"]'),
('53fb6879-97ac-44c3-85b4-b163f713e70b','自嘲','陸游','宋','宋诗','song-poetry','','[]','身見紹興初改元，百罹敢料至今存。',64,'全唐诗/poet.song.131000.json','["身見紹興初改元，百罹敢料至今存。", "生涯破碎餘龍具，學問荒唐守兔園。", "獨立未除還笏氣，餘生猶待闔棺論。", "北窗燈暗霜風惡，且置孤愁近酒樽。"]'),
('e8471291-a5df-4134-b9bd-2112c1878967','作夢','陸游','宋','宋诗','song-poetry','','[]','作夢今逾七十年，平生懷抱尚依然。',64,'全唐诗/poet.song.131000.json','["作夢今逾七十年，平生懷抱尚依然。", "結茅杜曲桑麻地，覓句灞橋風雪天。", "驃騎向來求作佛，淮南末路望登仙。", "世間妄想何窮盡，輸與山翁一醉眠。"]'),
('afe78b6f-8feb-4974-a0a0-2e5eed93fdd0','夜坐','陸游','宋','宋诗','song-poetry','','[]','杳杳霜鐘十里聲，娟娟江月半窗明。',64,'全唐诗/poet.song.131000.json','["杳杳霜鐘十里聲，娟娟江月半窗明。", "陳編欲絕猶堪讀，微火相依更有情。", "九曲烟雲新散吏，百年鉛槧老諸生。", "頹然待旦君無笑，尚勝聞雞賦早行。"]'),
('dbcf974e-2b31-45c4-9760-b545e2474807','北園雜詠十首  其一','陸游','宋','宋诗','song-poetry','','[]','西村林外起炊烟，南浦橋邊繫釣船。',32,'全唐诗/poet.song.131000.json','["西村林外起炊烟，南浦橋邊繫釣船。", "樂歲家家俱自得，桃源未必是神仙。"]'),
('fed4a36f-5a3d-4bea-802c-98b618a4150f','北園雜詠十首  其二','陸游','宋','宋诗','song-poetry','','[]','舍北橋東幽事多，老夫飯飽得婆娑。',32,'全唐诗/poet.song.131000.json','["舍北橋東幽事多，老夫飯飽得婆娑。", "茅簷日落聞舂相，荻浦烟深有櫂歌。"]'),
('0d566059-e371-4da7-a7d9-2004dcf628e4','北園雜詠十首  其三','陸游','宋','宋诗','song-poetry','','[]','小橋密接西岡路，支徑深通北崦村。',32,'全唐诗/poet.song.131000.json','["小橋密接西岡路，支徑深通北崦村。", "老子意行無遠近，月中時打野人門。"]'),
('8275f492-e555-4a0f-857e-e7d3586e8d8a','北園雜詠十首  其四','陸游','宋','宋诗','song-poetry','','[]','東吳霜薄富園蔬，紫芥青菘小雨餘。',32,'全唐诗/poet.song.131000.json','["東吳霜薄富園蔬，紫芥青菘小雨餘。", "未說春盤供采擷，老夫湯餅亦時須。"]'),
('41ec9aa8-464d-4ff0-a71b-5be1c1c5aa05','北園雜詠十首  其五','陸游','宋','宋诗','song-poetry','','[]','鉏麥家家趁晚晴，筑陂處處待春耕。',32,'全唐诗/poet.song.131000.json','["鉏麥家家趁晚晴，筑陂處處待春耕。", "小槽酒熟豚蹄美，剩與兒童樂太平。"]'),
('02a9ea32-ed60-4d6a-b818-647b16929244','北園雜詠十首  其六','陸游','宋','宋诗','song-poetry','','[]','閑伴鄰翁去荷鉏，林疏歷歷見村墟。',32,'全唐诗/poet.song.131000.json','["閑伴鄰翁去荷鉏，林疏歷歷見村墟。", "怪生白鷺飛無數，水落灘生易取魚。"]'),
('84731fe5-2b96-4e7a-8444-4ddbc91d8650','北園雜詠十首  其七','陸游','宋','宋诗','song-poetry','','[]','短筇行樂出柴荆，雪意闌珊却變晴。',32,'全唐诗/poet.song.131000.json','["短筇行樂出柴荆，雪意闌珊却變晴。", "林際已看春雉起，屋頭還聽歲豬鳴。"]'),
('90fa2418-22cf-47b6-acad-c12055e96c89','北園雜詠十首  其八','陸游','宋','宋诗','song-poetry','','[]','歲殘已似早春天，隔水橫林一抹烟。',32,'全唐诗/poet.song.131000.json','["歲殘已似早春天，隔水橫林一抹烟。", "聞道埭西梅半吐，携兒閑上釣魚船。"]'),
('ce7fbe6c-ae6a-4c7d-86d2-5308a980779c','北園雜詠十首  其九','陸游','宋','宋诗','song-poetry','','[]','白髮蕭蕭病滿身，凍雲野渡正愁人。',32,'全唐诗/poet.song.131000.json','["白髮蕭蕭病滿身，凍雲野渡正愁人。", "揚鞭大散關頭日，曾看中原萬里春。"]'),
('678c7f63-a6b9-4727-b9f2-3bc382fcd653','北園雜詠十首  其一○','陸游','宋','宋诗','song-poetry','','[]','暮年身似一虛舟，付與滄波自在流。',32,'全唐诗/poet.song.131000.json','["暮年身似一虛舟，付與滄波自在流。", "垂地雪雲吹不散，且傾桑落膾槎頭。"]'),
('101408b4-4c6d-4011-8697-b754780c70ba','龜堂獨坐遣悶二首  其一','陸游','宋','宋诗','song-poetry','','[]','髮已凋疏齒已摇，高談誰與慰無聊。',64,'全唐诗/poet.song.131000.json','["髮已凋疏齒已摇，高談誰與慰無聊。", "苦心雖嘔何由出，病骨非讒亦自銷。", "玉雪細塵烹瑞草，烟脂小把斸靈苗。", "賀公吳語吾能似，太息遺魂不可招。"]'),
('9a5da891-092d-401b-ad32-73e9ab256dca','龜堂獨坐遣悶二首  其二','陸游','宋','宋诗','song-poetry','','[]','放逐還山八見春，枯顱槁項雪霜新。',64,'全唐诗/poet.song.131000.json','["放逐還山八見春，枯顱槁項雪霜新。", "大床不解除豪氣，凡眼安能識貴人。", "食有淖糜猶足飽，衣存短褐未全貧。", "北窗坐卧君無笑，拈起烏藤捷有神。"]'),
('c10cdaaa-2ab3-4efe-9b73-de11437d3ff7','復竊祠祿示兒子','陸游','宋','宋诗','song-poetry','','[]','得飽不啻足，閉門還讀書。',48,'全唐诗/poet.song.131000.json','["得飽不啻足，閉門還讀書。", "翁猶羹不糝，兒固食無魚。", "衮繡曷加我，簞瓢常晏如。", "人生隨所遇，勿替此心初。"]'),
('d6652799-9f07-48cf-a7ad-01169df4f875','隴頭水','陸游','宋','宋诗','song-poetry','','[]','隴頭十月天雨霜，壯士夜枕綠沈槍。',96,'全唐诗/poet.song.131000.json','["隴頭十月天雨霜，壯士夜枕綠沈槍。", "卧聞隴水思故鄉，三更起坐泪數行。", "我語壯士勉自彊，男兒墮地志四方。", "裹尸馬革固其常，豈若婦女不下堂。", "生逢和親最可傷，歲輦金絮輸胡羌。", "夜視太白收光芒，報國欲死無戰場。"]'),
('79442f3a-37f1-48db-b7cb-be6c2679c161','雪歌','陸游','宋','宋诗','song-poetry','','[]','黑雲黯黯如翻鴉，急霰颯颯疑投沙。',128,'全唐诗/poet.song.131000.json','["黑雲黯黯如翻鴉，急霰颯颯疑投沙。", "初聞萬竅號地籟，已見六出飛天花。", "寧論異事吠群犬，且喜和氣連千家。", "穿簾投隙矜嫵媚，平坑塞谷迷谽谺。", "遥遥林塔出玉筍，渺渺江路蟠修蛇。", "扣門方擬貰鄰酒，篝火更欲尋僧茶。", "懸知朝士集闕角，靴聲入賀趨正衙。", "吾衰久矣尚何說，所幸一稔均幽遐。"]'),
('66e4e74d-b08e-48df-ab8f-8d68ceaf5831','春近','陸游','宋','宋诗','song-poetry','','[]','短褐枯筇老病身，龍鍾也復喜新春。',64,'全唐诗/poet.song.131000.json','["短褐枯筇老病身，龍鍾也復喜新春。", "已知不解多年住，且作都無一事人。", "簷角鳥聲呼醉夢，室中花氣襲衣巾。", "朝來更有欣然處，一筯山蔬勝八珍。"]'),
('ba164a48-8d00-4038-81b3-c67cb037f95c','望永阜陵','陸游','宋','宋诗','song-poetry','','[]','聖主乘乾臨斧扆，小臣承詔上丹墀。',64,'全唐诗/poet.song.131000.json','["聖主乘乾臨斧扆，小臣承詔上丹墀。", "寧知齒豁頭童後，更遇天崩地陷時。", "泣至眼枯無血續，夢隨魂斷獨心知。", "白頭才盡空濡筆，寧繼生民下武詩。"]'),
('f9b964b6-a6e2-4292-a33e-a59116b8f56f','初拜再領祠宮之命有感','陸游','宋','宋诗','song-poetry','','[]','黄紙初開喜可知，追懷平昔却成悲。',64,'全唐诗/poet.song.131000.json','["黄紙初開喜可知，追懷平昔却成悲。", "生當京國承平日，仕及皇家再造時。", "小草出山初已誤，斷雲含雨欲何施。", "兒孫賀罷仍無事，却赴幽人把釣期。"]'),
('0013d3c7-72a7-4cc2-9037-af2e4d445bbb','醉中信筆作四絕句既成懼觀者不知野人本心也復作一絕  其一','陸游','宋','宋诗','song-poetry','','[]','麥野桑村有酒徒，過門相覓醉相扶。',32,'全唐诗/poet.song.131000.json','["麥野桑村有酒徒，過門相覓醉相扶。", "朱門日日教歌舞，也有儂家此樂無。"]'),
('c10ad72d-f5a8-4105-9e32-6aaf76227c42','醉中信筆作四絕句既成懼觀者不知野人本心也復作一絕  其二','陸游','宋','宋诗','song-poetry','','[]','過得一日過一日，人間萬事不須謀。',32,'全唐诗/poet.song.131000.json','["過得一日過一日，人間萬事不須謀。", "鄰家幸可賒芳醞，紅蕊何曾笑白頭。"]'),
('c912159a-d3ed-4526-877f-30459229ef3c','醉中信筆作四絕句既成懼觀者不知野人本心也復作一絕  其三','陸游','宋','宋诗','song-poetry','','[]','今朝賣穀得青錢，自出街頭買彘肩。',32,'全唐诗/poet.song.131000.json','["今朝賣穀得青錢，自出街頭買彘肩。", "草火燎來香滿屋，未容下筯已流涎。"]'),
('56b2df8c-063e-427c-b6cc-d5bd7f88f665','醉中信筆作四絕句既成懼觀者不知野人本心也復作一絕  其四','陸游','宋','宋诗','song-poetry','','[]','老覺人間足畏塗，怕人渾似怕於菟。',32,'全唐诗/poet.song.131000.json','["老覺人間足畏塗，怕人渾似怕於菟。", "晴明頗動青鞵興，先探門前有客無。"]'),
('87025692-dc0a-46f7-a337-d28ad54c199d','醉中信筆作四絕句既成懼觀者不知野人本心也復作一絕  其五','陸游','宋','宋诗','song-poetry','','[]','治道巍巍本易成，狂言安得略施行。',32,'全唐诗/poet.song.131000.json','["治道巍巍本易成，狂言安得略施行。", "太平事業人皆見，不計封倫死與生。"]'),
('35f9b84e-0f19-46bc-888d-d22ab5c2442c','臘月十九日午睡覺復酣卧至晚戲作','陸游','宋','宋诗','song-poetry','','[]','枕痕著面眼芒羊，欲起元無抵死忙。',64,'全唐诗/poet.song.131000.json','["枕痕著面眼芒羊，欲起元無抵死忙。", "擁被却尋初斷夢，掩屏重撥欲殘香。", "雪雲雖散寒猶緊，春意將回晝已長。", "老去此身無著處，華胥真恐是吾鄉。"]'),
('cfabeb08-f6fb-47fd-8d89-9f73e425e285','睡起至園中','陸游','宋','宋诗','song-poetry','','[]','春風忽已遍天涯，老子猶能領物華。',64,'全唐诗/poet.song.131000.json','["春風忽已遍天涯，老子猶能領物華。", "淺碧細傾家釀酒，小紅初試手栽花。", "野人易與輸肝肺，俗語誰能挂齒牙。", "更欲世間同省事，勾回蟻戰放蜂衙。"]'),
('23c5e931-388f-492a-8220-d51101ecf8d1','北園籬外放步','陸游','宋','宋诗','song-poetry','','[]','北園西出路逶迤，荆作門扉枳縛籬。',64,'全唐诗/poet.song.131000.json','["北園西出路逶迤，荆作門扉枳縛籬。", "鋤麥正忙人滿野，營巢未定鵲爭枝。", "招呼父老嘗新釀，約束兒童筑壞陂。", "遇興閑行便終日，隔溪績火已參差。"]'),
('717d0c5e-09af-43bb-a1bf-51028f44077c','歲暮獨酌感懷','陸游','宋','宋诗','song-poetry','','[]','明時頻忝武夷僊，俯仰人間只自憐。',64,'全唐诗/poet.song.131000.json','["明時頻忝武夷僊，俯仰人間只自憐。", "總角回思如昨日，挂冠過限已三年。", "病多晴日思行藥，睡少清宵學坐禪。", "更嘆衰孱不禁酒，地黄一盞即頹然。"]'),
('8f97701d-cb22-4367-a36c-1a96e566539c','盆池','陸游','宋','宋诗','song-poetry','','[]','雨送疏疏響，風吹細細紋。',48,'全唐诗/poet.song.131000.json','["雨送疏疏響，風吹細細紋。", "猶稀綠萍點，已映小魚群。", "傍有一拳石，又生膚寸雲。", "我來閑照影，一笑整綸巾。"]'),
('54ebd1c7-cc97-4b25-aba3-65ac28637370','對食','陸游','宋','宋诗','song-poetry','','[]','蓬藋生庭葉擁階，經旬飯豆爨枯䕸。',64,'全唐诗/poet.song.131000.json','["蓬藋生庭葉擁階，經旬飯豆爨枯䕸。", "烟霄舊謂行夷路，薪水今悲繫病懷。", "夢裏百年元易過，人間萬事苦難諧。", "癡兒自墮闍黎計，歡喜聞鐘已過齋。"]'),
('5e768531-baeb-4d45-b306-eafacfa14f93','蹭蹬','陸游','宋','宋诗','song-poetry','','[]','少慕功名頗自奇，一生蹭蹬鬢成絲。',64,'全唐诗/poet.song.131000.json','["少慕功名頗自奇，一生蹭蹬鬢成絲。", "市樓酒美貧何預，斗柄春回老不知。", "黑幟遊魂應有數，白衣效命永無期。", "魚梁東畔牛欄北，舉世誰能識此悲。"]'),
('546020ae-aa9b-469e-b284-02b8e50d2954','海棠圖','陸游','宋','宋诗','song-poetry','','[]','人間奇草木，天必付名流。',48,'全唐诗/poet.song.131000.json','["人間奇草木，天必付名流。", "菊待陶元亮，竹須王子猷。", "我爲西蜀客，辱與海棠遊。", "再見應無日，開圖特地愁。"]'),
('dc3c81c5-b044-4deb-92fd-db5d1f30f02e','丁巳正月二日雞初鳴夢至一山寺名鳳山其尤勝處曰咮軒予爲賦詩既覺不遺一字','陸游','宋','宋诗','song-poetry','','[]','已窮阿閤勝，更作咮軒遊。',48,'全唐诗/poet.song.131000.json','["已窮阿閤勝，更作咮軒遊。", "不盡山河大，無根日月浮。", "吾身元是幻，何物彊名愁。", "久覓卓庵處，是間應可留。"]'),
('109c4a00-d90d-460d-a4f9-321ea2ff1985','初春','陸游','宋','宋诗','song-poetry','','[]','誰把鵝黄染柳絲，似催鄰曲蹋青期。',64,'全唐诗/poet.song.131000.json','["誰把鵝黄染柳絲，似催鄰曲蹋青期。", "已忘萬里封侯志，但憶千回上樹時。", "朝雨池塘光瀲灧，暮烟樓觀碧參差。", "紫姑欲問還休去，身世從來心自知。"]'),
('32f5154d-0b57-496b-ae74-4b7a4a4d2e49','雨中作三首  其一','陸游','宋','宋诗','song-poetry','','[]','三日雨頻作，昏昏饒睡眠。',48,'全唐诗/poet.song.131000.json','["三日雨頻作，昏昏饒睡眠。", "泥深散酒市，風惡惱燈天。", "茅屋松明照，茶鐺雪水煎。", "山家自成趣，撫枕寄悠然。"]'),
('007e3508-9c46-421f-975b-57cbd0a53dde','雨中作三首  其二','陸游','宋','宋诗','song-poetry','','[]','淅淅連江雨，愔愔一室幽。',48,'全唐诗/poet.song.131000.json','["淅淅連江雨，愔愔一室幽。", "茶甘留齒頰，香潤上衣裘。", "泥滓將雛鴨，林樊喚婦鳩。", "短章雖漫興，聊足散吾愁。"]'),
('77c2d0cd-40aa-4d76-b914-970a11f49c44','雨中作三首  其三','陸游','宋','宋诗','song-poetry','','[]','短鬢白如絲，梅花似舊時。',48,'全唐诗/poet.song.131000.json','["短鬢白如絲，梅花似舊時。", "掩屏愁入夢，隱几雨催詩。", "病爲陰天劇，春緣閏歲遲。", "非關畏車馬，衰甚實難支。"]'),
('d5bfac83-877c-4f3b-88c2-7be8e16ad38f','縱筆','陸游','宋','宋诗','song-poetry','','[]','氣本充天地，書非汗馬牛。',48,'全唐诗/poet.song.131000.json','["氣本充天地，書非汗馬牛。", "人人見堯舜，世世有巢由。", "朝市紅塵鬧，山村白髮稠。", "所欣吾道在，江漢古東流。"]'),
('b2ca0029-5643-4b21-a861-b07eb59506ae','題慧老芋巖','陸游','宋','宋诗','song-poetry','','[]','煨芋當時話已新，如今拈出更精神。',32,'全唐诗/poet.song.131000.json','["煨芋當時話已新，如今拈出更精神。", "十年相國非吾願，半顆君當別付人。"]'),
('0038647e-6f1e-4ece-97db-d21d6d9cb52f','立春日','陸游','宋','宋诗','song-poetry','','[]','江花江水每年同，春日春盤放手空。',64,'全唐诗/poet.song.131000.json','["江花江水每年同，春日春盤放手空。", "天地無私生萬物，山林有處著衰翁。", "牛趨死地身無罪，梅發京華信不通。", "數片飛飛猶臘雪，村鄰相喚賀年豐。"]'),
('35d8d500-0676-495f-9bf4-05abb8b85490','病中作二首  其一','陸游','宋','宋诗','song-poetry','','[]','老軀百病集，頹然仰天呼。',72,'全唐诗/poet.song.131000.json','["老軀百病集，頹然仰天呼。", "汝病勿怨天，藥石幸可扶。", "寓形天地間，疾病誰能無。", "不從酒色來，病自無根株。", "但使元氣在，雖劇行當蘇。", "哀哉忿慾子，永棄元化爐。"]'),
('91de0e3d-55f4-474a-b62f-222389188d20','病中作二首  其二','陸游','宋','宋诗','song-poetry','','[]','牧羊知治民，解牛得養生。',96,'全唐诗/poet.song.131000.json','["牧羊知治民，解牛得養生。", "一理儻造微，何事不可明。", "我老抱病久，頗窺古人情。", "唐堯授四時，帝道所以成。", "周家七百年，王業本農耕。", "造端無甚奇，至今稱太平。", "人生正如此，默默要無營。", "心君但高拱，萬物安能攖。"]'),
('a4161033-87d4-4e75-b91f-d0cc1b17920b','立春日二首  其一','陸游','宋','宋诗','song-poetry','','[]','花壓烏巾酒滿卮，舊逢春日恨春遲。',32,'全唐诗/poet.song.131000.json','["花壓烏巾酒滿卮，舊逢春日恨春遲。", "如今病卧孤村裏，過了新春也不知。"]'),
('9afdfde0-933c-407e-a1e6-bf236908485d','立春日二首  其二','陸游','宋','宋诗','song-poetry','','[]','慶元丁巳春來晚，人日初過近上元。',32,'全唐诗/poet.song.131000.json','["慶元丁巳春來晚，人日初過近上元。", "空對一樽三太息，無人爲戴縷金旛。"]'),
('4942efa2-7e90-4562-bdd6-5170e0b3be43','北望','陸游','宋','宋诗','song-poetry','','[]','中原墮胡塵，北望但莽莽。',72,'全唐诗/poet.song.131000.json','["中原墮胡塵，北望但莽莽。", "耆年死已盡，童稚日夜長。", "羊裘左其衽，寧復記疇曩。", "豈無豪俊士，憤氣塞穹壤。", "我欲友斯人，悲詫寄遐想。", "夢行黄河濱，雲開見仙掌。"]'),
('f0527a84-7820-4301-870f-3e7b9e4d23ec','上元夜作','陸游','宋','宋诗','song-poetry','','[]','百年古謂風前燭，我逾七十飯不足。',133,'全唐诗/poet.song.131000.json','["百年古謂風前燭，我逾七十飯不足。", "亦知生世無工拙，久向人間耐榮辱。", "今年上元燈滿城，十里東風度絲竹。", "蓬窗溼薪不禦寒，獨取殘書伴兒讀。", "忽然得意見古人，半碗凍齏甘勝肉。", "書生蓋棺事未定，論著儻存終見錄。", "富貴無名豈勝數，意氣空能驕世俗。", "君不見拄天拄地邢君牙，不如詩人窮瞎張太祝。"]'),
('205cd697-6c56-4205-a3d1-39b3f753c337','長歌行','陸游','宋','宋诗','song-poetry','','[]','不羨騎鶴上青天，不羨峨冠明主前。',124,'全唐诗/poet.song.131000.json','["不羨騎鶴上青天，不羨峨冠明主前。", "但願少賒死，得見平胡年。", "一朝胡運衰，送死桑乾川。", "胡星澹無光，龍庭爲飛烟。", "西琛過葱嶺，東戍逾朝鮮。", "巍巍天王都，九鼎奠澗瀍。", "萬國朝未央，玉帛來聯翩。", "黄頭汝小醜，汙我王會篇。", "盡誅非無名，不足煩戈鋋。", "還汝以舊職，牧羊遼海邊。"]'),
('307555b7-5b1c-4409-81c1-f3c49753256e','讀書','陸游','宋','宋诗','song-poetry','','[]','兩眼欲讀天下書，力雖不迨志有餘。',128,'全唐诗/poet.song.131000.json','["兩眼欲讀天下書，力雖不迨志有餘。", "千載欲追聖人徒，慷慨自信寧免愚。", "置書不讀談虛無，誰其始爲此創疽。", "古時澤被禽與魚，博施所以爲唐虞。", "正使老釋信不誣，爲我未免近楊朱。", "高軒大旆塞路衢，臺閣尊顯來于于。", "安得禹皋日陳謨，沾濡四表無焦枯。", "坐令事業見真儒，老農不恨老耕鉏。"]'),
('963ad309-7c9f-4e0a-a9a7-71a3eb7663bb','枕上作','陸游','宋','宋诗','song-poetry','','[]','龍鍾七十豈前期，矮帽枯筇與老宜。',64,'全唐诗/poet.song.131000.json','["龍鍾七十豈前期，矮帽枯筇與老宜。", "愁得酒卮如敵國，病須書卷作良醫。", "登山筋力雖猶健，閉戶工夫頗自奇。", "今日快情春睡足，卧聽簷鳥語多時。"]'),
('5a46c149-ec17-4d40-985f-a2bcece8ab40','書志','陸游','宋','宋诗','song-poetry','','[]','往年出都門，誓墓志已决。',120,'全唐诗/poet.song.131000.json','["往年出都門，誓墓志已决。", "况今蒲柳姿，俛仰及大耋。", "妻孥厭寒餓，鄰里笑迂拙。", "悲歌行拾穗，幽憤卧齧雪。", "千歲埋松根，陰風蕩空穴。", "肝心獨不化，凝結變金鐵。", "鑄爲上方劍，釁以佞臣血。", "匣藏武庫中，出參髦頭列。", "三尺粲星辰，萬里靜妖孽。", "君看此神奇，醜虜何足滅。"]'),
('1f8c8230-fee9-4de4-996c-0b043eb7b031','夜賦','陸游','宋','宋诗','song-poetry','','[]','簷滴新春雨，窗昏半夜燈。',48,'全唐诗/poet.song.131000.json','["簷滴新春雨，窗昏半夜燈。", "病無詩一字，窮賴酒三升。", "世路澀如棘，祠官冷欲冰。", "殘年只此是，年少解飛騰。"]'),
('58ac1e46-bb19-4d4d-bc9a-857e927d008b','晚步','陸游','宋','宋诗','song-poetry','','[]','晚步清溪上，微陰忽快晴。',48,'全唐诗/poet.song.131000.json','["晚步清溪上，微陰忽快晴。", "鴉棲先小泊，魚暖已群行。", "藥餌扶垂老，耕桑樂太平。", "非關戀鄉社，久客倦遐征。"]'),
('2ac79218-57c2-40fb-9f8e-7eb32243ab7c','漁歌','陸游','宋','宋诗','song-poetry','','[]','斜陽收盡暮烟青，嫋嫋漁歌起遠汀。',32,'全唐诗/poet.song.131000.json','["斜陽收盡暮烟青，嫋嫋漁歌起遠汀。", "商略野人何所恨，數聲哀絕不堪聽。"]'),
('f2561f28-729e-411f-b339-a63614102a7e','殘夢','陸游','宋','宋诗','song-poetry','','[]','少時鐵馬蹴河冰，老去摧藏百不能。',32,'全唐诗/poet.song.131000.json','["少時鐵馬蹴河冰，老去摧藏百不能。", "風雨滿山窗未曉，只將殘夢伴殘燈。"]'),
('b9c0a5d1-2f29-43de-8489-1f6f2bd276db','書憤二首  其一','陸游','宋','宋诗','song-poetry','','[]','白髮蕭蕭卧澤中，祇憑天地鑒孤忠。',64,'全唐诗/poet.song.131000.json','["白髮蕭蕭卧澤中，祇憑天地鑒孤忠。", "阨窮蘇武餐氈久，憂憤張巡嚼齒空。", "細雨春蕪上林苑，頹垣夜月洛陽宮。", "壯心未與年俱老，死去猶能作鬼雄。"]'),
('3e6ac640-70f4-4e34-b332-02a51e0f4925','書憤二首  其二','陸游','宋','宋诗','song-poetry','','[]','鏡裏流年兩鬢殘，寸心自許尚如丹。',64,'全唐诗/poet.song.131000.json','["鏡裏流年兩鬢殘，寸心自許尚如丹。", "衰遲罷試戎衣窄，悲憤猶爭寶劍寒。", "遠戍十年臨的博，壯圖萬里戰皋蘭。", "關河自古無窮事，誰料如今袖手看。"]'),
('07c6710d-97c1-4d85-9be0-7dddc6b0f078','小舟遊西涇度西岡而歸','陸游','宋','宋诗','song-poetry','','[]','小雨重三後，餘寒百五前。',48,'全唐诗/poet.song.131000.json','["小雨重三後，餘寒百五前。", "聊乘瓜蔓水，閑泛木蘭船。", "雪暗梨千樹，烟迷柳一川。", "西岡夕陽路，不到又經年。"]'),
('37cc9405-00d3-41e4-a301-3f3dab8d5f4a','春行','陸游','宋','宋诗','song-poetry','','[]','九日春陰一日晴，强扶衰病此閑行。',64,'全唐诗/poet.song.131000.json','["九日春陰一日晴，强扶衰病此閑行。", "猩紅带露海棠溼，鴨綠平堤湖水明。", "酒賤柳陰逢醉卧，土肥稻壟看深耕。", "山翁莫道渾無用，解與明時說太平。"]'),
('e772414c-1acd-44a0-892b-91ed67e7ef15','姜總管自筑墓舍名繭庵求詩','陸游','宋','宋诗','song-poetry','','[]','君不見贅翁退隱真皇時，繭室遺名星日垂。',134,'全唐诗/poet.song.131000.json','["君不見贅翁退隱真皇時，繭室遺名星日垂。", "雖無豪士千車送，不愧高人一鍤隨。", "又不見貞觀故人有王顯，抵老摧頹不作繭。", "一時戲語今尚傳，人生窮達誰能免。", "繭庵知君出游戲，壽過期頤乃常事。", "青松手種三千本，會看半空翻鼓吹。", "人老則衰君不然，快瀉玉船鯨吸川。", "釣璜遠祖應相似，八十方爲筮仕年。"]'),
('cab426f2-f008-413e-b430-836dec9e14ef','湖上今歲遊人頗盛戲作四首  其一','陸游','宋','宋诗','song-poetry','','[]','龍船看罷日平西，柳闇花穠步步迷。',32,'全唐诗/poet.song.131000.json','["龍船看罷日平西，柳闇花穠步步迷。", "射的山前朱舫小，樵風涇上紫騮嘶。"]'),
('6423fa4a-2761-4dc4-8e03-04f1b9d750e3','湖上今歲遊人頗盛戲作四首  其二','陸游','宋','宋诗','song-poetry','','[]','畫船鼓吹載凉州，不到三更枉出遊。',32,'全唐诗/poet.song.131000.json','["畫船鼓吹載凉州，不到三更枉出遊。", "忽有歌聲出霄漢，誰家開宴五雲樓。"]'),
('5fd521f7-a27a-464f-810a-3d78e23e3e61','湖上今歲遊人頗盛戲作四首  其三','陸游','宋','宋诗','song-poetry','','[]','翠阜青林烟疊重，朱樓畫閣雨空濛。',32,'全唐诗/poet.song.131000.json','["翠阜青林烟疊重，朱樓畫閣雨空濛。", "禹祠西走蘭亭路，一片湖山錦繡中。"]'),
('7e52595e-be98-4d23-854b-19e08cadeba9','湖上今歲遊人頗盛戲作四首  其四','陸游','宋','宋诗','song-poetry','','[]','臺府官醅歲歲新，蘭亭春勝鏡湖春。',32,'全唐诗/poet.song.131000.json','["臺府官醅歲歲新，蘭亭春勝鏡湖春。", "三山小甕雖堪笑，也向湖邊作醉人。"]'),
('a35710b7-b62b-4c3a-bb94-c823d9fca65f','賞花至湖上','陸游','宋','宋诗','song-poetry','','[]','吾國名花天下稀，園林盡日敞朱扉。',64,'全唐诗/poet.song.131000.json','["吾國名花天下稀，園林盡日敞朱扉。", "蝶穿密葉常相失，蜂戀繁香不記歸。", "欲過每愁風蕩漾，半開却要雨霏微。", "良辰樂事真當勉，莫遣匆匆一片飛。"]'),
('3f0c1019-6f81-4343-9e71-372ab2e6e031','暮春二首  其一','陸游','宋','宋诗','song-poetry','','[]','季子黄金盡，安仁白髮新。',48,'全唐诗/poet.song.131000.json','["季子黄金盡，安仁白髮新。", "無情五更雨，便送一年春。", "難續西樓夢，空存北陌身。", "海棠應似舊，惆悵又成塵。"]'),
('9794abe1-7a24-46dd-9ba9-267dead4ad3e','暮春二首  其二','陸游','宋','宋诗','song-poetry','','[]','綠葉枝頭密，青蕪陌上深。',48,'全唐诗/poet.song.131000.json','["綠葉枝頭密，青蕪陌上深。", "江山妨極目，天地入孤吟。", "身已雙蓬鬢，家惟一素琴。", "世情君莫說，頭痛欲涔涔。"]'),
('5c232081-4999-4dfb-985b-4f5b382cfa99','暮春','陸游','宋','宋诗','song-poetry','','[]','數間茅屋鏡湖濱，萬卷藏書不救貧。',64,'全唐诗/poet.song.131000.json','["數間茅屋鏡湖濱，萬卷藏書不救貧。", "燕去燕來還過日，花開花落即經春。", "開編喜見平生友，照水驚非曩歲人。", "自笑滅胡心尚在，憑高慷慨欲忘身。"]'),
('5460437f-2255-4896-b27e-55d6864a06c1','九里','陸游','宋','宋诗','song-poetry','','[]','破曉憑鞍野興濃，鷺飛先我過村東。',64,'全唐诗/poet.song.131000.json','["破曉憑鞍野興濃，鷺飛先我過村東。", "綠鍼細細稻浮水，絳雪紛紛花舞風。", "陌上鞦韆喧笑語，擔頭粔籹簇青紅。", "誰知老子裴回意，絕愛山橫淡靄中。"]'),
('b4af902b-020f-4132-b0b2-5c487bc137df','清明','陸游','宋','宋诗','song-poetry','','[]','氣候江吳異，清明乃爾寒。',48,'全唐诗/poet.song.131000.json','["氣候江吳異，清明乃爾寒。", "老增丘墓感，貧苦道途難。", "燕子家家入，梨花樹樹殘。", "一春回首盡，懷抱若爲寬。"]'),
('07d44603-e56b-495a-93fe-97ac81cfe9be','一百五日行','陸游','宋','宋诗','song-poetry','','[]','一百五日東郊時，陂塘水滿雨如絲。',128,'全唐诗/poet.song.131000.json','["一百五日東郊時，陂塘水滿雨如絲。", "人家青烟不禁火，俚俗豈復思子推。", "舊墳年多木已拱，新墳積土高纍纍。", "老鴉飛鳴銜肉去，紙錢雨溼挂樹枝。", "深松茂柏死自樂，地下應笑生人悲。", "眼中青山身後塚，此事决定君何疑。", "風吹雲破日下照，小灘碎礫光陸離。", "停車暫憩道傍舍，解囊且補殘春詩。"]'),
('f37bf4f1-fc66-4eb5-8389-ff1bdaee1094','送李憲被召舊與其先侍郎遊從','陸游','宋','宋诗','song-poetry','','[]','早謁龍門鬢未秋，暮年乃復接英遊。',64,'全唐诗/poet.song.131000.json','["早謁龍門鬢未秋，暮年乃復接英遊。", "海瀕已幸見公子，瓜壟仍煩訪故侯。", "霖雨即陪諸老進，德星肯爲一方留。", "西城柳色青如許，欲挽長條特地愁。"]'),
('71fcadc0-0bdf-4322-b6d6-9520fe5e3871','初夏','陸游','宋','宋诗','song-poetry','','[]','已過浣花天，行開解粽筵。',72,'全唐诗/poet.song.131000.json','["已過浣花天，行開解粽筵。", "店沽浮臘酒，步檥載秧船。", "古俗交情久，豐年樂事偏。", "出波蓴菜滑，上市鮆魚鮮。", "僧閣梅山麓，漁扉禹廟壖。", "丹青不可畫，得句一欣然。"]'),
('b17f5d15-8519-4dd4-9695-21d92d61e9d5','幽居','陸游','宋','宋诗','song-poetry','','[]','社結山林友，家藏種樹書。',72,'全唐诗/poet.song.131000.json','["社結山林友，家藏種樹書。", "蔽床欣卜宅，容駟笑高閭。", "薄飯頻葅韭，單衣旋製綀。", "東家借蹇罷，南市買船初。", "美景遊俱遍，鄰翁好不疏。", "時時得乘興，豈獨愛吾廬。"]'),
('b9c99aaf-b00d-4b17-b497-38082cbb1218','閑適','陸游','宋','宋诗','song-poetry','','[]','朝讀易一卦，時鈔史數行。',48,'全唐诗/poet.song.131000.json','["朝讀易一卦，時鈔史數行。", "花開聊把酒，睡起獨焚香。", "寂寂市聲遠，悠悠村日長。", "吾衰尚何恨，兒女解耕桑。"]'),
('11b74b29-1e7e-4c6f-973a-063c5b556bb5','病中夜賦','陸游','宋','宋诗','song-poetry','','[]','客如病鶴卧還起，燈似孤螢闔復開。',64,'全唐诗/poet.song.131000.json','["客如病鶴卧還起，燈似孤螢闔復開。", "苜蓿花催春事去，梧桐葉送雨聲來。", "榮河溫洛幾時復，志士仁人空自哀。", "但使胡塵一朝靜，此身不恨死蒿萊。"]'),
('be8e7cf9-35af-4208-8277-9310766fa3e0','閑身','陸游','宋','宋诗','song-poetry','','[]','炊烟漠漠閉柴荆，聊用閑身答太平。',64,'全唐诗/poet.song.131000.json','["炊烟漠漠閉柴荆，聊用閑身答太平。", "重碧飛觴心未老，硬黄臨帖眼猶明。", "吳蠶滿箔含桃熟，壟麥登車摶黍鳴。", "補劓息黥今有地，問君何處用虛名。"]'),
('d5ed2dde-fde9-4af1-b7bc-73715283c47b','書感','陸游','宋','宋诗','song-poetry','','[]','奪璧元知價不讎，屠龍誰信本無求。',64,'全唐诗/poet.song.131000.json','["奪璧元知價不讎，屠龍誰信本無求。", "哦詩聲裏歲時速，憂國泪邊天地秋。", "已欠謝安俱泛海，况無王粲與登樓。", "此身著處憑君記，萬里烟波沒白鷗。"]'),
('af37f3d9-2acc-4b8a-ad28-6880df3ece9f','衰病','陸游','宋','宋诗','song-poetry','','[]','衰病集餘日，推移成老翁。',48,'全唐诗/poet.song.131000.json','["衰病集餘日，推移成老翁。", "衡門隱者趣，大布古人風。", "几杖呻吟裏，山川蒼莽中。", "從來世緣簿，不是坐詩窮。"]'),
('ca32f4ae-f099-41ac-b6a5-62885a563bff','雜題六首  其一','陸游','宋','宋诗','song-poetry','','[]','少談王霸謀身拙，晚好詩騷學道疏。',32,'全唐诗/poet.song.131000.json','["少談王霸謀身拙，晚好詩騷學道疏。", "賴有一籌差自慰，閉門不作子公書。"]'),
('d307bbee-2063-482f-9866-f84b35fb91aa','雜題六首  其二','陸游','宋','宋诗','song-poetry','','[]','莫笑花前白髮新，宣和人醉慶元春。',32,'全唐诗/poet.song.131000.json','["莫笑花前白髮新，宣和人醉慶元春。", "何時道路平如砥，却就清伊整幅巾。"]'),
('1779252f-b3a1-46dd-922d-8217e9226a5c','雜題六首  其三','陸游','宋','宋诗','song-poetry','','[]','三生元是出家人，一念差來墮薦紳。',32,'全唐诗/poet.song.131000.json','["三生元是出家人，一念差來墮薦紳。", "二寸楮冠雙草屨，天公還我水雲身。"]'),
('43497ed3-66a0-45fa-ad54-2ac3309e124b','雜題六首  其四','陸游','宋','宋诗','song-poetry','','[]','黄庭兩卷伴身閑，盤篆香殘日未殘。',32,'全唐诗/poet.song.131000.json','["黄庭兩卷伴身閑，盤篆香殘日未殘。", "泛泛孤身似萍葉，始知天地不勝寬。"]'),
('600cb050-d6d2-478e-a51e-53434eab33af','雜題六首  其五','陸游','宋','宋诗','song-poetry','','[]','年華偃蹇留不住，鬢雪縱橫耘更多。',32,'全唐诗/poet.song.131000.json','["年華偃蹇留不住，鬢雪縱橫耘更多。", "樂天不生夢得死，恨無人續竹枝歌。"]'),
('a747766f-8dd9-456c-a0b2-ea8785beafe0','雜題六首  其六','陸游','宋','宋诗','song-poetry','','[]','年來世事掃除盡，猶有閑吟頗自奇。',32,'全唐诗/poet.song.131000.json','["年來世事掃除盡，猶有閑吟頗自奇。", "安得陟釐九萬箇，爲君盡寫暮年詩。"]'),
('efbdbbab-3374-43b3-9f8a-72661c6c39d7','自傷','陸游','宋','宋诗','song-poetry','','[]','朝雨暮雨梅子黄，東家西家鬻蘭香。',96,'全唐诗/poet.song.131000.json','["朝雨暮雨梅子黄，東家西家鬻蘭香。", "白頭老鰥哭空堂，不獨悼死亦自傷。", "齒如敗屐鬢如霜，計此光景寧久長。", "扶杖欲起輒仆床，去死近如不隔牆。", "世間萬事俱茫茫，惟有進德當自强。", "往從二士餓首陽，千載骨朽猶芬芳。"]'),
('2d0a9eac-d0c9-4163-a620-5f394837db54','雨後絕凉偶作','陸游','宋','宋诗','song-poetry','','[]','槐陰日色薄，桐葉雨聲長。',48,'全唐诗/poet.song.131000.json','["槐陰日色薄，桐葉雨聲長。", "林下有餘適，城中無此凉。", "浮瓜寒水碧，斸藥小鉏香。", "未許陶潜達，華簪何足忘。"]'),
('e72f1de2-00ef-4f86-9ae7-03a5ef94fe8f','村居','陸游','宋','宋诗','song-poetry','','[]','黍酒濃浮甕，瓜葅綠映槃。',48,'全唐诗/poet.song.131000.json','["黍酒濃浮甕，瓜葅綠映槃。", "老便藜粥美，病喜粟漿酸。", "紗帽新裁穩，絁袍舊製寬。", "村居亦何好，聊用發詩端。"]'),
('8cbc2aee-2ebf-43bf-94b4-6c6a908af288','久雨','陸游','宋','宋诗','song-poetry','','[]','水長平侵岸，雲低半失村。',48,'全唐诗/poet.song.131000.json','["水長平侵岸，雲低半失村。", "菰蒲亂鳧鴨，泥潦困雞豚。", "弄筆排孤悶，煎茶洗睡昏。", "荒郊多狗盜，及早閉柴門。"]'),
('36010663-47a6-472e-ab22-5243d05dcb28','七十三吟','陸游','宋','宋诗','song-poetry','','[]','七十三年事事新，涵濡幸作六朝民。',64,'全唐诗/poet.song.131000.json','["七十三年事事新，涵濡幸作六朝民。", "髮無可白方爲老，酒不能賒始覺貧。", "末路已悲身是客，此心猶與物爲春。", "柴門勿謂常岑寂，時有鄉鄰請藥人。"]'),
('5077b4ae-e937-4afa-b5e0-b134af0585d1','會稽','陸游','宋','宋诗','song-poetry','','[]','海近風雲惡，城高鼓角雄。',48,'全唐诗/poet.song.131000.json','["海近風雲惡，城高鼓角雄。", "山川橫慘淡，樓閣半虛空。", "故國千年鶴，征途萬里蓬。", "餘生猶幾日，盡合付杯中。"]'),
('1e2c17cd-e721-42b9-9737-42a48ab9142c','泛舟','陸游','宋','宋诗','song-poetry','','[]','山照澄波䰀鬌青，新蒲梢上立蜻蜓。',32,'全唐诗/poet.song.131000.json','["山照澄波䰀鬌青，新蒲梢上立蜻蜓。", "孤舟每爲尋詩出，輸與漁翁醉不醒。"]'),
('2307c36a-b9ec-4bf5-8a6d-99699eae24fc','夜觀子虡所得淮上地圖','陸游','宋','宋诗','song-poetry','','[]','閉置空齋清夜徂，時聞水鳥暗相呼。',32,'全唐诗/poet.song.131000.json','["閉置空齋清夜徂，時聞水鳥暗相呼。", "胡塵漫漫連淮潁，泪盡燈前看地圖。"]'),
('cbe96b56-e58a-407e-aa9a-ebbac177b0e5','水村','陸游','宋','宋诗','song-poetry','','[]','家住烟波似畫圖，殘年不復嘆頭顱。',64,'全唐诗/poet.song.131000.json','["家住烟波似畫圖，殘年不復嘆頭顱。", "深深竹塢見螢度，翳翳菰叢聞鳥呼。", "十里笳聲上雲漢，一空星影落陂湖。", "天公著我非無地，却悔從來錯怪渠。"]'),
('ac1d715b-ef29-4632-889a-43f0211e2371','題庵壁二首  其一','陸游','宋','宋诗','song-poetry','','[]','萬里東歸白髮翁，閉門不復與人通。',64,'全唐诗/poet.song.131000.json','["萬里東歸白髮翁，閉門不復與人通。", "綠樽浮蟻狂猶在，黄紙棲鴉夢已空。", "薄技徒勞真刻楮，浮生隨處是飛蓬。", "湖邊吹笛非凡士，儻肯相從寂寞中。"]'),
('4548b9b3-4ac3-4c02-849d-444cbedbb154','題庵壁二首  其二','陸游','宋','宋诗','song-poetry','','[]','俠氣當年蓋五陵，今成粥飯在家僧。',64,'全唐诗/poet.song.131000.json','["俠氣當年蓋五陵，今成粥飯在家僧。", "身存但倚貧非病，齒落方慚豁可憎。", "踏月閑穿雙草屩，聽琴橫按一枯藤。", "年來萬事都經遍，强笑看人獨未曾。"]'),
('3fb6c678-9204-46ab-ae08-893dbe498398','晚歸舟中作','陸游','宋','宋诗','song-poetry','','[]','路入芙蕖浦，家依䆉䅉村。',48,'全唐诗/poet.song.131000.json','["路入芙蕖浦，家依䆉䅉村。", "急灘雙鷺立，平野萬鴉翻。", "市散人爭渡，僧歸寺掩門。", "凄凉誦新句，招得欲殘魂。"]'),
('fd438a32-31c8-47f2-917d-aa95e5626607','送嚴居厚棄官歸建陽溪莊','陸游','宋','宋诗','song-poetry','','[]','曼容不過六百石，淵明僅留八十日。',96,'全唐诗/poet.song.131000.json','["曼容不過六百石，淵明僅留八十日。", "寥寥千載有兩公，海內至今推絕識。", "放翁貪祿老始歸，自今不作一錢直。", "見人勇退輒欣慕，亟欲起拜忘衰疾。", "吾廬近在官道傍，門外未掃車馬迹。", "溪莊有地肯見分，會結茅齋傍青壁。"]'),
('25371895-36f7-4c30-9211-ec8bd7e97df5','次朱元晦韵題嚴居厚溪莊圖','陸游','宋','宋诗','song-poetry','','[]','鶴俸元知不療窮，葉舟還入亂雲中。',32,'全唐诗/poet.song.131000.json','["鶴俸元知不療窮，葉舟還入亂雲中。", "溪莊直下秋千頃，贏取閑身伴釣翁。"]'),
('3002e789-df46-4ae1-af46-51ffd9235fb6','夢中遊禹祠','陸游','宋','宋诗','song-poetry','','[]','湖上無人月自明，夢中彷彿得閑行。',64,'全唐诗/poet.song.131000.json','["湖上無人月自明，夢中彷彿得閑行。", "庭空滿地楸梧影，風壯侵雲鼓角聲。", "世異客懷增慘愴，秋高歲事已崢嶸。", "長歌忽遇騎鯨客，喚取同朝白玉京。"]'),
('d35ec238-eee5-4d9d-a8bc-a395a265ed5a','感懷','陸游','宋','宋诗','song-poetry','','[]','老抱遺書隱故山，鏡中衰鬢似霜菅。',64,'全唐诗/poet.song.131000.json','["老抱遺書隱故山，鏡中衰鬢似霜菅。", "規模肯墮管蕭亞，夢想每馳河渭間。", "竹帛竟孤千載事，江湖敢恨一生閑。", "殘功賴有吾兒續，把卷燈前爲破顔。"]'),
('b4fea52b-8e1e-46c1-8b18-1029d1b9447d','酒熟','陸游','宋','宋诗','song-poetry','','[]','侯印何由得酒泉，小槽新熟亦欣然。',32,'全唐诗/poet.song.131000.json','["侯印何由得酒泉，小槽新熟亦欣然。", "放翁達處過彭澤，客自在傍吾自眠。"]'),
('d261431a-fe70-4a9c-bcdc-28f9c7bb4f32','病起遊近村','陸游','宋','宋诗','song-poetry','','[]','老人摧頹絕造請，門設常關草生徑。',96,'全唐诗/poet.song.131000.json','["老人摧頹絕造請，門設常關草生徑。", "一年三百六十日，三百五十九日病。", "一日不病出忘歸，繞村處處扣柴扉。", "水東溪友新酒熟，舍北園公菰菜肥。", "平生養氣心不動，黜陟雖聞了如夢。", "從今病愈即相尋，共聽糟床滴春甕。"]'),
('507a9d9a-400c-4ed3-874c-0679260601c6','秋夜讀書示兒子','陸游','宋','宋诗','song-poetry','','[]','久病少睡眠，往往中夕起。',96,'全唐诗/poet.song.131000.json','["久病少睡眠，往往中夕起。", "呼燈取書讀，不能盡數紙。", "喟然置之嘆，生世後闕里。", "持蠡欲測海，遽復迫老死。", "人生各有業，唐虞本吾事。", "詩書脫秦厄，天意固在此。", "異端塞穹壤，作俑孰爲始。", "神禹逝不還，吾其如洚水。"]'),
('11ccd490-2a71-441b-956b-1fc1966c0074','秋晚書感','陸游','宋','宋诗','song-poetry','','[]','丘塚相望故舊空，放翁猶復寄漚中。',64,'全唐诗/poet.song.131000.json','["丘塚相望故舊空，放翁猶復寄漚中。", "少眠危坐待窗白，得酒細傾生頰紅。", "雖愧蛟龍起雲雨，尚勝魚鳥困池籠。", "秋來莫道無遊興，野渡村橋處處通。"]'),
('a530cb7e-f8b8-456e-9816-fd504a04803e','王成之給事挽歌辭二首  其一','陸游','宋','宋诗','song-poetry','','[]','昔泝黄牛峽，曾經白鷺洲。',48,'全唐诗/poet.song.131000.json','["昔泝黄牛峽，曾經白鷺洲。", "從容參步武，談笑極風流。", "晚預蓬萊客，時從禊祓遊。", "揮毫看半醉，追想只添愁。"]'),
('ff7bea7d-6731-4a48-a03c-6c7f5009e101','王成之給事挽歌辭二首  其二','陸游','宋','宋诗','song-poetry','','[]','詩騷湘水客，風度曲江公。',48,'全唐诗/poet.song.131000.json','["詩騷湘水客，風度曲江公。", "一夕南樓去，千秋東省空。", "囊封震朝右，墨敕絕宮中。", "贈極文昌貴，君恩厚飾終。"]'),
('3f81da46-15f3-4e0a-9c90-a568e9ad46fa','書南堂壁二首  其一','陸游','宋','宋诗','song-poetry','','[]','偶筑湖邊舍，侵尋四十春。',48,'全唐诗/poet.song.131000.json','["偶筑湖邊舍，侵尋四十春。", "山丘未埋骨，詩酒尚關身。", "樵路霜侵屨，漁舟雨墊巾。", "忝蒙鄉黨敬，六聖有遺民。"]'),
('e8f3bc40-a640-45f2-aee4-3893bfbaa563','書南堂壁二首  其二','陸游','宋','宋诗','song-poetry','','[]','荒寒淺村步，隱翳小茅茨。',48,'全唐诗/poet.song.131000.json','["荒寒淺村步，隱翳小茅茨。", "偶逐漁樵住，都忘歲月移。", "閑惟接僧話，老始愛陶詩。", "耆齒猶須幾，羸然敢自期。"]'),
('976245f4-ab33-4c00-aaeb-921af4497c65','秋晚','陸游','宋','宋诗','song-poetry','','[]','寒渚雁新下，壞牆蛩夜吟。',48,'全唐诗/poet.song.131000.json','["寒渚雁新下，壞牆蛩夜吟。", "庭莎欲無色，園樹不成陰。", "霑灑孤臣泪，馳驅壯士心。", "明朝鏡中髮，飽受雪霜侵。"]'),
('dce4ac8f-d039-482e-a09d-60c952d02c86','晨起待子聿歸','陸游','宋','宋诗','song-poetry','','[]','老人盥櫛罷，坐待汝晨省。',72,'全唐诗/poet.song.131000.json','["老人盥櫛罷，坐待汝晨省。", "忽思隔重關，懷抱增耿耿。", "小雨暗北窗，誰與慰凄冷。", "卷書默袖手，奈此清晝永。", "懸知河橋下，亦已喚舴艋。", "長路歸當饑，呼童具湯餅。"]'),
('6f280bc1-5ea0-4399-bf98-d480462dc71c','信筆二首  其一','陸游','宋','宋诗','song-poetry','','[]','吾生本暫寓，無日不可死。',48,'全唐诗/poet.song.131000.json','["吾生本暫寓，無日不可死。", "區區遲速間，何地著慍喜。", "朝移一株石，暮引一脈水。", "是中亦何樂，一笑聊爾耳。"]'),
('48404082-6286-4d39-9463-4a5ea566fc97','信筆二首  其二','陸游','宋','宋诗','song-poetry','','[]','有酒或一醉，無酒終日閑。',48,'全唐诗/poet.song.131000.json','["有酒或一醉，無酒終日閑。", "雨足通南澗，木落見西山。", "飯飽出柴門，本散腰脚頑。", "偶然遇野人，笑語欲忘還。"]'),
('2fa80f5d-7226-42f7-b792-7ff0203d1ee4','龜堂東窗戲弄筆墨偶得絕句五首  其一','陸游','宋','宋诗','song-poetry','','[]','身如蠶老已三眠，一繭何妨自裹纏。',32,'全唐诗/poet.song.131000.json','["身如蠶老已三眠，一繭何妨自裹纏。", "豆飯藜羹支永日，槿籬竹屋送餘年。"]'),
('e8658d0e-e92e-4240-bb2d-946f2fe93532','龜堂東窗戲弄筆墨偶得絕句五首  其二','陸游','宋','宋诗','song-poetry','','[]','一樽且復罄幽歡，不是癡頑强自寬。',32,'全唐诗/poet.song.131000.json','["一樽且復罄幽歡，不是癡頑强自寬。", "死去何憂累兒子，千錢可買市成棺。"]'),
('c052ec01-bef6-4afa-9666-830d9914f8e6','龜堂東窗戲弄筆墨偶得絕句五首  其三','陸游','宋','宋诗','song-poetry','','[]','北菴睡起坐東廂，無事方知日月長。',32,'全唐诗/poet.song.131000.json','["北菴睡起坐東廂，無事方知日月長。", "天與詩人送詩本，一雙黄蝶弄秋光。"]'),
('3a979228-5baa-4aa7-b9c6-ca74d4d68cab','龜堂東窗戲弄筆墨偶得絕句五首  其四','陸游','宋','宋诗','song-poetry','','[]','老衰有驗詩先退，勳業無心夢漸稀。',32,'全唐诗/poet.song.131000.json','["老衰有驗詩先退，勳業無心夢漸稀。", "淺浦小山孤絕處，數家烟火自相依。"]'),
('671d5c98-0d5f-4595-94c7-ed90156304a4','龜堂東窗戲弄筆墨偶得絕句五首  其五','陸游','宋','宋诗','song-poetry','','[]','老人孤寂似無家，午枕初回日已斜。',32,'全唐诗/poet.song.131000.json','["老人孤寂似無家，午枕初回日已斜。", "偶得風和身亦健，舍南舍北探梅花。"]'),
('e2fbc250-2cc7-4f58-98e7-3184cf3947cb','次呂子益韵','陸游','宋','宋诗','song-poetry','','["\u897f\u6e56"]','呂子奇才非復常，詩來起我醉中狂。',64,'全唐诗/poet.song.131000.json','["呂子奇才非復常，詩來起我醉中狂。", "大音誰和陽春曲，真色一空時世妝。", "東閤獻諛無轍迹，西湖寄傲有杯觴。", "病懷正待君湔祓，墨妙時須寄數行。"]'),
('f865ea75-2877-46ad-8d6b-77f29230df4b','舍北行飯書觸目二首  其一','陸游','宋','宋诗','song-poetry','','[]','晚餐初潑一甌茶，曳杖閑行興未涯。',64,'全唐诗/poet.song.131000.json','["晚餐初潑一甌茶，曳杖閑行興未涯。", "烟樹參差墨濃淡，風鴉零亂字橫斜。", "夕陽偏傍平橋路，寒蝶猶依晚菊花。", "堪笑衰翁耐荒寂，短衣霑露未還家。"]'),
('482d2066-05d6-4e4f-b9a8-9a0d1ae25fdc','舍北行飯書觸目二首  其二','陸游','宋','宋诗','song-poetry','','[]','落雁昏鴉集遠洲，青林紅樹擁平疇。',64,'全唐诗/poet.song.131000.json','["落雁昏鴉集遠洲，青林紅樹擁平疇。", "意行舍北三叉路，閑看橋西一片秋。", "小婦破烟撐去艇，丫童橫笛喚歸牛。", "形容野景無餘思，自怪癡頑不解愁。"]'),
('5bb92256-14e9-4fb4-b8ed-6a187f4ed501','明日復得五字二首  其一','陸游','宋','宋诗','song-poetry','','[]','羸病偶不死，端居思出遊。',48,'全唐诗/poet.song.131000.json','["羸病偶不死，端居思出遊。", "山寒麥苗短，天闊雁聲遒。", "學劍元癡絕，脂車久罷休。", "鄰翁獨眷眷，同好自相求。"]'),
('d92d6769-15b6-4c05-9ffe-0d4392a4209d','明日復得五字二首  其二','陸游','宋','宋诗','song-poetry','','[]','腰痛今朝愈，褰裳野興長。',48,'全唐诗/poet.song.131000.json','["腰痛今朝愈，褰裳野興長。", "黄鴉號亂篠，碧蝶繞枯桑。", "陂壞良疇廢，村空舊路荒。", "十年逢九潦，誰與問蒼蒼。"]'),
('b8ac4f66-9cbc-42a5-9bec-e7574b98491d','十一月二十二日夜待子聿未歸','陸游','宋','宋诗','song-poetry','','[]','寒爐火半銷，壞壁燈欲死。',56,'全唐诗/poet.song.131000.json','["寒爐火半銷，壞壁燈欲死。", "人行籬犬吠，月出林鵲起。", "吾兒信偶非長路，老子可憐煎百慮。", "人人父子與我同，立朝勿遣交河戍。"]'),
('d187a8e8-dc83-4f85-99ac-edc9eeb76715','南窗','陸游','宋','宋诗','song-poetry','','[]','暄妍一窗日，的礫數枝梅。',48,'全唐诗/poet.song.131000.json','["暄妍一窗日，的礫數枝梅。", "小鼎煎茶熟，幽人作夢回。", "新春又將近，晚景但堪哀。", "用底舒懷抱，殘書闔復開。"]'),
('48148eca-499c-48e1-814d-cf034ccadfaf','幽居','陸游','宋','宋诗','song-poetry','','[]','衰鬢蕭條笑舊青，一枝棲穩寄餘齡。',64,'全唐诗/poet.song.131000.json','["衰鬢蕭條笑舊青，一枝棲穩寄餘齡。", "徐行不愧衣露肘，安卧何妨席見經。", "視客恰如堂上燕，捐書那願案頭螢。", "時時開說前賢事，聊遣鄉閭識典刑。"]'),
('5bdd795d-232d-42ff-95e8-0a26cdbd29df','春近山中即事三首  其一','陸游','宋','宋诗','song-poetry','','[]','乞得松楠手自栽，結茅聊喜避風埃。',64,'全唐诗/poet.song.131000.json','["乞得松楠手自栽，結茅聊喜避風埃。", "百年孰與夢長短，萬事只如雲去來。", "雪後梅花初半吐，身閑樽酒盍頻開。", "錦官城外青羊路，常記當年小獵回。"]'),
('6f7e6e88-02eb-44c5-b2ae-1e566e524f25','春近山中即事三首  其二','陸游','宋','宋诗','song-poetry','','[]','節物貧家有故常，春盤臘粥逐時忙。',64,'全唐诗/poet.song.131000.json','["節物貧家有故常，春盤臘粥逐時忙。", "悠悠歲月催雙鬢，草草雞豚薦一觴。", "人意自殊平日樂，梅花寧減故時香。", "小園新展西南角，挂樹青蘿百尺長。"]'),
('bd5e0a04-e13b-4360-b35c-93e797c19b05','春近山中即事三首  其三','陸游','宋','宋诗','song-poetry','','[]','世亂王孫泣路隅，時平野老醉相扶。',64,'全唐诗/poet.song.131000.json','["世亂王孫泣路隅，時平野老醉相扶。", "種榿正可三年大，愛竹何曾一日無。", "細路迢迢上雲雨，輕舟渺渺入菰蒲。", "暮歸剩欲談幽勝，安得丹青爲作圖。"]'),
('85ff4e46-4d48-44e1-881e-dc52be9e9191','雪夜感舊','陸游','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u793e\u4f1a", "\u8ffd\u5fc6", "\u65c5\u9014", "\u6124\u61d1"]','江月亭前樺燭香，龍門閣上馱聲長。',64,'全唐诗/poet.song.131000.json','["江月亭前樺燭香，龍門閣上馱聲長。", "亂山古驛經三折，小市孤城宿兩當。", "晚歲猶思事鞍馬，當時那信老耕桑。", "綠沉金鎖俱塵委，雪灑寒燈泪數行。"]'),
('4561ca25-3914-41dd-a189-ca94d15dffd0','將進酒','陸游','宋','宋诗','song-poetry','','[]','我欲挽住北斗杓，常指蒼龍無動摇。',96,'全唐诗/poet.song.131000.json','["我欲挽住北斗杓，常指蒼龍無動摇。", "春風日夜吹草木，只有榮盛無時凋。", "我欲剗斷日行道，陽烏當空月杲杲。", "非惟四海常不夜，亦使人生失衰老。", "如山積麴高崔嵬，大江釀作蒲萄醅。", "頹然一醉三千杯，借問白髮何從來。"]'),
('e11b654b-9e16-482f-a911-465174568442','歲暮懷張季長','陸游','宋','宋诗','song-poetry','','[]','已迫桑榆景，况逢梅柳時。',48,'全唐诗/poet.song.131000.json','["已迫桑榆景，况逢梅柳時。", "功名終自誤，老病獨如期。", "醉眼嫌天迮，孤吟覺鬼悲。", "唐安在何許，無字寄相思。"]'),
('022bb2be-c0bd-4d14-af84-22fd9e973d38','謝朱元晦寄紙被二首  其一','陸游','宋','宋诗','song-poetry','','[]','木枕藜床席見經，卧看飄雪入窗欞。',32,'全唐诗/poet.song.131000.json','["木枕藜床席見經，卧看飄雪入窗欞。", "布衾紙被元相似，只欠高人爲作銘。"]'),
('23c26c33-1f78-4298-96a8-5b1ee2464fb2','謝朱元晦寄紙被二首  其二','陸游','宋','宋诗','song-poetry','','[]','紙被圍身度雪天，白於狐腋軟於綿。',32,'全唐诗/poet.song.131000.json','["紙被圍身度雪天，白於狐腋軟於綿。", "放翁用處君知否，絕勝蒲團夜坐禪。"]'),
('d01aec52-d47e-4154-83d2-4b847106f272','送王季嘉赴湖南漕司主管官','陸游','宋','宋诗','song-poetry','','[]','它人作陵邑，榜笞朝暮急。',80,'全唐诗/poet.song.131000.json','["它人作陵邑，榜笞朝暮急。", "王子乃不然，袖手萬事集。", "它人西入都，競裁丞相書。", "王子掉頭去，長沙萬里餘。", "問子謀身無乃左，凜如霜松姿磊砢。", "屈原賈誼死有靈，計此兩人心獨可。"]'),
('148c014b-ec9e-4194-aab9-c01e5830eb71','庵中夜興','陸游','宋','宋诗','song-poetry','','[]','示疾維摩無侍者，夜闌自掩草庵門。',64,'全唐诗/poet.song.131000.json','["示疾維摩無侍者，夜闌自掩草庵門。", "有情梅影半窗月，相應雞聲十里村。", "紙帳擁裘尋斷夢，地爐撥火暖殘樽。", "扶衰又踐新春境，萬事元知不足論。"]'),
('b2b1b908-27df-4f63-ba59-92ee08a1c068','初春欲散步畏寒而歸','陸游','宋','宋诗','song-poetry','','[]','峭寒漠漠入重貂，酒力欺人凝不消。',64,'全唐诗/poet.song.131000.json','["峭寒漠漠入重貂，酒力欺人凝不消。", "春困苦多無處賣，客魂欲斷倩誰招。", "一溪水淺梅枝瘦，四野雲酣雪意驕。", "欲到前村無奈懶，却尋歸路度西橋。"]'),
('ef98724e-0109-4d7d-8201-9c63abf42bf4','憶昔','陸游','宋','宋诗','song-poetry','','[]','憶昔從戎出渭濱，壺漿馬首泣遺民。',64,'全唐诗/poet.song.131000.json','["憶昔從戎出渭濱，壺漿馬首泣遺民。", "夜棲高冢占星象，晝上巢車望虜塵。", "共道功名方迫逐，豈知老病只逡巡。", "燈前撫卷空流涕，何限人間失意人。"]'),
('d8003410-bdea-4012-a609-a14afceb2be6','戊午元日讀書至夜分有感二首  其一','陸游','宋','宋诗','song-poetry','','[]','七十年來又四年，雨聲燈影故依然。',64,'全唐诗/poet.song.131000.json','["七十年來又四年，雨聲燈影故依然。", "未收浮世風漚夢，尚了前生蠹簡緣。", "老學辛勤那有補，舊聞零落恐無傳。", "先師鉢袋終當付，嘆息誰能共著鞭。"]'),
('5270cf50-7a61-45be-80f3-c4676e645c21','戊午元日讀書至夜分有感二首  其二','陸游','宋','宋诗','song-poetry','','[]','强戴羅旛怯歲增，光陰堪嘆捷飛騰。',64,'全唐诗/poet.song.131000.json','["强戴羅旛怯歲增，光陰堪嘆捷飛騰。", "簷間點滴新春雨，窗下青熒半夜燈。", "傍架討尋書散亂，倚屏吟嘯髮鬅鬙。", "極知老境惟當佚，絕學端居恨未能。"]'),
('15350d49-54fb-4db6-8972-3e37f1f80a7c','雜感十首  其一','陸游','宋','宋诗','song-poetry','','[]','志士山棲恨不深，人知已是負初心。',32,'全唐诗/poet.song.131000.json','["志士山棲恨不深，人知已是負初心。", "不須先說嚴光輩，直自巢由錯到今。"]'),
('724fb622-917a-4e7c-b448-67e9095dfbc1','雜感十首  其二','陸游','宋','宋诗','song-poetry','','[]','勸君莫識一丁字，此事從來誤幾人。',32,'全唐诗/poet.song.131000.json','["勸君莫識一丁字，此事從來誤幾人。", "輸與茅簷負暄叟，時時睡覺一頻伸。"]'),
('083e3759-9887-4d4c-840d-f7b16cd22a5a','雜感十首  其三','陸游','宋','宋诗','song-poetry','','[]','世事紛紛無已時，勸君杯到不須辭。',32,'全唐诗/poet.song.131000.json','["世事紛紛無已時，勸君杯到不須辭。", "但能爛醉三千日，楚漢興亡總不知。"]'),
('7541ed5c-7605-45dc-9647-e209d009ee5f','雜感十首  其四','陸游','宋','宋诗','song-poetry','','[]','百年鼎鼎成何事，寒暑相催即白頭。',32,'全唐诗/poet.song.131000.json','["百年鼎鼎成何事，寒暑相催即白頭。", "縱得金丹真不死，摩挲銅狄更添愁。"]'),
('6d12e898-90ae-48f5-b27e-0d60644c7a73','雜感十首  其五','陸游','宋','宋诗','song-poetry','','[]','世間魚鳥各飛沉，茅屋青山無古今。',32,'全唐诗/poet.song.131000.json','["世間魚鳥各飛沉，茅屋青山無古今。", "畢竟替他愁不得，幾人虛費一生心。"]'),
('13dc811a-ed60-428c-958d-5de9bdddf10b','雜感十首  其六','陸游','宋','宋诗','song-poetry','','[]','一杯濁酒即醺然，自笑閑愁七十年。',32,'全唐诗/poet.song.131000.json','["一杯濁酒即醺然，自笑閑愁七十年。", "今日出門天地別，此身如在結繩前。"]'),
('de10e514-153f-48fc-b914-c44d779eb066','雜感十首  其七','陸游','宋','宋诗','song-poetry','','[]','山人那信宦塗艱，强著朝衣趁曉班。',32,'全唐诗/poet.song.131000.json','["山人那信宦塗艱，强著朝衣趁曉班。", "豪氣不除狂態作，始知只合死空山。"]'),
('4ddd6c1e-b416-48a1-a39d-9a9849a2774c','雜感十首  其八','陸游','宋','宋诗','song-poetry','','[]','老子傾囊得萬錢，石帆山下買烏犍。',32,'全唐诗/poet.song.131000.json','["老子傾囊得萬錢，石帆山下買烏犍。", "牧童避雨歸來晚，一笛春風草滿川。"]'),
('4e7e69cb-39d6-490b-96d8-645b34e518a3','雜感十首  其九','陸游','宋','宋诗','song-poetry','','[]','故舊書來訪死生，時聞剝啄叩柴荆。',32,'全唐诗/poet.song.131000.json','["故舊書來訪死生，時聞剝啄叩柴荆。", "自嗟不及東家老，至死無人識姓名。"]'),
('2669cd75-7833-4440-b6d7-7102e1726943','雜感十首  其一○','陸游','宋','宋诗','song-poetry','','[]','忍窮待死十年間，老子誰知老更頑。',32,'全唐诗/poet.song.131000.json','["忍窮待死十年間，老子誰知老更頑。", "溪友留魚供晚酌，鄰僧送米續朝餐。"]'),
('fe8ae81f-0d7f-41f1-a2e0-b020b5eccf8d','嘆老','陸游','宋','宋诗','song-poetry','','[]','朋儕什九墮丘墟，自笑身如脫網魚。',64,'全唐诗/poet.song.131000.json','["朋儕什九墮丘墟，自笑身如脫網魚。", "委命已悲吾道喪，垂名真負此心初。", "齒殘僅可决濡肉，眼澀知難讀細書。", "家事豈容關老子，兒曹努力事耕鉏。"]'),
('7f4e3824-b878-49e2-9f69-d5ae93e62e5e','朝饑食齏麫甚美戲作二首  其一','陸游','宋','宋诗','song-poetry','','[]','一杯齏餺飥，老子腹膨脝。',24,'全唐诗/poet.song.131000.json','["一杯齏餺飥，老子腹膨脝。", "坐擁茅簷日，山茶未用烹。"]'),
('6b525a29-403b-42c7-8125-c5d08bbbd97c','朝饑食齏麫甚美戲作二首  其二','陸游','宋','宋诗','song-poetry','','[]','一杯齏餺飥，手自芼油葱。',24,'全唐诗/poet.song.131000.json','["一杯齏餺飥，手自芼油葱。", "天上蘇陀供，懸知未易同。"]'),
('d70de84a-2bd1-4a7d-943a-58fe1f7c0442','漁隱堂獨坐至夕','陸游','宋','宋诗','song-poetry','','[]','斜倚筇枝岸幅巾，閉門久已謝知聞。',64,'全唐诗/poet.song.131000.json','["斜倚筇枝岸幅巾，閉門久已謝知聞。", "中庭日正花無影，曲沼風生水有紋。", "三尺桐絲多靜寄，一樽玉瀣足幽欣。", "世間萬事都忘盡，惟向閑中屢策勳。"]'),
('5e1a8bfb-3286-4e29-8eae-e4ba70427d76','讀書','陸游','宋','宋诗','song-poetry','','[]','讀書肝膽尚輪囷，蠹簡堆中著此身。',64,'全唐诗/poet.song.131000.json','["讀書肝膽尚輪囷，蠹簡堆中著此身。", "飽識三千餘歲事，已爲七十四年人。", "鏡中衰鬢難藏老，海內虛名不救貧。", "只欲從今都掃盡，剩沽春酒答新春。"]'),
('28f4298d-7973-47bc-ab24-1897b85dbbf7','北望','陸游','宋','宋诗','song-poetry','','[]','昔我初生歲，中原失太平。',48,'全唐诗/poet.song.131000.json','["昔我初生歲，中原失太平。", "寧知墓木拱，不見塞塵清。", "京洛無來信，江淮尚宿兵。", "何時青海月，重照漢家營。"]'),
('fb9c9545-7f68-4e05-9ac2-fe223de439c2','蘭','陸游','宋','宋诗','song-poetry','','[]','南巖路最近，飯已時散策。',48,'全唐诗/poet.song.131000.json','["南巖路最近，飯已時散策。", "香來知有蘭，遽求乃弗獲。", "生世本幽谷，豈願爲世娛。", "無心託階庭，當門任君鋤。"]'),
('42cea954-7445-454e-9f2b-8f5ceafea18d','古梅','陸游','宋','宋诗','song-poetry','','[]','梅花吐幽香，百卉皆可屏。',48,'全唐诗/poet.song.131000.json','["梅花吐幽香，百卉皆可屏。", "一朝見古梅，梅亦墮凡境。", "重疊碧蘚暈，夭矯蒼虯枝。", "誰汲古磵水，養此塵外姿。"]'),
('7e07cbd6-bea1-4658-9f45-09e5264022b9','山脚散步由舍北歸三首  其一','陸游','宋','宋诗','song-poetry','','[]','偶散東岡步，因成北渚遊。',48,'全唐诗/poet.song.131000.json','["偶散東岡步，因成北渚遊。", "鴉昏先小泊，魚暖欲群浮。", "緩曳紅藤杖，斜披紫綺裘。", "閑身病亦可，隨處得無愁。"]'),
('05fd3ff1-4268-421c-85f4-2bff6c0c4413','山脚散步由舍北歸三首  其二','陸游','宋','宋诗','song-poetry','','[]','幽徑欣行藥，衰年困負薪。',48,'全唐诗/poet.song.131000.json','["幽徑欣行藥，衰年困負薪。", "梅殘香更遠，草動綠初勻。", "魚似濠梁樂，鷗如海上馴。", "度橋成一笑，微健及新春。"]'),
('835f5636-8aef-4162-86b5-62d5c826b164','山脚散步由舍北歸三首  其三','陸游','宋','宋诗','song-poetry','','[]','空碧升團月，江郊弄夕霏。',48,'全唐诗/poet.song.131000.json','["空碧升團月，江郊弄夕霏。", "生涯今始是，年事古猶稀。", "冰解魚初躍，風和雁欲歸。", "興來忘遠近，草露已沾衣。"]'),
('086a91f6-f7ae-4dc8-8818-f3257a887dc5','寄題連江陳氏拂石軒','陸游','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','平生聞說西江水，百丈奫淪深見底。',128,'全唐诗/poet.song.131000.json','["平生聞說西江水，百丈奫淪深見底。", "漁舟來去白鷗飛，上有綸巾隱君子。", "作詩自許輩陶謝，嘯傲烟雲弄清泚。", "紛紛聲利滿人間，耳本不聞安用洗。", "李公過江號高流，逸氣凜凜橫清秋。", "沙邊一笑偶邂逅，掃石蔭松相獻酬。", "浩歌聲斷七十載，尚寄萬壑風颼飀。", "放翁老憊狂未歇，買船欲作西江遊。"]'),
('0e32137b-70e3-49cf-a023-4daa52c9d0aa','得張季長書以大蓬見稱蓋以予寄祿官視昔祕書監也因作五字寄之','陸游','宋','宋诗','song-poetry','','[]','老病江湖上，煩公問死生。',48,'全唐诗/poet.song.131000.json','["老病江湖上，煩公問死生。", "僊蓬雖誤到，殘錦只虛名。", "點滴三更雨，凄凉萬里情。", "向來遺恨極，不遂隱青城。"]'),
('b815fcd3-092f-46be-aed4-6f5042c3c2a5','病足累日不能出庵門折花自娛','陸游','宋','宋诗','song-poetry','','[]','頻報園花照眼明，蹣跚正廢下堂行。',64,'全唐诗/poet.song.131000.json','["頻報園花照眼明，蹣跚正廢下堂行。", "擁衾又聽五更雨，屈指元無三日晴。", "不奈病何拋酒醆，粗知春在賴鶯聲。", "一枝自浸銅瓶水，喜與年光未隔生。"]'),
('48d0df8f-0259-4ee2-8edd-82481aa397b0','書意','陸游','宋','宋诗','song-poetry','','[]','帝命煌煌敕百神，方傾天漢洗胡塵。',64,'全唐诗/poet.song.131000.json','["帝命煌煌敕百神，方傾天漢洗胡塵。", "但須荆州一好漢，安用商山四老人。", "竹帛恐貽千古笑，江湖未愧百年身。", "此心欲與何人說，病足呻吟又過春。"]'),
('f5ba7fa6-77cc-4417-9814-62aff6584eda','新燕','陸游','宋','宋诗','song-poetry','','[]','天工不用翦刀催，山杏溪桃次第開。',32,'全唐诗/poet.song.131000.json','["天工不用翦刀催，山杏溪桃次第開。", "要信今年春事早，社前十日燕新來。"]'),
('e1bf6eb2-673e-446f-a79e-159b250664ee','北巖采新茶用忘懷錄中法煎飲欣然忘病之未去也','陸游','宋','宋诗','song-poetry','','[]','槐火初鉆燧，松風自候湯。',48,'全唐诗/poet.song.131000.json','["槐火初鉆燧，松風自候湯。", "携籃苔徑遠，落爪雪芽長。", "細啜襟靈爽，微吟齒頰香。", "歸時更清絕，竹影踏斜陽。"]'),
('d27c86aa-c4ce-4ba8-8bbb-ec0227829677','連日至梅僊塢及花涇觀桃花抵暮乃歸二首  其一','陸游','宋','宋诗','song-poetry','','[]','千載桃源信不通，鏡湖西塢擅春風。',64,'全唐诗/poet.song.131000.json','["千載桃源信不通，鏡湖西塢擅春風。", "舟行十里畫屏上，身在西山紅雨中。", "俗事挽人常故故，夕陽歸櫂莫匆匆。", "豪華無復當年樂，爛醉狂歌亦足雄。"]'),
('83e928cf-ec98-4af9-ad0a-a11882a10e70','連日至梅僊塢及花涇觀桃花抵暮乃歸二首  其二','陸游','宋','宋诗','song-poetry','','[]','桃花塢近釣魚磯，不比劉郎萬里歸。',64,'全唐诗/poet.song.131000.json','["桃花塢近釣魚磯，不比劉郎萬里歸。", "水底紅雲迷醉眼，樽前絳雪點春衣。", "病依几杖猶能出，老愛風光未忍違。", "天借清遊每窮日，夜深炬火候柴扉。"]'),
('1e0d70dd-bb30-4f15-8a43-2a40a5e0e714','病中作','陸游','宋','宋诗','song-poetry','','[]','破裘縫更暖，糲食美無餘。',48,'全唐诗/poet.song.131000.json','["破裘縫更暖，糲食美無餘。", "摩詰病說法，虞卿窮著書。", "身羸支枕久，足蹇下堂疏。", "今日晴窗好，幽懷得好攄。"]'),
('df7fc3b7-50e0-4d4a-9c06-0769563a555c','題郭太尉金州第中至喜堂','陸游','宋','宋诗','song-poetry','','[]','安康甲第天下傳，玉題繡井摩雲烟。',160,'全唐诗/poet.song.131000.json','["安康甲第天下傳，玉題繡井摩雲烟。", "落成鼓吹震百里，意氣欲壓秦山川。", "第中筑堂最宏麗，奎畫岌岌蛟龍纏。", "知公所喜在勇退，顧視解組如登仙。", "公心雖爾天未可，終倚北伐銘燕然。", "十年宿衛功第一，小却卧護長淮邊。", "帳前犀甲羅十萬，幕下珠履逾三千。", "願公小緩高枕計，即今河雒猶腥膻。", "出師雞鹿擁皂纛，畫象麒麟峨玉蟬。", "是時公喜客亦樂，爲公滿瀉黄金船。"]'),
('5d683c65-10ea-44cc-b44c-a6d977304af8','暮春','陸游','宋','宋诗','song-poetry','','[]','山陰又見暮春初，禁火園林社雨餘。',64,'全唐诗/poet.song.131000.json','["山陰又見暮春初，禁火園林社雨餘。", "世事不妨隨日改，年光未遽與人疏。", "豉香下箸嘗蓴菜，鹽白開奩得䱥魚。", "草草一杯終可喜，數間茅屋亦吾廬。"]'),
('59137ff7-fada-4cd8-9eec-ebb0a7e63af7','小園新晴二首  其一','陸游','宋','宋诗','song-poetry','','[]','散髮陽狂不計年，園林只在小窗前。',64,'全唐诗/poet.song.131000.json','["散髮陽狂不計年，園林只在小窗前。", "斷虹千尺卷殘雨，新月一鈎生暮天。", "臘釀拆泥留客醉，山茶落磑喚兒煎。", "物華心賞元無盡，剩住人間作地仙。"]'),
('bd1c43c0-cae4-473a-8491-7baa1b26056b','小園新晴二首  其二','陸游','宋','宋诗','song-poetry','','[]','衰病猶煩藥石功，殘春終日在園中。',64,'全唐诗/poet.song.131000.json','["衰病猶煩藥石功，殘春終日在園中。", "地偏幽草爲誰綠，雨霽新花如許紅。", "足蹇扶持須稚子，杯深暖熱賴鄰翁。", "此身雖向閑中老，若比休休却未同。"]'),
('39620aaa-c413-46dd-9d06-4e6360647f61','春晚感事二首  其一','陸游','宋','宋诗','song-poetry','','[]','據鞍千里何曾病，閉戶安眠百病生。',32,'全唐诗/poet.song.131000.json','["據鞍千里何曾病，閉戶安眠百病生。", "每憶嘉陵江上路，插花藉草醉清明。"]'),
('3c2d9fc1-def1-4d40-aa9f-fdfa2838f379','春晚感事二首  其二','陸游','宋','宋诗','song-poetry','','[]','寒食梁州十萬家，鞦韆蹴鞠尚豪華。',32,'全唐诗/poet.song.131000.json','["寒食梁州十萬家，鞦韆蹴鞠尚豪華。", "犢車轣轆歸城晚，爭碾平蕪入亂花。"]'),
('e7358310-c3cd-439e-9139-dd7a60fd6056','春晚園中作','陸游','宋','宋诗','song-poetry','','[]','杏子青青梅子酸，山園轉眼又春殘。',64,'全唐诗/poet.song.131000.json','["杏子青青梅子酸，山園轉眼又春殘。", "老懷豈復小年樂，病骨不禁清曉寒。", "學術背時甘義墮，功名無路久心闌。", "蠶收麥熟吾何恨，但遣銀杯似海寬。"]'),
('346d37b8-f95c-4d04-8143-700034054e76','題夷堅志後','陸游','宋','宋诗','song-poetry','','[]','筆近反離騷，書非支諾皋。',48,'全唐诗/poet.song.131000.json','["筆近反離騷，書非支諾皋。", "豈惟堪史補，端足擅文豪。", "馳騁空凡馬，從容立斷鼇。", "陋儒那得議，汝輩亦徒勞。"]'),
('d06133dd-1c13-4a33-9989-ee7e693f410d','幽居','陸游','宋','宋诗','song-poetry','','[]','小舫藤爲纜，幽居竹織門。',48,'全唐诗/poet.song.131000.json','["小舫藤爲纜，幽居竹織門。", "短籬圍藕蕩，細路入桑村。", "魚膾槎頭美，醅傾粥面渾。", "殘年謝軒冕，猶足號黎元。"]'),
('1843180e-9787-4178-ae92-59bd0268df46','聞鳥聲有感二首  其一','陸游','宋','宋诗','song-poetry','','[]','小市提壺酤濁酒，東陂脫袴插青秧。',32,'全唐诗/poet.song.131000.json','["小市提壺酤濁酒，東陂脫袴插青秧。", "歸來靜卧茅簷底，如覺閑中白日長。"]'),
('d967a94d-89b9-4e7f-b3d1-ae5e229dff6b','聞鳥聲有感二首  其二','陸游','宋','宋诗','song-poetry','','[]','流年冉冉去無情，日夜溪頭布穀聲。',32,'全唐诗/poet.song.131000.json','["流年冉冉去無情，日夜溪頭布穀聲。", "城郭雖存人換盡，令威應悔學長生。"]'),
('fda5ad69-ad85-4b1d-863b-2ba280cede71','與子虡子坦坐龜堂後東窗偶書','陸游','宋','宋诗','song-poetry','','[]','時鳥朝暮鳴，芳草日夜生。',96,'全唐诗/poet.song.131000.json','["時鳥朝暮鳴，芳草日夜生。", "春風捨我去，歲律俄崢嶸。", "綴簇繭白白，出陂稻青青。", "鳴機織苧葛，暑服亦已成。", "小兒結山房，窗戶頗疏明。", "萬事不挂眼，朱黄浩縱橫。", "佳哉東北風，吹下讀書聲。", "功名詎敢望，且復慰父兄。"]'),
('76337b1d-21c5-49d6-bf0d-f2440bffcd7e','行年','陸游','宋','宋诗','song-poetry','','[]','行年過七十，與世兩相忘。',48,'全唐诗/poet.song.131000.json','["行年過七十，與世兩相忘。", "墨沼龜魚樂，藥園芝晝香。", "吾生一蟲臂，世路幾羊腸。", "楮弁新裁就，翛然學道裝。"]'),
('ed3b5c83-dd73-446e-994f-52ae421b2f75','東窗小酌二首  其一','陸游','宋','宋诗','song-poetry','','[]','烏帽翩僊白苧凉，東窗隨事具杯觴。',64,'全唐诗/poet.song.131000.json','["烏帽翩僊白苧凉，東窗隨事具杯觴。", "流年不貸世人老，造物能容吾輩狂。", "藤葉成陰山鳥下，檜花滿地蜜蜂忙。", "何人畫得農家樂，咿軋繅車隔短牆。"]'),
('c6468663-d8c2-4c28-817e-5a6c619c394b','東窗小酌二首  其二','陸游','宋','宋诗','song-poetry','','[]','市塵遠不到林塘，嫩暑軒窗晝漏長。',64,'全唐诗/poet.song.131000.json','["市塵遠不到林塘，嫩暑軒窗晝漏長。", "蠶妾趁時爭鹽繭，農夫得雨正移秧。", "徒行有客驚頑健，爛醉無人笑老狂。", "却掩庵門徑投枕，鼾聲雷起撼藜床。"]'),
('9722eb86-abfe-4d45-b93f-00634b24fa73','西林傅庵主求定庵詩二首  其一','陸游','宋','宋诗','song-poetry','','[]','粥後鐘魚未動時，夜燈仍對碧琉璃。',32,'全唐诗/poet.song.131000.json','["粥後鐘魚未動時，夜燈仍對碧琉璃。", "不須更說能生慧，枯木寒灰也自奇。"]'),
('6b78ba9f-0a33-4c5c-9260-5c61d56efee6','西林傅庵主求定庵詩二首  其二','陸游','宋','宋诗','song-poetry','','[]','業力驅人舉世忙，西林袖手一爐香。',32,'全唐诗/poet.song.131000.json','["業力驅人舉世忙，西林袖手一爐香。", "未能成佛渾閑事，十劫看渠坐道場。"]'),
('18ed7d76-206e-4585-be1e-0228b814ca5d','夏日五首  其一','陸游','宋','宋诗','song-poetry','','[]','將雛燕子漸離巢，過母龍孫已放梢。',64,'全唐诗/poet.song.131000.json','["將雛燕子漸離巢，過母龍孫已放梢。", "日出並湖初曬網，雨餘乘屋旋添茅。", "家貧舊業元知廢，身老微官久合拋。", "莫恨門前車馬絕，豈無農圃與論交。"]'),
('b3a5703b-e0d6-4ba2-9626-57cddc36ccf4','夏日五首  其二','陸游','宋','宋诗','song-poetry','','[]','過眼春光久已空，曬絲擣麥又匆匆。',64,'全唐诗/poet.song.131000.json','["過眼春光久已空，曬絲擣麥又匆匆。", "新泥滿路梅黄雨，古木號山月暈風。", "角黍茭新間樽俎，靈符墨溼照房櫳。", "歲華不爲衰翁駐，且付餘生一笑中。"]'),
('8b45f6c1-2912-4064-a0eb-45ec17f749bc','夏日五首  其三','陸游','宋','宋诗','song-poetry','','[]','吳中五月暑猶微，竟日南堂坐掩扉。',64,'全唐诗/poet.song.131000.json','["吳中五月暑猶微，竟日南堂坐掩扉。", "綠樹露香鶯獨語，畫廊風惡燕雙歸。", "三千界內人人錯，七十年來念念非。", "投老萬緣俱掃盡，從今僧亦不須依。"]'),
('04ba04af-60ba-45fb-976e-b4355a265723','夏日五首  其四','陸游','宋','宋诗','song-poetry','','[]','雨斷雲歸旋作晴，尚餘紅溼在簾旌。',64,'全唐诗/poet.song.131000.json','["雨斷雲歸旋作晴，尚餘紅溼在簾旌。", "燕雛掠地飛無力，梅子臨池墜有聲。", "米粣解包供午餉，萍齏傍枕析朝酲。", "此翁不負頑軀處，捫腹時時繞舍行。"]'),
('a9d798a4-bb4c-444f-b08a-ccc3247cefc2','夏日五首  其五','陸游','宋','宋诗','song-poetry','','[]','梅雨初收景氣新，太平阡陌樂閑身。',64,'全唐诗/poet.song.131000.json','["梅雨初收景氣新，太平阡陌樂閑身。", "陂塘漫漫行秧馬，門巷陰陰挂艾人。", "白葛烏紗稱時節，黄雞綠酒聚比鄰。", "掀髯一笑吾真足，不爲無錐更嘆貧。"]'),
('c2ebf7aa-fbdf-442b-873e-31823c0d94c1','夜酌','陸游','宋','宋诗','song-poetry','','[]','酒淥孤燈夜，梅黄細雨天。',48,'全唐诗/poet.song.131000.json','["酒淥孤燈夜，梅黄細雨天。", "聊成顧影醉，復作曲肱眠。", "腰下蘇秦印，囊中趙壹錢。", "丈夫隨所遇，底處不陶然。"]'),
('0531c60e-2b54-4454-b52e-c5433ce77a8a','夏夜四首  其一','陸游','宋','宋诗','song-poetry','','[]','夏夜誰知亦自長，幽居渺在水雲鄉。',64,'全唐诗/poet.song.131000.json','["夏夜誰知亦自長，幽居渺在水雲鄉。", "月侵竹簟清無暑，風度衣篝潤有香。", "棲鵲自驚移別樹，流螢相逐過橫塘。", "放翁尚苦餘酲在，細綆銅瓶落井床。"]'),
('1b8eaa5e-9aa6-4981-aac1-197d5f852678','夏夜四首  其二','陸游','宋','宋诗','song-poetry','','[]','山崦風生鵩嘯悲，柴門月上樹陰移。',64,'全唐诗/poet.song.131000.json','["山崦風生鵩嘯悲，柴門月上樹陰移。", "熏衣汗雨初乾後，把卷蚊雷不動時。", "孤悶難禁終歲病，浮生易滿百年期。", "釣竿只待清秋近，一棹烟波信所之。"]'),
('89a44c60-292b-4c19-bfb3-641d553d74ab','夏夜四首  其三','陸游','宋','宋诗','song-poetry','','[]','展轉紗幮睡不成，一藤扶憊繞廊行。',64,'全唐诗/poet.song.131000.json','["展轉紗幮睡不成，一藤扶憊繞廊行。", "月昇雙鵲移枝宿，露下孤螢綴蔓明。", "汲井忽驚人已起，開門堪嘆事還生。", "羽衣道帽從吾好，柏子烟中起磬聲。"]'),
('d5eadf06-5ab8-4ecb-a4fa-8290056260a6','夏夜四首  其四','陸游','宋','宋诗','song-poetry','','[]','龜息綿綿破五更，起扶藤杖並南榮。',64,'全唐诗/poet.song.131000.json','["龜息綿綿破五更，起扶藤杖並南榮。", "擇栖孤鵲尚三匝，司旦老雞俄一鳴。", "移坐徐看山月吐，脫巾聊受水風清。", "不知竟是真仙未，夜夜神遊白玉京。"]'),
('dc02d070-b8f8-420f-a671-87f4b7ac364f','泛舟','陸游','宋','宋诗','song-poetry','','[]','水鄉元不減吳松，短櫂沿洄野興濃。',64,'全唐诗/poet.song.131000.json','["水鄉元不減吳松，短櫂沿洄野興濃。", "鬰鬰冬青森翠葆，離離夜合散紅茸。", "村深初度穿林笛，寺近先聞出塢鐘。", "歸路夕陽猶滿岸，憑舷一笑覽衰容。"]'),
('93b38016-3292-4be5-81e9-0d0ea1a5ff1e','感舊六首  其一','陸游','宋','宋诗','song-poetry','','[]','要識梁州遠，南山在眼邊。',48,'全唐诗/poet.song.131000.json','["要識梁州遠，南山在眼邊。", "霜郊熊撲樹，雪路馬蒙氈。", "慘淡遺壇側，蕭條古廟壖。", "百詩猶可想，嘆息遂無傳。"]'),
('031902d0-e667-4347-a269-4620321d8c62','感舊六首  其二','陸游','宋','宋诗','song-poetry','','[]','夜涉南沮水，朝過小益城。',48,'全唐诗/poet.song.131000.json','["夜涉南沮水，朝過小益城。", "梯山天一握，度棧土微平。", "雨近秦雲暗，霜高隴月明。", "至今孤夢裏，喝馬有遺聲。"]'),
('63210740-9a78-4670-ba51-356ad1abd781','感舊六首  其三','陸游','宋','宋诗','song-poetry','','[]','早發金堆市，更衣石柜亭。',48,'全唐诗/poet.song.131000.json','["早發金堆市，更衣石柜亭。", "灘聲秋後壯，山色雨餘青。", "道濘愁車轍，橋危避駝鈴。", "功名竟何在，撫事感頹齡。"]'),
('2f65611b-9213-47ad-947a-d078b100b7d1','感舊六首  其四','陸游','宋','宋诗','song-poetry','','[]','塵土暗貂裘，森然白髮稠。',48,'全唐诗/poet.song.131000.json','["塵土暗貂裘，森然白髮稠。", "年光真衮衮，吾事竟悠悠。", "馬宿平沙夜，烽傳絕塞秋。", "故人零落盡，追寫只添愁。"]'),
('ac33f433-2d12-40de-a149-c8333e3485e1','感舊六首  其五','陸游','宋','宋诗','song-poetry','','[]','凜凜隆中相，臨戎遂不還。',48,'全唐诗/poet.song.131000.json','["凜凜隆中相，臨戎遂不還。", "塵埃出師表，草棘定軍山。", "壯氣河潼外，雄名管樂間。", "登堂拜遺像，千載愧吾顔。"]'),
('bbf35c81-ec46-46ae-81a2-8be1d3cb8085','感舊六首  其六','陸游','宋','宋诗','song-poetry','','[]','我思杜陵叟，處處有遺蹤。',48,'全唐诗/poet.song.131000.json','["我思杜陵叟，處處有遺蹤。", "錦里瞻祠柏，綿州吊海棕。", "蹉跎悲櫪驥，感會失雲龍。", "生世後斯士，吾將安所從。"]'),
('c7b290b2-393d-42be-96ee-40478bcc8475','書喜','陸游','宋','宋诗','song-poetry','','[]','雨足郊原正得晴，地綿萬里盡春耕。',64,'全唐诗/poet.song.131000.json','["雨足郊原正得晴，地綿萬里盡春耕。", "陰陰阡陌桑麻暗，軋軋房櫳機杼鳴。", "亭鼓不聞知盜息，社錢易斂慶秋成。", "天公不負書生眼，留向人間看太平。"]'),
('940fa1a4-83e6-4878-8453-70a06b8d2e80','自詠','陸游','宋','宋诗','song-poetry','','[]','平生萬事付憨癡，兀兀騰騰到死時。',64,'全唐诗/poet.song.131000.json','["平生萬事付憨癡，兀兀騰騰到死時。", "夜踏亂雲過略彴，曉分寒溜注軍持。", "束薪山客招烹石，渡海蕃僧乞製碑。", "作箇生涯君勿笑，拄天勳業亦兒嬉。"]'),
('0443cf98-ab44-4741-b58e-73a6e6a8880c','露坐二首  其一','陸游','宋','宋诗','song-poetry','','[]','旋削甘瓜進酒卮，斷雲漠漠斗離離。',64,'全唐诗/poet.song.131000.json','["旋削甘瓜進酒卮，斷雲漠漠斗離離。", "北臨積水風來壯，東恨長林月上遲。", "秋近不堪聞急杵，夜凉已復怯輕絺。", "天孫老抱河梁恨，豈獨人生事可悲。"]'),
('34e1d7a5-c02f-4ea4-a262-8853c8688df3','露坐二首  其二','陸游','宋','宋诗','song-poetry','','[]','岸幘臨窗意未便，又拖筇杖出庭前。',64,'全唐诗/poet.song.131000.json','["岸幘臨窗意未便，又拖筇杖出庭前。", "清秋欲近露霑草，皎月未升星滿天。", "過埭船爭明旦市，蹋車人廢徹宵眠。", "齊民一飽勤如許，坐食官倉每惕然。"]'),
('d61db430-9e73-427e-99dd-78723b688330','親舊或見嘲終歲杜門戲作解嘲','陸游','宋','宋诗','song-poetry','','[]','十年蕭散住林間，只是幽居不是閑。',64,'全唐诗/poet.song.131000.json','["十年蕭散住林間，只是幽居不是閑。", "續得茶經新絕筆，補成僧史可藏山。", "詩題紫閣憑雲寄，藥報青城附鶴還。", "自笑何曾總無事，枉教人道閉柴關。"]'),
('4f89b433-1a48-4e4b-bb92-f2ade470cef6','北窗','陸游','宋','宋诗','song-poetry','','[]','寒泉斷藕素絲長，紋簟開瓜碧玉香。',32,'全唐诗/poet.song.131000.json','["寒泉斷藕素絲長，紋簟開瓜碧玉香。", "午睡覺來桐影轉，無人可共北窗凉。"]'),
('66355c99-9ef4-49d2-b694-3a029ef6636f','新秋以窗裏人將老門前樹欲秋爲韵作小詩十首  其一','陸游','宋','宋诗','song-poetry','','[]','殘暑無多日，幽居近小江。',24,'全唐诗/poet.song.131000.json','["殘暑無多日，幽居近小江。", "酒醒中夜起，松月入山窗。"]'),
('b98f8cdb-b954-451f-a388-2b7e8d907b16','新秋以窗裏人將老門前樹欲秋爲韵作小詩十首  其二','陸游','宋','宋诗','song-poetry','','[]','陸子江海人，所願守節死。',24,'全唐诗/poet.song.131000.json','["陸子江海人，所願守節死。", "潮生釣瀨邊，月落菱歌裏。"]'),
('17690cf6-8a9e-4ab4-94e8-d91fe9edb1fd','新秋以窗裏人將老門前樹欲秋爲韵作小詩十首  其三','陸游','宋','宋诗','song-poetry','','[]','小智每自私，大患緣有身。',24,'全唐诗/poet.song.131000.json','["小智每自私，大患緣有身。", "孰能忘彼己，吾將友斯人。"]'),
('10d9eb3f-6a4c-444e-8eab-68e45e793459','新秋以窗裏人將老門前樹欲秋爲韵作小詩十首  其四','陸游','宋','宋诗','song-poetry','','[]','野艇千錢買，明當泛渺茫。',24,'全唐诗/poet.song.131000.json','["野艇千錢買，明當泛渺茫。", "但能容一榼，家具不須將。"]'),
('b05e69cd-493d-48ec-a9a8-fd416cc989fa','新秋以窗裏人將老門前樹欲秋爲韵作小詩十首  其五','陸游','宋','宋诗','song-poetry','','[]','立朝紹興間，猶及見諸老。',24,'全唐诗/poet.song.131000.json','["立朝紹興間，猶及見諸老。", "魂夢不可逢，丘墳閉秋草。"]'),
('6b2ac787-41cb-417d-8b72-717851e14161','新秋以窗裏人將老門前樹欲秋爲韵作小詩十首  其六','陸游','宋','宋诗','song-poetry','','[]','朝真方捨杖，步月始開門。',24,'全唐诗/poet.song.131000.json','["朝真方捨杖，步月始開門。", "零落山花後，經旬掩綠樽。"]'),
('8f385536-175c-4aa9-9408-9dfcc9f6be0b','新秋以窗裏人將老門前樹欲秋爲韵作小詩十首  其七','陸游','宋','宋诗','song-poetry','','[]','唐虞雖已遠，至道豈無傳。',24,'全唐诗/poet.song.131000.json','["唐虞雖已遠，至道豈無傳。", "度日一編裏，懷人千載前。"]'),
('618bd413-b820-4efa-9945-110ef3ea3bf5','新秋以窗裏人將老門前樹欲秋爲韵作小詩十首  其八','陸游','宋','宋诗','song-poetry','','[]','秋風昨夜來，聲滿梧桐樹。',24,'全唐诗/poet.song.131000.json','["秋風昨夜來，聲滿梧桐樹。", "故人渺天末，此夕誰與度。"]'),
('b80edc1c-52eb-44af-85ae-b0007970be3c','新秋以窗裏人將老門前樹欲秋爲韵作小詩十首  其九','陸游','宋','宋诗','song-poetry','','[]','少年雖婚宦，淡然本無欲。',24,'全唐诗/poet.song.131000.json','["少年雖婚宦，淡然本無欲。", "婆娑三畝園，自嘆不啻足。"]'),
('d2eb5945-17cd-4020-9b42-e60815a63871','新秋以窗裏人將老門前樹欲秋爲韵作小詩十首  其一○','陸游','宋','宋诗','song-poetry','','[]','無食妨何事，吾兒可散愁。',24,'全唐诗/poet.song.131000.json','["無食妨何事，吾兒可散愁。", "焚香正巾褐，聽汝讀春秋。"]'),
('27e4e45e-7e34-4ab3-8f89-d3edc9958eb3','食新有感貧居久蔬食至是方稍得肉','陸游','宋','宋诗','song-poetry','','[]','壯遊車轍遍天涯，晚得祠官不去家。',64,'全唐诗/poet.song.131000.json','["壯遊車轍遍天涯，晚得祠官不去家。", "優老每慚千載遇，食新又嘆一年加。", "出波魚美如通印，下棧羊肥抵卧沙。", "捫腹笑歌仍索酒，不嫌鄰舍怪讙譁。"]'),
('5ab7bd36-65f9-4678-80d1-1b3dfef4067c','秋夕露坐作','陸游','宋','宋诗','song-poetry','','[]','銀河半落露華清，南斗闌干北斗明。',64,'全唐诗/poet.song.131000.json','["銀河半落露華清，南斗闌干北斗明。", "冉冉方悲老將至，纖纖又嘆月初生。", "酒床細滴香浮甕，衣杵相聞聲滿城。", "萬卷讀書無用處，却將耕稼報昇平。"]'),
('93df21ff-1c55-4482-848d-212c96682b2d','有年','陸游','宋','宋诗','song-poetry','','[]','不向神林乞雨晴，天公自解相西成。',64,'全唐诗/poet.song.131000.json','["不向神林乞雨晴，天公自解相西成。", "急符收盡無逋賦，新酒沽多足笑聲。", "外戶徹扃停夕柝，齊民相勸力春耕。", "傳聞夜市連三鼓，却恨龐公不入城。"]'),
('e97adb17-24ed-40a6-8134-c94cddf79847','大雨','陸游','宋','宋诗','song-poetry','','[]','北風挾驕雲，突起塞宇宙。',120,'全唐诗/poet.song.131000.json','["北風挾驕雲，突起塞宇宙。", "赫日初未西，盼轉失白晝。", "翻空黑幟合，列陣奇鬼鬭。", "雨鏃飛縱橫，雷車助奔驟。", "平階水入戶，溝瀆不能受。", "對面語不聞，持繖避屋漏。", "兒童抱圖書，衣屨那暇救。", "縱暴理豈長，忽已收簷霤。", "比鄰更相勞，捃拾如過寇。", "老子獨癡頑，長歌對醇酎。"]'),
('7c544b67-7da9-4259-8099-a54590d388e5','東西家','陸游','宋','宋诗','song-poetry','','[]','東家雲出岫，西家籠半山。',72,'全唐诗/poet.song.131000.json','["東家雲出岫，西家籠半山。", "西家泉落澗，東家鳴佩環。", "相對籬數掩，各有茆三間。", "芹羹與麥飯，日不廢往還。", "兒女若一家，雞犬意自閑。", "我亦思卜鄰，餘地君勿慳。"]'),
('90c7803d-61f9-40ef-b0f0-3e08ebe850c2','予自春夏屢病至立秋而愈作長句自賀','陸游','宋','宋诗','song-poetry','','[]','良藥扶衰抵萬金，漸加糜粥輟呻吟。',64,'全唐诗/poet.song.131000.json','["良藥扶衰抵萬金，漸加糜粥輟呻吟。", "溪風拂簟有秋意，山影半庭生夕陰。", "薄俗只成驚老眼，幽居正得遂初心。", "岸巾待月欄干曲，更覺天公愛我深。"]'),
('57d3e7a2-3a51-478e-a8ca-d24e1078bba4','七月十一日雨後夜坐戶外觀月','陸游','宋','宋诗','song-poetry','','[]','浴罷淡無事，岸幘臨前軒。',120,'全唐诗/poet.song.131000.json','["浴罷淡無事，岸幘臨前軒。", "雷雨始退散，雲月相吐吞。", "風蟬斷還續，枝間終夕喧。", "露螢闔復開，熠熠綴草根。", "殘暑會當去，孰敢厭炮燔。", "四時莽相代，所嘆歲月奔。", "歡悰挽不留，白髮生無根。", "兒女日夜長，子且復有孫。", "澗松偶未薪，野鶴猶孤鶱。", "華表幸來歸，餘事何足言。"]'),
('4bb8ac47-b41c-44f4-84a8-cc9644a5cbc7','王與道尚書挽詞二首  其一','陸游','宋','宋诗','song-poetry','','[]','朗朗百間屋，汪汪千頃陂。',48,'全唐诗/poet.song.131000.json','["朗朗百間屋，汪汪千頃陂。", "直能彰主聖，清不願人知。", "許國多艱日，逢辰獨斷時。", "人猶望霖雨，殄瘁不勝悲。"]'),
('acdd2759-cd52-47e0-b44d-22304b8adfe1','王與道尚書挽詞二首  其二','陸游','宋','宋诗','song-poetry','','[]','昔遇開藩日，嘗叨下榻榮。',48,'全唐诗/poet.song.131000.json','["昔遇開藩日，嘗叨下榻榮。", "從容陪讌笑，傾倒及平生。", "借譽言猶在，懷知涕易橫。", "終慚五字句，不盡百年情。"]'),
('3929a638-0e60-4a17-ad3b-14086a220fe3','初秋','陸游','宋','宋诗','song-poetry','','[]','雨氣排殘暑，風聲送早秋。',48,'全唐诗/poet.song.131000.json','["雨氣排殘暑，風聲送早秋。", "拂窗聞葉落，繞井看螢流。", "卧起須人助，炊舂尚自謀。", "蕭條歲將晚，百慮入搔頭。"]'),
('63260db0-cd07-4f8f-b8bf-afdc39d90f1f','感秋','陸游','宋','宋诗','song-poetry','','[]','秋色關河外，秋聲天地間。',96,'全唐诗/poet.song.131000.json','["秋色關河外，秋聲天地間。", "壯士感此時，朝鏡凋朱顔。", "一身寄空谷，萬里夢天山。", "噫嗚怒眥裂，憤激悲涕潸。", "古來真龍駒，未必置天閑。", "長松倒澗壑，委棄同蓁菅。", "得志未可測，談笑濟時艱。", "凜然出師表，一字不可刪。"]'),
('8c413d2a-6ab2-4d2b-9eaf-93c3b48a545c','北窗試筆','陸游','宋','宋诗','song-poetry','','[]','老來日月速，去若弦上箭。',96,'全唐诗/poet.song.131000.json','["老來日月速，去若弦上箭。", "方看出土牛，已復送巢燕。", "清晨覓縑衣，正午廢紈扇。", "北窗小雨餘，盆山鬰葱蒨。", "病體爲之輕，一笑玩筆硯。", "雖無顔柳工，揮灑亦忘倦。", "紙窮墨漸燥，蛇蚖爭入卷。", "屬兒善藏之，勿遣俗子見。"]'),
('4c8063cc-5f43-4bd6-ae56-7912aaa31d72','秋思四首  其一','陸游','宋','宋诗','song-poetry','','[]','秋毫不受俗塵侵，隨處悠然一散襟。',64,'全唐诗/poet.song.131000.json','["秋毫不受俗塵侵，隨處悠然一散襟。", "天際挂虹初斷雨，雲頭翳日又成陰。", "引泉北澗長澆竹，拂榻西窗自霑琴。", "藥石掃空身便健，始知萬事要無心。"]'),
('1ce84145-50bc-498e-a143-579911e4921c','秋思四首  其二','陸游','宋','宋诗','song-poetry','','[]','雨長蒼苔滿釣磯，坐令秋暑斂餘威。',64,'全唐诗/poet.song.131000.json','["雨長蒼苔滿釣磯，坐令秋暑斂餘威。", "天高月破殘雲出，野曠風驚蠹葉飛。", "終歲鉏犁猶不飽，萬家碪杵獨無衣。", "早知竟坐儒冠誤，射虎南山未必非。"]'),
('da87f941-1bd6-4775-829c-979cae3c520b','秋思四首  其三','陸游','宋','宋诗','song-poetry','','[]','身似龐翁不出家，一窗自了淡生涯。',64,'全唐诗/poet.song.131000.json','["身似龐翁不出家，一窗自了淡生涯。", "山薑零落初成子，石竹凄凉半吐花。", "寒澗挹泉供試墨，墮巢篝火喚煎茶。", "掩關本意君知否，兩耳衰年不耐譁。"]'),
('b33e84e8-5e72-4914-89b7-f173369753e1','秋思四首  其四','陸游','宋','宋诗','song-poetry','','[]','老懷不慣著閑愁，信脚時爲野外遊。',64,'全唐诗/poet.song.131000.json','["老懷不慣著閑愁，信脚時爲野外遊。", "過雁未驚殘月曉，片雲先借一天秋。", "村醅似粥家家醉，社肉如林處處留。", "七十已稀今又過，問君端的更何求。"]'),
('fe1201e8-9877-4b07-83bd-f0b336dfee87','新凉二首  其一','陸游','宋','宋诗','song-poetry','','[]','山居謝來客，病體喜新凉。',48,'全唐诗/poet.song.131000.json','["山居謝來客，病體喜新凉。", "幽草上牆綠，落花霑土香。", "捐書心自息，聽雨夢偏長。", "菰葉鄰人餉，欣然獨舉觴。"]'),
('08d11d61-3062-43aa-a4b0-7bca02fe8f6e','新凉二首  其二','陸游','宋','宋诗','song-poetry','','[]','菰首初離水，薑芽淺漬糟。',48,'全唐诗/poet.song.131000.json','["菰首初離水，薑芽淺漬糟。", "粳香等炊玉，韭美勝炮羔。", "露下殘蕪溼，風生萬木號。", "從今更何事，痛飲讀離騷。"]'),
('06e5b9c1-a563-4538-857f-eccacf1362ae','自遣','陸游','宋','宋诗','song-poetry','','[]','踽踽人間未死身，鄉閭共敬六朝民。',64,'全唐诗/poet.song.131000.json','["踽踽人間未死身，鄉閭共敬六朝民。", "睡無由著緣多感，醉不能成坐一貧。", "幽屏最憎蟲吊夜，狂吟略似鳥鳴春。", "也知世俗誰知我，猶待君王獵渭濱。"]'),
('8d139835-6c56-4dd2-91bf-b02e9e5510da','自規','陸游','宋','宋诗','song-poetry','','[]','曲肱飲水彼何人，汝獨何爲厭賤貧。',64,'全唐诗/poet.song.131000.json','["曲肱飲水彼何人，汝獨何爲厭賤貧。", "大節勿汙千載史，少時便盡百年身。", "圖書幸可傳遺業，雞黍何妨約近鄰。", "今日仲秋還小雨，剩鉏麥壟待新春。"]'),
('cfd39ff4-494a-4d33-ac20-cdfb9fed3312','感舊四首末章蓋思有以自廣  其一','陸游','宋','宋诗','song-poetry','','[]','庚寅歲入巴東峽，卧聽清猿月下聲。',32,'全唐诗/poet.song.131000.json','["庚寅歲入巴東峽，卧聽清猿月下聲。", "二十九年窮未死，却思當日似前生。"]'),
('704e42e1-ea72-42ba-8c78-59113871711a','感舊四首末章蓋思有以自廣  其二','陸游','宋','宋诗','song-poetry','','[]','百堂小益最初程，朱棧青崖照眼明。',32,'全唐诗/poet.song.131000.json','["百堂小益最初程，朱棧青崖照眼明。", "十日經行圖障裏，時時馬上聽鶯聲。"]'),
('2c619be8-3ffa-4862-8c57-62e96401f2c9','感舊四首末章蓋思有以自廣  其三','陸游','宋','宋诗','song-poetry','','[]','路入梁州似掌平，鞦韆蹴鞠趁清明。',32,'全唐诗/poet.song.131000.json','["路入梁州似掌平，鞦韆蹴鞠趁清明。", "未論日遠長安近，且喜南山天際橫。"]'),
('7287a7de-4733-44bf-859c-d15e1e19a81d','感舊四首末章蓋思有以自廣  其四','陸游','宋','宋诗','song-poetry','','[]','青城山裏屏風疊，太華峰頭腰带鞓。',32,'全唐诗/poet.song.131000.json','["青城山裏屏風疊，太華峰頭腰带鞓。", "跨鶴橫空吾欲去，九秋月露看青冥。"]'),
('d5b3be02-1135-4288-8959-f5c0735aed52','秋日獨酌','陸游','宋','宋诗','song-poetry','','[]','草木秋始繁，黄碧照籬落。',72,'全唐诗/poet.song.131000.json','["草木秋始繁，黄碧照籬落。", "雖云各有時，意緒終索莫。", "老人固多感，對此聊命酌。", "風霜肅萬物，過雁在寥廓。", "吾當識其大，微物不足託。", "何以豁曠懷，短章可時作。"]'),
('ef38d8a8-a761-46c8-a2e4-55193779827d','夙興','陸游','宋','宋诗','song-poetry','','[]','草堂風雨少睡眠，骨冷始覺非壯年。',96,'全唐诗/poet.song.131000.json','["草堂風雨少睡眠，骨冷始覺非壯年。", "水鳥長鳴聲戛然，庭中棲鴉亦已翩。", "老人清餓如龜蟬，起坐甚愛小窗妍。", "一生宦遊膏火煎，歸來杜門氣粗全。", "人看雖不直一錢，知我自有穹穹天。", "賦詩稿成棄不傳，殘鐘斷磬知誰編。"]'),
('f44b1e52-164c-4778-8c07-295d77d4ad9a','身世','陸游','宋','宋诗','song-poetry','','[]','身世浮沉等一漚，卧看校尉例封侯。',64,'全唐诗/poet.song.131000.json','["身世浮沉等一漚，卧看校尉例封侯。", "青燈微火藥鐺夜，淡月凄風衣杵秋。", "醉裏不辭嘲兀兀，吟邊時得寄悠悠。", "即今老眼無開處，又向城南倚寺樓。"]'),
('37c2e620-f7fa-44ba-baff-6d5ecb8f48bc','憶昔','陸游','宋','宋诗','song-poetry','','[]','憶自梁州下益州，身閑處處醉紅樓。',64,'全唐诗/poet.song.131000.json','["憶自梁州下益州，身閑處處醉紅樓。", "早知虛起彈冠意，悔不常爲秉燭遊。", "詩思已慚馳陣馬，目光猶覺射車牛。", "蓮峰日觀何時到，下看人間萬里秋。"]'),
('dac8f698-4e6e-48e8-887e-182380342df3','豐歲','陸游','宋','宋诗','song-poetry','','[]','豐歲歡聲動四鄰，深秋景氣粲如春。',64,'全唐诗/poet.song.131000.json','["豐歲歡聲動四鄰，深秋景氣粲如春。", "羊腔酒擔爭迎婦，鼉鼓龍船共賽神。", "處處喜晴過甲子，家家筑屋趁庚申。", "老翁欲伴鄉閭醉，先辦長衫紫領巾。"]'),
('eeb4ecd3-448a-4e37-9efa-9dbb0345e6f0','村居','陸游','宋','宋诗','song-poetry','','[]','孤村淺浦近江城，西折坡陁一嶺橫。',64,'全唐诗/poet.song.131000.json','["孤村淺浦近江城，西折坡陁一嶺橫。", "墟落烟生含暮色，園林風勁作秋聲。", "年豐租稅無逋負，酒熟鄉鄰遞送迎。", "老病愈知難報國，只將高枕送餘生。"]'),
('c5248d3b-d116-4553-8028-2c16b9fd60c4','中秋夜半後無雲而月色微淡尤爲絕景','陸游','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','輕烟薄靄九霄寒，素月渾如隔縠看。',32,'全唐诗/poet.song.131000.json','["輕烟薄靄九霄寒，素月渾如隔縠看。", "此夕洞庭應更好，誰能從我跨青鸞。"]'),
('fc3b5042-2406-4c9e-b6f4-33c76ab88519','夜賦','陸游','宋','宋诗','song-poetry','','[]','老人不食覺魂清，怳若身遊白玉京。',64,'全唐诗/poet.song.131000.json','["老人不食覺魂清，怳若身遊白玉京。", "夜靜月驚林鵲起，水凉風颭露荷傾。", "昏燈一點窺孤夢，畫角三終轉五更。", "欲醉海山還懶去，且携羽扇憩青城。"]'),
('e9f50c67-a4e2-4284-904a-77786a6b5ffe','遣興','陸游','宋','宋诗','song-poetry','','[]','學廢文章傳世少，身閑車馬過門疏。',64,'全唐诗/poet.song.131000.json','["學廢文章傳世少，身閑車馬過門疏。", "壯心易盡彘肩酒，義氣肯貪熊掌魚。", "列聖仁恩深雨露，兩京宮闕尚丘墟。", "素懷華渭嗟誰問，且作狂歌楚接輿。"]'),
('96afd4a1-8edb-461d-8ccf-5d2318a67dca','秋賽','陸游','宋','宋诗','song-poetry','','[]','柳姑廟前烟出浦，冉冉縈空青一縷。',136,'全唐诗/poet.song.131000.json','["柳姑廟前烟出浦，冉冉縈空青一縷。", "須臾散作四山雲，明日來爲社公雨。", "小巫屢舞大巫歌，士女拜祝肩相摩。", "芳茶綠酒進雜遝，長魚大胾高嵯峨。", "常年徵科煩箠楚，縣家血溼庭前土。", "妻啼兒號不敢怨，期會常憂累官府。", "今年家家有餘粟，縣符未下輸先足。", "木刻吏，蒲作鞭。", "自然粟帛如流泉，儲積不愁無九年。"]'),
('7e59932b-070c-4c56-98e2-8cf379bbea94','寄題周丞相平園','陸游','宋','宋诗','song-poetry','','[]','先生道心平如砥，秋毫忿慾何曾起。',128,'全唐诗/poet.song.131000.json','["先生道心平如砥，秋毫忿慾何曾起。", "漫將周易著床頭，本不洗心那洗耳。", "先生國論如砥平，三朝倚之作權衡。", "泰階兩兩元不動，自然萬里無欃槍。", "如今歸來曲肱卧，世事無窮俱看破。", "不栽桃李不鉏蘭，山僧野叟時來過。", "吾儕七十固已壽，更到期頤亦何有。", "倘知生死本自平，拈放一邊如把酒。"]'),
('8d0ab1f9-b9f5-406c-b1b4-df0131b4948b','雨三日歌','陸游','宋','宋诗','song-poetry','','[]','秋風戒寒雨三日，空村無人暮蕭瑟。',96,'全唐诗/poet.song.131000.json','["秋風戒寒雨三日，空村無人暮蕭瑟。", "北窗書生萬卷書，齒豁頭童真可惜。", "輪囷新蟹黄欲滿，磊落香橙綠堪摘。", "興來尚能氣吞酒，詩成不覺泪漬筆。", "士生蓬矢射四方，掃平河雒吾儕職。", "湖中隱士倘可逢，握手與君談至夕。"]'),
('9ffd0be9-e4bb-4e2a-bf42-d6d941547e58','戲作治生絕句','陸游','宋','宋诗','song-poetry','','[]','治生何用學陶朱，少許能慳便有餘。',32,'全唐诗/poet.song.131000.json','["治生何用學陶朱，少許能慳便有餘。", "惜酒已停晨服藥，省油仍廢夜觀書。"]'),
('8c6ad404-11be-4ce8-b71d-22afd301c8bf','龜堂雜題四首  其一','陸游','宋','宋诗','song-poetry','','[]','龜堂端是無能者，妄想元無一事成。',32,'全唐诗/poet.song.131000.json','["龜堂端是無能者，妄想元無一事成。", "最後數年尤可笑，飽餐甘寢送浮生。"]'),
('63f122fa-afff-43d3-9d55-9c34430d7d6c','龜堂雜題四首  其二','陸游','宋','宋诗','song-poetry','','[]','癡頑老子老無能，遊惰農夫酒肉僧。',32,'全唐诗/poet.song.131000.json','["癡頑老子老無能，遊惰農夫酒肉僧。", "閉著庵門終日睡，任人來喚不曾譍。"]'),
('6323cc25-51f8-45f0-a8be-cb965880850f','龜堂雜題四首  其三','陸游','宋','宋诗','song-poetry','','[]','長腰玉粒出新舂，秋穫真成畝一鍾。',32,'全唐诗/poet.song.131000.json','["長腰玉粒出新舂，秋穫真成畝一鍾。", "衣食粗供官賦足，何妨世世作耕農。"]'),
('58e3814d-c407-41b9-8d39-3d2a42d39bac','龜堂雜題四首  其四','陸游','宋','宋诗','song-poetry','','[]','冷雨蕭蕭澀不晴，亂書圍坐正縱橫。',32,'全唐诗/poet.song.131000.json','["冷雨蕭蕭澀不晴，亂書圍坐正縱橫。", "忽聞小甕新醅熟，急喚兒童洗破觥。"]'),
('5f0818ea-ee86-442e-be52-fdfbc1425e24','偶讀陳無己芍藥詩云一枝剩欲簪雙髻未有人間第一人蓋晚年所作也爲之絕倒戲作小詩','陸游','宋','宋诗','song-poetry','','[]','少年妄想已癡絕，鏡裏何堪白髮生。',32,'全唐诗/poet.song.131000.json','["少年妄想已癡絕，鏡裏何堪白髮生。", "縱有傾城何預汝，可憐元未解人情。"]'),
('8d528298-2b39-468b-8d0e-de677dadade0','村舍','陸游','宋','宋诗','song-poetry','','[]','過埭六七里，並江三四家。',36,'全唐诗/poet.song.131000.json','["過埭六七里，並江三四家。", "潮生魚滬短，風起鴨船斜。", "世守桑麻業，長無市井譁。"]'),
('4277572e-2e9e-45cb-ad4c-184955301e7a','雨中作','陸游','宋','宋诗','song-poetry','','[]','雨聲可愛秋方見，睡味無窮老始知。',32,'全唐诗/poet.song.131000.json','["雨聲可愛秋方見，睡味無窮老始知。", "半醉擁衾支倦枕，誰能三復放翁詩。"]'),
('d946c757-06ed-458d-9a37-a0e507032f06','江郊','陸游','宋','宋诗','song-poetry','','[]','白草江郊暮，青帘野店秋。',48,'全唐诗/poet.song.131000.json','["白草江郊暮，青帘野店秋。", "喧呼估船客，嵬峨飲家流。", "老豈題橋柱，愁惟倚寺樓。", "更傷昏澀眼，烟際數歸牛。"]'),
('0509041d-e88a-4ccf-97f2-9349c49b41bc','閑趣三首  其一','陸游','宋','宋诗','song-poetry','','[]','被擁聽秋雨，兒扶上夜香。',48,'全唐诗/poet.song.131000.json','["被擁聽秋雨，兒扶上夜香。", "甑炊霜後稻，糟漬社前薑。", "馬病空思路，僧歸却住房。", "風扉久嘔軋，錯認櫓聲長。"]'),
('398d31f6-2a59-4504-a3b2-c2a8555fcc4f','閑趣三首  其二','陸游','宋','宋诗','song-poetry','','[]','飯滿七綴鉢，香凝百衲窗。',48,'全唐诗/poet.song.131000.json','["飯滿七綴鉢，香凝百衲窗。", "雨聲酣曉枕，燈燼落秋釭。", "疾豎元知遯，天魔亦已降。", "超然對兒子，未愧鹿門龐。"]'),
('2773b5ff-3af9-4992-b0d6-b1a787b2d6c0','閑趣三首  其三','陸游','宋','宋诗','song-poetry','','[]','老至衰滋劇，秋高病尚侵。',48,'全唐诗/poet.song.131000.json','["老至衰滋劇，秋高病尚侵。", "坐看兒學字，卧聽客彈琴。", "囷滿雀方鬭，栖寒雞欲瘖。", "世情元自懶，不是事違心。"]'),
('6207a0ac-1aa4-4814-86b2-2c4fd5f06a1a','小飲','陸游','宋','宋诗','song-poetry','','[]','莫笑放翁顛，歌呼覆酒船。',48,'全唐诗/poet.song.131000.json','["莫笑放翁顛，歌呼覆酒船。", "雙螯初斫雪，珍鮝已披綿。", "寒雨連旬日，新橙又一年。", "更須重九到，作意菊花前。"]'),
('d9e2aed4-c87c-4d9f-bcb5-a6622c8b55d9','作字','陸游','宋','宋诗','song-poetry','','[]','整整復斜斜，翩如風際鴉。',48,'全唐诗/poet.song.131000.json','["整整復斜斜，翩如風際鴉。", "書成半行草，眼倦正昏花。", "未辦倉盛筆，寧能錐畫沙。", "老夫端可愧，頭白不名家。"]'),
('f743c2bc-3e3d-4333-80ae-69d4d24e0ad2','晝睡起偶賦','陸游','宋','宋诗','song-poetry','','[]','蝴蝶與蒙莊，頹然寓一床。',48,'全唐诗/poet.song.131000.json','["蝴蝶與蒙莊，頹然寓一床。", "日隨香篆過，夢逐雨聲長。", "酒喜新篘綠，橙如故歲黄。", "昏昏還隱几，誰識老龜堂。"]'),
('97057112-96f2-4317-b661-92636692d1ee','小舟過吉澤效王右丞','陸游','宋','宋诗','song-poetry','','[]','澤園霜露晚，孤村烟火微。',48,'全唐诗/poet.song.131000.json','["澤園霜露晚，孤村烟火微。", "本去官道遠，自然人迹稀。", "木落山盡出，鐘鳴僧獨歸。", "漁家閑似我，未夕閉柴扉。"]'),
('ff7a34bf-205f-4e2b-93f1-4bf67f7d8d7b','湖山雜賦五首  其一','陸游','宋','宋诗','song-poetry','','[]','門前天鏡倒千峰，舍後菰蒲與海通。',32,'全唐诗/poet.song.131000.json','["門前天鏡倒千峰，舍後菰蒲與海通。", "乘興出遊無遠近，烟波何處覓孤篷。"]'),
('c2ac23d4-4733-4f72-8844-c6c9e814efd9','湖山雜賦五首  其二','陸游','宋','宋诗','song-poetry','','[]','一生到處賈胡留，身屬官倉不自由。',32,'全唐诗/poet.song.131000.json','["一生到處賈胡留，身屬官倉不自由。", "白首歸來更何恨，十年爛醉石帆秋。"]'),
('375c44a3-b04e-446e-ade2-6285e5aad089','湖山雜賦五首  其三','陸游','宋','宋诗','song-poetry','','[]','東西相望兩湖橋，來往無時一畫橈。',32,'全唐诗/poet.song.131000.json','["東西相望兩湖橋，來往無時一畫橈。", "買酒每尋村市步，煮蔬時就野僧寮。"]'),
('4543d165-316c-450d-8e71-56bec554223d','湖山雜賦五首  其四','陸游','宋','宋诗','song-poetry','','[]','不到梅山二十霜，望中常似隔他鄉。',32,'全唐诗/poet.song.131000.json','["不到梅山二十霜，望中常似隔他鄉。", "一杯罌粟紗燈下，最憶初寒宿上方。"]'),
('3301c4a0-d1d8-4b8f-8504-42b1233b7f72','湖山雜賦五首  其五','陸游','宋','宋诗','song-poetry','','[]','烟中一棹小江秋，憶上牛頭倚寺樓。',32,'全唐诗/poet.song.131000.json','["烟中一棹小江秋，憶上牛頭倚寺樓。", "今日籬邊殘照裏，却從西北望牛頭。"]'),
('cc747c5c-de6c-460e-b74e-e1383ad08dff','太息四首  其一','陸游','宋','宋诗','song-poetry','','[]','早歲元于利欲輕，但餘一念在功名。',32,'全唐诗/poet.song.131000.json','["早歲元于利欲輕，但餘一念在功名。", "白頭不試平戎策，虛向江湖過此生。"]'),
('eaf07e9b-7cb3-4e4a-8e10-7adaa1515d56','太息四首  其二','陸游','宋','宋诗','song-poetry','','[]','書生忠義與誰論，骨朽猶應此念存。',32,'全唐诗/poet.song.131000.json','["書生忠義與誰論，骨朽猶應此念存。", "砥柱河流僊掌日，死前恨不見中原。"]'),
('c49e8fa7-8a93-4ade-bf3e-ba8fc2879b81','太息四首  其三','陸游','宋','宋诗','song-poetry','','[]','自古才高每恨浮，偉人要是出中州。',32,'全唐诗/poet.song.131000.json','["自古才高每恨浮，偉人要是出中州。", "即今未必無房魏，埋沒胡沙死即休。"]'),
('87995f19-e6c4-47a3-a88f-5c92a7c7fda5','太息四首  其四','陸游','宋','宋诗','song-poetry','','[]','關輔堂堂墮虜塵，渭城杜曲又逢春。',32,'全唐诗/poet.song.131000.json','["關輔堂堂墮虜塵，渭城杜曲又逢春。", "安知今日新豐市，不有悠然獨酌人。"]'),
('d4dbd891-7009-4885-af1c-24a8f91209b7','學書','陸游','宋','宋诗','song-poetry','','[]','九月十九柿葉紅，閉門讀書人笑翁。',64,'全唐诗/poet.song.131000.json','["九月十九柿葉紅，閉門讀書人笑翁。", "世間誰許一錢直，窗底自用十年功。", "老蔓纏松飽霜雪，瘦蛟出海拏虛空。", "即今譏評何足道，後五百年言自公。"]'),
('5ea25b2f-29c0-4e48-a60e-b7bcb4989c09','晚興','陸游','宋','宋诗','song-poetry','','[]','壯遊車轍遍天涯，晚落農桑不自知。',64,'全唐诗/poet.song.131000.json','["壯遊車轍遍天涯，晚落農桑不自知。", "許國雖堅身遽老，讀書未倦眼先衰。", "雲深嶺路樵歸晚，雨細江亭渡發遲。", "一事猶堪慰孤寂，錦囊傾倒有新詩。"]'),
('cb763f61-d97c-4a40-be1e-b65da3ef823f','秋晴見天際飛鴻有感','陸游','宋','宋诗','song-poetry','','[]','新晴天宇色正青，群鴻高鶱在冥冥。',128,'全唐诗/poet.song.131000.json','["新晴天宇色正青，群鴻高鶱在冥冥。", "兒童相呼共仰視，我亦扶杖來中庭。", "豐年到處稻粱滿，胡不暫下栖沙汀。", "應須江海寄曠快，肯爲霜雪嗟飄零。", "書生可笑不自喜，憔悴久翦籠中翎。", "鷗波萬里每愧杜，鶴化千載知非丁。", "風前哀號漫激烈，月下孤影常竛竮。", "詩成欲寫復懶去，誦似溪友聲泠泠。"]'),
('436b5399-74da-4d3d-9a8e-c358c55572dd','初寒獨居戲作','陸游','宋','宋诗','song-poetry','','[]','開殼得紫栗，带葉摘黄甘。',48,'全唐诗/poet.song.131000.json','["開殼得紫栗，带葉摘黄甘。", "獨卧維摩室，誰同彌勒龕。", "宗文樹雞柵，靈照挈蔬籃。", "一段無生話，燈籠可與談。"]'),
('c8ae374d-f77a-4dac-bf67-08977dbce495','夢觀牡丹','陸游','宋','宋诗','song-poetry','','[]','忘却晨梳滿把絲，楝花嫌不似胭脂。',32,'全唐诗/poet.song.131000.json','["忘却晨梳滿把絲，楝花嫌不似胭脂。", "起來一笑看清鏡，惟插梨花却較宜。"]'),
('957cd5eb-0cb3-408a-b9e6-4b8108e90d6f','書喜三首  其一','陸游','宋','宋诗','song-poetry','','[]','水際柴荆鍵不開，野人相覓漫敲推。',64,'全唐诗/poet.song.131000.json','["水際柴荆鍵不開，野人相覓漫敲推。", "寒鴉陣黑疑雲過，老木聲酣認雨來。", "酒價日低常得醉，官租時辦不勞催。", "平生未省如今樂，却笑傍觀誤見哀。"]'),
('e81c5969-7555-4217-ae31-962971b7aa14','書喜三首  其二','陸游','宋','宋诗','song-poetry','','[]','今年端的是豐穰，十里家家喜欲狂。',64,'全唐诗/poet.song.131000.json','["今年端的是豐穰，十里家家喜欲狂。", "俗美農夫知讓畔，化行蠶婦不爭桑。", "酒坊飲客朝成市，佛廟村伶夜作場。", "身是閑人新病愈，剩移霜菊待重陽。"]'),
('0b0b8da2-b44b-471f-8c0a-7cc7838b44b8','書喜三首  其三','陸游','宋','宋诗','song-poetry','','[]','滿川秋穫重赬肩，拾穗兒童擁道邊。',64,'全唐诗/poet.song.131000.json','["滿川秋穫重赬肩，拾穗兒童擁道邊。", "夜夜江村無吠犬，家家市步有新船。", "奪攘不復憂山越，安樂渾疑是地仙。", "惟有衰翁最知達，避胡猶記建炎年。"]'),
('7190a2e7-7e20-446b-a554-ba76ccf1dfdb','小飲罷行至湖塘而歸','陸游','宋','宋诗','song-poetry','','[]','社酒真如粥面濃，朱顔頃刻換衰容。',64,'全唐诗/poet.song.131000.json','["社酒真如粥面濃，朱顔頃刻換衰容。", "霜輕已覺樹摇落，雲起始知山疊重。", "梅市魚歸衝雨棹，寶林人定隔城鐘。", "此翁大似遊僧樣，爐暖窗深又過冬。"]'),
('7655984e-2ecd-4526-bc93-37faac195073','病雁','陸游','宋','宋诗','song-poetry','','[]','蘆洲有病雁，雪霜摧羽翰。',96,'全唐诗/poet.song.131000.json','["蘆洲有病雁，雪霜摧羽翰。", "不辭道路遠，置身湖海寬。", "稻粱亦滿目，鳴聲自辛酸。", "我正與此同，百憂雙鬢殘。", "東歸忽十載，四忝侍祠官。", "雖云幸得飽，早夜不敢安。", "乃知學者心，羞愧甚饑寒。", "讀我病雁篇，萬鍾均一簞。"]'),
('290e4e58-bfcf-406e-9bce-42d434388270','澤居','陸游','宋','宋诗','song-poetry','','[]','澤居僅足不求餘，曠快真同縱壑魚。',64,'全唐诗/poet.song.131000.json','["澤居僅足不求餘，曠快真同縱壑魚。", "平日酷憎蠅附驥，暮年肯作鶴乘車。", "齒摇但煮岷山芋，眼澀惟觀胄監書。", "此際自應還往絕，本無心與俗人疏。"]'),
('f52d09f3-81f4-47c1-95ca-aca70eb09130','秋穫歌','陸游','宋','宋诗','song-poetry','','[]','牆頭累累柿子黄，人家秋穫爭登場。',149,'全唐诗/poet.song.131000.json','["牆頭累累柿子黄，人家秋穫爭登場。", "長碓擣珠照地光，大甑炊玉連村香。", "萬人牆進輸官倉，倉吏{炙火=肉}冷不暇嘗。", "訖事散去喜若狂，醉卧相枕官道傍。", "數年斯民阨兇荒，轉徙溝壑殣相望。", "縣吏亭長如餓狼，婦女怖死兒童僵。", "豈知皇天賜豐穰，畝收一鍾富萬箱。", "我願鄰曲謹蓋藏，縮衣節食勤耕桑。", "追思食不饜糟糠，勿使水旱憂堯湯。"]'),
('a2964428-1447-4b48-ae86-e12da9fac1ef','戊午重九','陸游','宋','宋诗','song-poetry','','[]','朋舊相望天一涯，登高結伴只鄰家。',64,'全唐诗/poet.song.131000.json','["朋舊相望天一涯，登高結伴只鄰家。", "秋風自欲吹紗帽，衰鬢何曾泥菊花。", "藥市神仙思益部，糕盤節物記京華。", "自憐病後歡悰薄，小醉歸來日未斜。"]'),
('d9760e8e-69bb-4680-9691-1836f4f16fa3','重九懷獨孤景略','陸游','宋','宋诗','song-poetry','','[]','昔逢重九日，初識獨孤君。',48,'全唐诗/poet.song.131000.json','["昔逢重九日，初識獨孤君。", "並轡洮河馬，聯詩劍閣雲。", "已悲吳蜀遠，更嘆死生分。", "安得持卮酒，澆君丈五墳。"]'),
('37ce2a61-c2b7-40cd-a9dd-57e7ac0aa67e','晨鏡','陸游','宋','宋诗','song-poetry','','[]','晨起覽清鏡，有叟鬢已皤。',96,'全唐诗/poet.song.131000.json','["晨起覽清鏡，有叟鬢已皤。", "馘黄色類梔，面皺紋如鞾。", "熟視但驚嘆，初不相誰何。", "久乃稍醒悟，舉手自摩挲。", "與汝周旋久，流年捷飛梭。", "生當老病死，求脫理則那。", "切勿彊撐拄，據鞍效廉頗。", "惟須勤把酒，暫遣衰顔酡。"]'),
('3a303f7e-0644-4ec9-af18-6134a9239aec','秋霽遣懷','陸游','宋','宋诗','song-poetry','','[]','陸生少日心膽壯，萬里憑陵寄疏放。',96,'全唐诗/poet.song.131000.json','["陸生少日心膽壯，萬里憑陵寄疏放。", "玉關曾誓馬革裹，滄海豈憂魚腹葬。", "人生富貴本細事，釣筑逢時俱將相。", "正令不遇亦何慊，藥鑱丹爐老青嶂。", "今年秋晚苦多雨，三十六溪新綠漲。", "極知世事不足論，霽日小舟行可榜。"]'),
('fc596560-e2ec-41ae-8a1b-58111d8135f8','屏迹','陸游','宋','宋诗','song-poetry','','[]','昔者航濤江，雲山迎我東。',96,'全唐诗/poet.song.131000.json','["昔者航濤江，雲山迎我東。", "擊楫誓江神，永託冥冥鴻。", "十年桑榆暖，萬事馬牛風。", "邇來愈屏迹，庭戶深蒿蓬。", "就甕挹新醅，傍畦擷晚菘。", "鄰曲或念我，小鮮亦時供。", "喟然撫几嘆，恨今已龍鍾。", "向使早十年，何愧柴桑翁。"]'),
('d65d73b3-5cbe-4489-a8a9-1711e97cfe98','初寒','陸游','宋','宋诗','song-poetry','','[]','今日霜露冷，凜然悲暮秋。',48,'全唐诗/poet.song.131000.json','["今日霜露冷，凜然悲暮秋。", "垂帷跨微火，發篋出輕裘。", "徂歲逝將換，殘生愈覺浮。", "一杯還自閔，小獵記梁州。"]'),
('4700a866-a6f1-470d-963b-cc70bbfdc2ab','風雨','陸游','宋','宋诗','song-poetry','','[]','風雨從北來，萬木皆怒號。',72,'全唐诗/poet.song.131000.json','["風雨從北來，萬木皆怒號。", "入夜殊未止，聲亂秋江濤。", "渺然老書生，白頭卧蓬蒿。", "閉門不敢出，裂面風如刀。", "鄰人閔我寒，牆頭過濁醪。", "時哉一昏醉，新橙宜蟹螯。"]'),
('1de04ad1-82e7-44d9-9a6e-7e1394d239ed','龜堂自詠二首  其一','陸游','宋','宋诗','song-poetry','','[]','龜堂一老翁，短褐立秋風。',48,'全唐诗/poet.song.131000.json','["龜堂一老翁，短褐立秋風。", "時過同籬菊，身衰似井桐。", "新霜萬瓦白，朝日數欞紅。", "且復尋書卷，悠然度歲窮。"]'),
('0e81a556-c706-4a10-981b-0960d517c814','龜堂自詠二首  其二','陸游','宋','宋诗','song-poetry','','[]','采藤持織履，剝楮治爲冠。',48,'全唐诗/poet.song.131000.json','["采藤持織履，剝楮治爲冠。", "看劍心空壯，騎驢骨本寒。", "病多辭酒伴，老甚解祠官。", "賴有扁舟在，秋濤萬里寬。"]'),
('9db25a86-f0bc-43cd-b295-026f121ba662','閑居初冬作','陸游','宋','宋诗','song-poetry','','[]','香碗蒲團又一新，天將閑處著閑身。',64,'全唐诗/poet.song.131000.json','["香碗蒲團又一新，天將閑處著閑身。", "東窗換紙明初日，南圃移花及小春。", "婦女晨炊動井臼，兒童夜誦聒比鄰。", "早知閭巷無窮樂，悔不終身一幅巾。"]'),
('0657a3ab-24f5-47b2-a0db-40b38a9d8ed5','病中排悶','陸游','宋','宋诗','song-poetry','','[]','面骨崢嶸鬢雪新，承平版籍有遺民。',64,'全唐诗/poet.song.131000.json','["面骨崢嶸鬢雪新，承平版籍有遺民。", "心雖願繼無傳學，力不能支已廢身。", "開卷眼昏如隔霧，擁爐肺渴欲生塵。", "老龐亦有兒孫念，付與天公不問人。"]'),
('d75d023c-f6b4-4e1f-b7d5-d2725be15228','季秋已寒節令頗正喜而有賦','陸游','宋','宋诗','song-poetry','','[]','霜降今年已薄霜，菊花開亦及重陽。',64,'全唐诗/poet.song.131000.json','["霜降今年已薄霜，菊花開亦及重陽。", "四時氣正無愆伏，比屋年豐有蓋藏。", "風色蕭蕭生麥隴，車聲碌碌滿魚塘。", "老夫亦與人同樂，醉倒何妨卧道傍。"]'),
('4eb5d22d-baae-4fbd-a9a5-480327517efd','秋懷','陸游','宋','宋诗','song-poetry','','[]','形骸歲歲就枯朽，意氣時時猶激昂。',64,'全唐诗/poet.song.131000.json','["形骸歲歲就枯朽，意氣時時猶激昂。", "水遠浮鷗方浩蕩，霜高殘菊更芬芳。", "人皆有舌是非在，劫未成灰時世長。", "三百里湖行自復，子孫努力事耕桑。"]'),
('fd83d8f7-cf73-48ad-a6f0-e0b240911a8f','吳體寄張季長','陸游','宋','宋诗','song-poetry','','[]','九月十月天雨霜，江南劍南途路長。',64,'全唐诗/poet.song.131000.json','["九月十月天雨霜，江南劍南途路長。", "平生故人阻携手，萬里一書空斷腸。", "人生彊健已難恃，世事變遷那可常。", "兩家子孫各長大，他年窮達毋相忘。"]'),
('f82931d7-cedf-46db-812e-3ad2c95a1ffd','嘲畜貓','陸游','宋','宋诗','song-poetry','','[]','甚矣翻盆暴，嗟君睡得成。',48,'全唐诗/poet.song.131000.json','["甚矣翻盆暴，嗟君睡得成。", "但思魚饜足，不顧鼠縱橫。", "欲騁銜蟬快，先憐上樹輕。", "朐山在何許，此族最知名。"]'),
('a41c325a-560f-4bc9-9698-1a26d82c8afc','立冬日作','陸游','宋','宋诗','song-poetry','','[]','室小財容膝，牆低僅及肩。',48,'全唐诗/poet.song.131000.json','["室小財容膝，牆低僅及肩。", "方過授衣月，又遇始裘天。", "寸積篝爐炭，銖稱布被綿。", "平生師陋巷，隨處一欣然。"]'),
('1ef3e18f-942c-423f-86e6-1293637afef7','初冬','陸游','宋','宋诗','song-poetry','','[]','志士逢秋已自傷，老人况復惜年光。',64,'全唐诗/poet.song.131000.json','["志士逢秋已自傷，老人况復惜年光。", "正看溪碓舂粳滑，又見山坡下麥忙。", "桐落井床多槁葉，菊殘衫袂尚餘香。", "讀書有課真當勉，剩貯明膏伴夜長。"]'),
('d3798278-1aa5-4ecc-8b11-57eebbfe0786','醉題','陸游','宋','宋诗','song-poetry','','[]','生來避世傲公卿，海內無人識姓名。',64,'全唐诗/poet.song.131000.json','["生來避世傲公卿，海內無人識姓名。", "九節筇邊秋萬里，長明燈下雨三更。", "心安白髮何勞掃，藥熟黄金固可成。", "只待蓬壺賦詩罷，却來京洛看昇平。"]'),
('b527bcfe-0407-4b16-8377-f57317accdff','新作火閣二首  其一','陸游','宋','宋诗','song-poetry','','[]','旋設篝爐下紙簾，樂哉容膝似陶潜。',64,'全唐诗/poet.song.131000.json','["旋設篝爐下紙簾，樂哉容膝似陶潜。", "囊中佩藥無時服，架上堆書信手拈。", "似玉秋菰殊未老，如雲宿麥不須占。", "掃空祠祿吾何欠，陋巷簞瓢易屬厭。"]'),
('d208ad71-d336-41b6-bf87-44bc565e2d3f','新作火閣二首  其二','陸游','宋','宋诗','song-poetry','','[]','山路霜清葉正黄，地爐火暖夜偏長。',64,'全唐诗/poet.song.131000.json','["山路霜清葉正黄，地爐火暖夜偏長。", "中安煮藥膨脝鼎，傍設安禪曲录床。", "木槁不知年自往，雲閑已與世相忘。", "更闌坐穩人聲靜，時聽風簾響暗廊。"]'),
('f19bfb10-ce23-468e-88f3-63623d210851','舍北行飯','陸游','宋','宋诗','song-poetry','','[]','蔓絡疏籬草滿塘，飽嬉聊復步斜陽。',64,'全唐诗/poet.song.131000.json','["蔓絡疏籬草滿塘，飽嬉聊復步斜陽。", "一霜驟變千林色，兩犢新犁百畝荒。", "野寺僧殘尚鐘鼓，官堤舟過見帆檣。", "歸來笑補空囊課，寒日誰知亦自長。"]'),
('e452bc10-0e76-44c5-b2f1-705cd201b69d','遣興二首  其一','陸游','宋','宋诗','song-poetry','','[]','轍迹當年遍九州，晚歸始解卧林丘。',64,'全唐诗/poet.song.131000.json','["轍迹當年遍九州，晚歸始解卧林丘。", "愛身每戒玉抵鵲，養氣要如刀解牛。", "柔櫓摇殘天鏡月，短筇領盡石帆秋。", "儘言未辦常扃戶，竟是吾身得自由。"]'),
('09640217-3516-4ccf-8866-642417d3d665','遣興二首  其二','陸游','宋','宋诗','song-poetry','','[]','出仕纔堪斗大州，初歸便擬筑糟丘。',64,'全唐诗/poet.song.131000.json','["出仕纔堪斗大州，初歸便擬筑糟丘。", "虛名大似月蟾兔，榮路久如風馬牛。", "唧唧悲蛩常吊夜，蕭蕭蠹葉更禁秋。", "靜觀世事頻興嘆，千載前時有許由。"]'),
('7bfad0ad-b844-47a9-872d-50aa371cfcfe','舟中三首  其一','陸游','宋','宋诗','song-poetry','','[]','柂邊潮水落還生，篷底寒燈滅復明。',32,'全唐诗/poet.song.131000.json','["柂邊潮水落還生，篷底寒燈滅復明。", "約束長年牢繫纜，報人風雨有鼉鳴。"]'),
('ad1a3942-cc5d-491a-bc01-c2f2538c9183','舟中三首  其二','陸游','宋','宋诗','song-poetry','','[]','蕭蕭風雨小江秋，不是愁人亦合愁。',32,'全唐诗/poet.song.131000.json','["蕭蕭風雨小江秋，不是愁人亦合愁。", "忽聽疏鐘知寺近，笑尋沙路上牛頭。"]'),
('399bc9ff-d01c-495d-87fc-42183e4c05ad','舟中三首  其三','陸游','宋','宋诗','song-poetry','','[]','龕山古戍更漏聲，白塔小市燈火明。',32,'全唐诗/poet.song.131000.json','["龕山古戍更漏聲，白塔小市燈火明。", "六十年間幾來往，依然惻愴路傍情。"]'),
('aaecec3d-fad1-46f8-ab33-5145373c7662','雨夜感舊','陸游','宋','宋诗','song-poetry','','[]','雨來猛打窗，燈暗猶照壁。',96,'全唐诗/poet.song.131000.json','["雨來猛打窗，燈暗猶照壁。", "老人耿不寐，撫事悲夙昔。", "風生桔柏渡，馬病金牛驛。", "裊枝猿下飲，登樹熊自擲。", "危巢窺鶻栖，深雪見虎迹。", "至今清夜夢，猶想嶓山碧。", "廢棄謝功名，老疾輟行役。", "賦詩雖不工，聊用慰今夕。"]'),
('d756f250-0098-4ffb-9206-3bbcf8299937','夜聞落葉','陸游','宋','宋诗','song-poetry','','[]','我行出柴門，初喜春草生。',96,'全唐诗/poet.song.131000.json','["我行出柴門，初喜春草生。", "俛仰幾何時，落葉終夜聲。", "嗟我日益老，抱疾况未平。", "晨興就盥櫛，顧亦彊支撐。", "齋中有兩童，熟視不能名。", "定非張睢陽，大笑頹冠纓。", "死至人所同，此理何待評。", "但有一可恨，不見復兩京。"]'),
('c2623891-3930-4620-81f5-9976a48113de','閉門','陸游','宋','宋诗','song-poetry','','[]','閉門高卧鏡湖傍，元自無閑可得忙。',64,'全唐诗/poet.song.131000.json','["閉門高卧鏡湖傍，元自無閑可得忙。", "泛罷杯觴餘菊苦，玩殘指爪带橙香。", "燈昏共度空階雨，蛩冷偏依丈室床。", "不待衰年宦情盡，未來如雁到衡陽。"]'),
('f2b0a2ab-ae3e-48cb-aa83-c42e2f6483f2','祠祿滿不敢復請作口號三首  其一','陸游','宋','宋诗','song-poetry','','[]','今年高謝武夷君，飯豆羹藜亦所欣。',64,'全唐诗/poet.song.131000.json','["今年高謝武夷君，飯豆羹藜亦所欣。", "參透莊生齊物論，掃空韓子送窮文。", "心如脫阱奔林鹿，迹似還山不雨雲。", "猶幸此身强健在，鄉鄰爭看布襦裙。"]'),
('c4ba14ef-1eef-43c8-bab7-f1e5a4f893b0','祠祿滿不敢復請作口號三首  其二','陸游','宋','宋诗','song-poetry','','[]','祠庭八載竊榮名，一飽心知合自營。',64,'全唐诗/poet.song.131000.json','["祠庭八載竊榮名，一飽心知合自營。", "牘後落銜便手倦，月頭鎸俸喜身輕。", "弊衣不補惟頻結，濁酒難謀且細傾。", "賴有東皋堪肆力，比鄰相喚事冬耕。"]'),
('2851d9c0-ea5f-41d1-90aa-17e058905cae','祠祿滿不敢復請作口號三首  其三','陸游','宋','宋诗','song-poetry','','[]','白首還山不自存，天書四降海邊村。',64,'全唐诗/poet.song.131000.json','["白首還山不自存，天書四降海邊村。", "慚非故將前侯比，誤辱優賢養老恩。", "龜壽自應能食氣，鶴歸那得更乘軒。", "從今再草公車奏，惟有挂冠神武門。"]'),
('fc6a4670-9d91-4c95-9422-baa6740d227f','過鄰家','陸游','宋','宋诗','song-poetry','','[]','扶杖過吾鄰，相誇自在身。',48,'全唐诗/poet.song.131000.json','["扶杖過吾鄰，相誇自在身。", "年豐稱貸少，酒賤往來頻。", "群散雞歸柵，聲喧雀噪囷。", "丁寧語兒子，切勿厭沉淪。"]'),
('6ddaa535-af0d-47cc-bd05-3bcf033286c0','舍北野望四首  其一','陸游','宋','宋诗','song-poetry','','[]','短景妨遊興，長歌慰作勞。',48,'全唐诗/poet.song.131000.json','["短景妨遊興，長歌慰作勞。", "葉凋西埭近，水落北橋高。", "病每隨時劇，衰難與世鏖。", "旗亭新釀美，萬事一秋毫。"]'),
('b9c8d927-d09a-4bb3-b215-c74d048a0b74','舍北野望四首  其二','陸游','宋','宋诗','song-poetry','','[]','斷壟圍蔬圃，枯桑繫釣查。',48,'全唐诗/poet.song.131000.json','["斷壟圍蔬圃，枯桑繫釣查。", "經行橋獨木，佇立路三叉。", "野卉棲孤蝶，平川起亂鴉。", "搘筇無定處，興盡即還家。"]'),
('0c9d9552-98f1-451b-bdb4-77d9a42145ed','舍北野望四首  其三','陸游','宋','宋诗','song-poetry','','[]','溪彴通西崦，山蹊繚北村。',48,'全唐诗/poet.song.131000.json','["溪彴通西崦，山蹊繚北村。", "殘霞明水面，落葉擁籬根。", "野父編龍具，樵兒習兔園。", "吾今井蛙耳，敢復慕鵬鯤。"]'),
('ad924f2a-9907-4700-9dc5-8d67909d3f40','舍北野望四首  其四','陸游','宋','宋诗','song-poetry','','[]','早歲遭逢異，中年促召頻。',48,'全唐诗/poet.song.131000.json','["早歲遭逢異，中年促召頻。", "馳驅猶許國，卧起已須人。", "藥石三秋病，風波萬里身。", "籬門殘照裏，慘淡易傷神。"]'),
('3710bbe2-fb00-4b71-8f58-b33a15896ca1','書感','陸游','宋','宋诗','song-poetry','','[]','常記當年賦子虛，公卿交口薦相如。',64,'全唐诗/poet.song.131000.json','["常記當年賦子虛，公卿交口薦相如。", "豈知鶴髮殘年叟，猶讀蠅頭細字書。", "出處幸逃千載笑，功名從負此心初。", "荒園落葉紛如積，日暮歸來自荷鋤。"]'),
('b402053b-bd08-4f05-8d68-6d535c25af1d','冬夜爐邊小飲','陸游','宋','宋诗','song-poetry','','[]','擁爐可使曲身直，飲酒能回槁面紅。',32,'全唐诗/poet.song.131000.json','["擁爐可使曲身直，飲酒能回槁面紅。", "若使金丹真入手，飛騰亦在立談中。"]'),
('c44cee8a-8b6a-47c6-86ff-f8accf0640f2','龜堂獨酌二首  其一','陸游','宋','宋诗','song-poetry','','[]','幅巾蕭散餞餘齡，江左諸賢可乞靈。',64,'全唐诗/poet.song.131000.json','["幅巾蕭散餞餘齡，江左諸賢可乞靈。", "護枕小屏圖紫閣，映窗矮卷寫黄庭。", "曠懷與世元難合，幽句何人可遣聽。", "一酌蘭溪遺萬事，時看牆底卧長瓶。"]'),
('d0d18698-e948-4859-a3ad-9402925a25ab','龜堂獨酌二首  其二','陸游','宋','宋诗','song-poetry','','[]','一榼蘭溪自獻酬，徂年不肯爲人留。',64,'全唐诗/poet.song.131000.json','["一榼蘭溪自獻酬，徂年不肯爲人留。", "巴山頻入初寒夢，江月偏供獨夜愁。", "越石壯心雞喔喔，子卿歸信雁悠悠。", "天生我輩初何用，病骨支離又過秋。"]'),
('c45e5ce3-7f24-4d29-b3e8-a7bd44e90ae0','冬夜作短歌','陸游','宋','宋诗','song-poetry','','[]','饑鼠窺殘燈，寒犬踏枯葉。',144,'全唐诗/poet.song.131000.json','["饑鼠窺殘燈，寒犬踏枯葉。", "小室擁燎爐，清笳下危堞。", "老人素多疾，舉動常畏怯。", "衣裘視寒燠，日夜自調燮。", "食必按本草，下箸未嘗輒。", "體安疾自去，藥石無此捷。", "敢學李輕車，霸亭夜遊獵。", "况如馬新息，萬里聽鳶跕。", "欲求神氣住，先戒事物接。", "寧爲子光瘖，不效嗇夫喋。", "明晨一杯粥，趺坐橫白氎。", "無魚何足道，爲爾歌長鋏。"]'),
('0dbe5e4d-6024-4b4d-a158-06693f6d102f','病愈','陸游','宋','宋诗','song-poetry','','[]','倦榻呻吟每自哀，占蓍來告出餘災。',64,'全唐诗/poet.song.131000.json','["倦榻呻吟每自哀，占蓍來告出餘災。", "自能洗研拂書几，時亦折花尋酒杯。", "久類寒蛟潜岫穴，忽如老馬噴風埃。", "霜晴爛熳東窗日，一笑山坡訪早梅。"]'),
('890e83cc-47ba-4a64-bb2a-7978aea1ee25','自遣','陸游','宋','宋诗','song-poetry','','[]','枳籬茅屋枕孤峰，偃盡初來手種松。',64,'全唐诗/poet.song.131000.json','["枳籬茅屋枕孤峰，偃盡初來手種松。", "睡少未成千里夢，愁深先怯五更鐘。", "中天日月逢真主，數畝桑麻伴老農。", "世事古今誰料得，不堪陂水照衰容。"]'),
('fda330c7-eb19-4d3a-92c2-0b73bcf73a5e','感舊二首  其一','陸游','宋','宋诗','song-poetry','','[]','君不見資中名士有李石，八月秋濤供筆力。',115,'全唐诗/poet.song.131000.json','["君不見資中名士有李石，八月秋濤供筆力。", "初爲博士不暖席，晚補臺郎俄復斥。", "諸公熟睨亦太息，摧壓至死終不惜。", "生前何曾一錢直，沒後遺文價金璧。", "後之視今猶視昔，此事誠非一朝夕。", "山城舊廬暗荆棘，羸然諸孫守墳籍。", "撫孤我負朋友責，萬里詩成泪空滴。"]'),
('235bd8ab-d857-4c9a-a0c4-4448b4150080','感舊二首  其二','陸游','宋','宋诗','song-poetry','','[]','君不見蜀師渾甫字伯渾，半生高卧蟆頤村。',131,'全唐诗/poet.song.131000.json','["君不見蜀師渾甫字伯渾，半生高卧蟆頤村。", "才不得施道則尊，死已骨朽名猶存。", "文章落筆數千言，上友離騷下招魂。", "望之眉宇何軒軒，高談浩若洪河翻。", "范尹敬如綺與園，方飾羔雁登衡門。", "小人謗傷實不根，妄指拱璧求瑕痕。", "窮通在公豈足論，浮雲終散朝陽暾。", "安得此老起九原，入贊國論蘇黎元。"]'),
('e406407c-60ee-45a6-b203-537d10c6df9a','寒雨中偶賦二首  其一','陸游','宋','宋诗','song-poetry','','[]','鬢毛蕭颯齒根浮，徂歲翩翩肯暫留。',64,'全唐诗/poet.song.131000.json','["鬢毛蕭颯齒根浮，徂歲翩翩肯暫留。", "窮巷多泥誰問疾，空階滴雨又經秋。", "自營可笑誇三窟，善守寧須筑百樓。", "但使胸中機事盡，一樽隨處送悠悠。"]'),
('3dfd8357-58b3-4738-b87c-ebbadaad0c6f','寒雨中偶賦二首  其二','陸游','宋','宋诗','song-poetry','','[]','暮年心事與誰同，到處飄然一病翁。',64,'全唐诗/poet.song.131000.json','["暮年心事與誰同，到處飄然一病翁。", "斷夢凄凉燈影裏，殘詩零落雨聲中。", "莫驚顔鬢渾非昨，略數朋儕已半空。", "祠祿上還猶負愧，何功班綴冠仙蓬。"]'),
('9e2580fc-83c0-4745-9761-80b1e75d77bb','壽考如富貴','陸游','宋','宋诗','song-poetry','','[]','壽考如富貴，初亦不自知。',96,'全唐诗/poet.song.131000.json','["壽考如富貴，初亦不自知。", "邂逅偶不死，亦或至期頤。", "予少多疾恙，五十已遽衰。", "齒摇頷鬚白，蕭然蒲柳姿。", "俛仰忽二紀，卧病實半之。", "富貴不可求，壽亦豈汝私。", "萬事付自然，孰爲樂與悲。", "惟當老益學，易簀以爲期。"]'),
('0ed4cf07-0865-4fe2-b221-9cc6e7b915d6','午飯二首  其一','陸游','宋','宋诗','song-poetry','','[]','我望天公本自廉，身閑飯足敢求兼。',32,'全唐诗/poet.song.131000.json','["我望天公本自廉，身閑飯足敢求兼。", "破裘負日茆簷底，一碗藜羹似蜜甜。"]'),
('a9d06ece-a620-4ff7-bbc5-0671a6f59b26','午飯二首  其二','陸游','宋','宋诗','song-poetry','','[]','民窮豐歲或無食，此事昔聞今見之。',32,'全唐诗/poet.song.131000.json','["民窮豐歲或無食，此事昔聞今見之。", "吾儕飯飽更念肉，不待人嘲應自知。"]'),
('7f72b3c1-7e29-4eab-aeba-b532e94310fc','題王仲信畫水石橫幅','陸游','宋','宋诗','song-poetry','','[]','王郎書逼楊風子，畫亦憑陵蜀兩孫。',32,'全唐诗/poet.song.131000.json','["王郎書逼楊風子，畫亦憑陵蜀兩孫。", "豈是天公憎絕藝，一生憔悴向衡門。"]'),
('42b550cd-236e-4cbd-9aab-4aebf4d90e7e','治圃','陸游','宋','宋诗','song-poetry','','[]','槁蔓殘蕪滿幽圃，多具鉏耰課僮豎。',128,'全唐诗/poet.song.131000.json','["槁蔓殘蕪滿幽圃，多具鉏耰課僮豎。", "非惟吾圃要翦除，亦恐爾輩成惰窳。", "老桂盤壑飽風霜，修篁當軒弄烟雨。", "一松孤立信豪傑，兩槐對植如賓主。", "珍禽揀枝春欲動，蠹穴掃空吾甚武。", "蘼蕪芽蘗已暗長，甘菊根芽亦潜吐。", "山薑澗蒲乃微草，露葉參差看仰俯。", "世間安得有遺才，位置要須令得所。"]'),
('510403da-cb7c-4d54-b5c3-78ae78763e04','冬日感興十韵','陸游','宋','宋诗','song-poetry','','[]','霧雨天昏曀，陂湖地阻深。',120,'全唐诗/poet.song.131000.json','["霧雨天昏曀，陂湖地阻深。", "蔽空鴉作陣，暗路棘成林。", "有客風埃裏，頻年老病侵。", "夢魂來二豎，相法欠三壬。", "舊憤開孤劍，新愁感斷砧。", "唐衢惟痛哭，莊舄正悲吟。", "瘦跨秋門馬，寒生夜店衾。", "但思全舊璧，敢冀訪遺簪。", "樓上蒼茫眼，燈前破碎心。", "長謠傾濁酒，慷慨壓層陰。"]'),
('6b79e532-b3ec-4952-992b-53385a79d9d7','冬日出遊十韵','陸游','宋','宋诗','song-poetry','','[]','吳會寒常薄，冬深略未冰。',120,'全唐诗/poet.song.131000.json','["吳會寒常薄，冬深略未冰。", "荒郊觀雉鬭，大澤見魚騰。", "釣艇頻容借，籃輿漸可乘。", "有時穿密篠，隨處倚枯藤。", "金石秦遺刻，衣冠禹舊陵。", "叢祠祈臘雪，小市試春燈。", "問路鉏畬叟，爭橋乞供僧。", "疏狂違俗久，衰疾與年增。", "干祿雖知耻，懸車愧未能。", "階官有微俸，醉髮任鬅鬙。"]'),
('13fd612a-e6f5-4a6b-b68e-1286d4f66586','思蜀三首  其一','陸游','宋','宋诗','song-poetry','','[]','園廬已卜錦城東，乘驛歸來更得窮。',64,'全唐诗/poet.song.131000.json','["園廬已卜錦城東，乘驛歸來更得窮。", "只道驊騮開道路，豈知魚鳥困池籠。", "石犀祠下春波綠，金雁橋邊夜燭紅。", "未死舊遊如可繼，典衣猶擬醉郫筒。"]'),
('de22fcc4-134f-466f-9e6f-9061aaf6e786','思蜀三首  其二','陸游','宋','宋诗','song-poetry','','[]','二十年前客錦城，酒徒詩社盡豪英。',64,'全唐诗/poet.song.131000.json','["二十年前客錦城，酒徒詩社盡豪英。", "才名吏部傾朝野，意氣成州共死生。", "廢苑探梅常共醉，遺祠訪柏亦俱行。", "即今病卧寒燈裏，欲話當時涕已傾。"]'),
('7f5886a8-4539-40fa-81b5-993beea9c5a0','思蜀三首  其三','陸游','宋','宋诗','song-poetry','','[]','譚侯才氣敵文園，日日銀鞍畫戟門。',64,'全唐诗/poet.song.131000.json','["譚侯才氣敵文園，日日銀鞍畫戟門。", "奇句入神聞鬼泣，巨觥如海看鯨吞。", "一官胄監能令死，萬里銘旌忍更論。", "湖上秋來頻入夢，憑誰詞翰與招魂。"]'),
('bb7b4f71-66b5-49b6-ab6c-761105b058e0','作雪二首  其一','陸游','宋','宋诗','song-poetry','','[]','雪雲寒不動，林鳥噤無聲。',48,'全唐诗/poet.song.131000.json','["雪雲寒不動，林鳥噤無聲。", "病起衰何劇，囊空醉不成。", "中原亂方作，弱虜運將平。", "臺省多賢俊，常談愧老生。"]'),
('618c8bfe-9d7c-4c23-a575-babad9ca1975','作雪二首  其二','陸游','宋','宋诗','song-poetry','','[]','荒村雪欲作，耄叟病無聊。',48,'全唐诗/poet.song.131000.json','["荒村雪欲作，耄叟病無聊。", "樹暝烏鳶集，茆深雉兔驕。", "溪灘觀趁渡，嶺路數歸樵。", "即死無它憾，終身負聖朝。"]'),
('96b22542-57c6-47b8-be52-d63cf143f1cc','戲詠山家食品','陸游','宋','宋诗','song-poetry','','[]','牛乳抨酥瀹茗芽，蜂房分蜜漬棕花。',64,'全唐诗/poet.song.131000.json','["牛乳抨酥瀹茗芽，蜂房分蜜漬棕花。", "舊知石芥真尤物，晚得蔞蒿又一家。", "疏索鄉鄰緣老病，團欒兒女且喧譁。", "古人不下藜羹糝，斟酌龜堂已太奢。"]'),
('780d93bc-b14d-405f-a5c7-29879667a250','耕罷偶書','陸游','宋','宋诗','song-poetry','','[]','新溉東皋畝一鍾，烏犍粗足事春農。',64,'全唐诗/poet.song.132000.json','["新溉東皋畝一鍾，烏犍粗足事春農。", "灞橋風雪吟雖苦，杜曲桑麻興本濃。", "老大斷非金谷友，生存惟冀酒泉封。", "莫嘲野餉蕭條甚，箭茁蓴絲亦粗供。"]'),
('78933773-ae64-4378-8654-49ab63f0275f','雨夜','陸游','宋','宋诗','song-poetry','','[]','末路蕭條客子心，不堪徂歲更沉陰。',64,'全唐诗/poet.song.132000.json','["末路蕭條客子心，不堪徂歲更沉陰。", "低簷雨滴睡眠少，敗壁燈殘感慨深。", "不辦典衣謀盡醉，尚能擁鼻作微吟。", "交朋一散如天遠，試向今宵夢裏尋。"]'),
('a4cb14a1-cd56-454c-8874-3b1e1921ccc4','庵中晨起書觸目四首  其一','陸游','宋','宋诗','song-poetry','','[]','山重水複怯朝寒，一卷窗間袖手看。',64,'全唐诗/poet.song.132000.json','["山重水複怯朝寒，一卷窗間袖手看。", "朱擔長瓶列雲液，絳囊細字拆龍團。", "數峰移自侏儒國，一研來從黯淡灘。", "要識放翁頑鈍處，胸中七澤著猶寬。"]'),
('b102a9e0-38ee-4886-8177-66788dca291c','庵中晨起書觸目四首  其二','陸游','宋','宋诗','song-poetry','','[]','暉暉初日上簾鈎，漠漠清寒透衲裘。',64,'全唐诗/poet.song.132000.json','["暉暉初日上簾鈎，漠漠清寒透衲裘。", "雪棘並棲雙鵲瞑，金環斜絆一猿愁。", "廉宣卧壑松楠老，王子穿林水石幽。", "戲事自憐除未盡，此生行欲散風漚。"]'),
('8ad8883b-1768-43cb-b6db-89e8a6bbe05b','庵中晨起書觸目四首  其三','陸游','宋','宋诗','song-poetry','','[]','賦形不使面團團，聳膊心知到骨寒。',64,'全唐诗/poet.song.132000.json','["賦形不使面團團，聳膊心知到骨寒。", "晏子元非枕鼓士，杜生那有切雲冠。", "時扶遷客桄榔杖，日厭詩人苜蓿盤。", "賴是平生憎阿堵，今年初解侍祠官。"]'),
('1a867d58-dde1-4209-91a9-3c2361144912','庵中晨起書觸目四首  其四','陸游','宋','宋诗','song-poetry','','[]','初歸誓墓老鄉邦，手結茆茨近小江。',64,'全唐诗/poet.song.132000.json','["初歸誓墓老鄉邦，手結茆茨近小江。", "北渚露霑行藥屐，東廂日射勘書窗。", "孤忠自信丹心折，萬事空成雪鬢雙。", "長愧宗人白崖老，贈行期我鹿門龐。"]'),
('e2bbd442-f66b-4f2a-9e0d-75ecf6d6c48d','三山杜門作歌五首  其一','陸游','宋','宋诗','song-poetry','','[]','我生學步逢喪亂，家在中原厭奔竄。',66,'全唐诗/poet.song.132000.json','["我生學步逢喪亂，家在中原厭奔竄。", "淮邊夜聞賊馬嘶，跳去不待雞號旦。", "人懷一餅草間伏，往往經旬不炊爨。", "嗚呼亂定百口俱得全，孰爲此者寧非天。"]'),
('9f30bd63-b882-47fc-8871-caa732839add','三山杜門作歌五首  其二','陸游','宋','宋诗','song-poetry','','[]','高宗下詔傳神器，嗣皇御殿猶揮涕。',66,'全唐诗/poet.song.132000.json','["高宗下詔傳神器，嗣皇御殿猶揮涕。", "當時獲綴鵷鷺行，百寮拜舞皆歔欷。", "小臣疏賤亦何取，即日趨召登丹陛。", "嗚呼橋山歲晚松柏寒，殺身從死豈所難。"]'),
('d8a45b31-5c0b-4082-8cd4-3df0e2f77c75','三山杜門作歌五首  其三','陸游','宋','宋诗','song-poetry','','[]','中歲遠遊踰劍閣，青衫誤入征西幕。',66,'全唐诗/poet.song.132000.json','["中歲遠遊踰劍閣，青衫誤入征西幕。", "南沮水邊秋射虎，大散關頭夜聞角。", "畫策雖工不見用，悲吒那復從軍樂。", "嗚呼人生難料老更窮，麥野桑村白髮翁。"]'),
('4f277984-d0f3-45ef-b151-b13101766aba','三山杜門作歌五首  其四','陸游','宋','宋诗','song-poetry','','[]','晚入南宮典箋奏，濫陪太史牛馬走。',66,'全唐诗/poet.song.132000.json','["晚入南宮典箋奏，濫陪太史牛馬走。", "忽然名在白簡中，一櫂還家傾臘酒。", "十年光陰如電雹，綠蓑黄犢從鄰叟。", "嗚呼古來骯髒例倚門，况我本自安丘園。"]'),
('7941f46c-9204-479a-9f26-76713986146c','三山杜門作歌五首  其五','陸游','宋','宋诗','song-poetry','','[]','寬恩四賦仙祠祿，每忍慚顔救枵腹。',66,'全唐诗/poet.song.132000.json','["寬恩四賦仙祠祿，每忍慚顔救枵腹。", "五秉初辭官粟紅，一瓢自酌巖泉綠。", "天公乘除不負汝，宿疾微平歲中熟。", "嗚呼字字細讀逍遥篇，此去八十有幾年。"]'),
('4c949a00-a186-49b4-a2df-b492f94f1b97','老境二首  其一','陸游','宋','宋诗','song-poetry','','[]','白髮短欲盡，人嗤心尚孩。',48,'全唐诗/poet.song.132000.json','["白髮短欲盡，人嗤心尚孩。", "埋盆池瀲灧，累瓦塔崔嵬。", "軟飯三舂米，醇醪九醞醅。", "忽然拈筆起，記著早梅開。"]'),
('751c600d-cf5f-41e7-9e48-1819e0c30e82','老境二首  其二','陸游','宋','宋诗','song-poetry','','[]','今日霜殊重，衰翁老可憐。',48,'全唐诗/poet.song.132000.json','["今日霜殊重，衰翁老可憐。", "朝晡兩炊火，覆藉一床氈。", "人客容稱疾，兒童不攪眠。", "雲開見殘日，更愛小窗妍。"]'),
('b49bc0b8-69ae-439b-83fb-fb25db6c9cb0','記戊午十一月二十四夜夢','陸游','宋','宋诗','song-poetry','','[]','街南酒樓粲丹碧，萬頃湖光照山色。',128,'全唐诗/poet.song.132000.json','["街南酒樓粲丹碧，萬頃湖光照山色。", "我來半醉躡危梯，坐客驚顧聞飛屐。", "長縚短帽黄絁裘，從一山童持藥笈。", "近傳老仙嘗過市，此翁或是那可識。", "逡巡相語或稽首，爭獻名樽冀餘瀝。", "我欲自言度不聽，亦復軒然爲專席。", "高談方縱驚四座，不覺鄰雞呼夢破。", "人生自欺多類此，撫枕長謠識吾過。"]'),
('cdf4eaac-998f-499c-ade6-097cd45659f7','六經示兒子','陸游','宋','宋诗','song-poetry','','[]','六經如日月，萬世固長懸。',48,'全唐诗/poet.song.132000.json','["六經如日月，萬世固長懸。", "學不趨卑近，人誰非聖賢。", "馬能龍作友，蜹乃甕爲天。", "我老空追悔，兒無棄壯年。"]'),
('48a13102-a286-4103-b89c-c603a99fd0ac','舍北晚步','陸游','宋','宋诗','song-poetry','','[]','漠漠炊烟村遠近，鼕鼕儺鼓埭西東。',64,'全唐诗/poet.song.132000.json','["漠漠炊烟村遠近，鼕鼕儺鼓埭西東。", "三叉古路殘蕪裏，一曲清江淡靄中。", "外物已忘如棄屣，老身無伴等羈鴻。", "天寒寂寞籬門晚，又見浮生一歲窮。"]'),
('6b7c28cd-59ff-40e8-a690-62e56eeb3681','對酒','陸游','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','老子不堪塵世勞，且當痛飲讀離騷。',64,'全唐诗/poet.song.132000.json','["老子不堪塵世勞，且當痛飲讀離騷。", "此身幸已免虎口，有手但能持蟹螯。", "牛角挂書何足問，虎頭食肉亦非豪。", "天寒欲與人同醉，安得長江化濁醪。"]'),
('599e74f6-13e0-4107-8f73-622c0cf55205','夜坐求酒已盡喟然有賦','陸游','宋','宋诗','song-poetry','','[]','澹月微霜夜漏徂，披裘不睡附寒爐。',64,'全唐诗/poet.song.132000.json','["澹月微霜夜漏徂，披裘不睡附寒爐。", "清笳嫋嫋已三弄，殘火熒熒纔一銖。", "報國無期心欲折，讀書自力眼將枯。", "麴生作態年來甚，不受閑人折簡呼。"]'),
('5d085be6-0d0d-405b-b2f3-28b2d2fe2664','食粥','陸游','宋','宋诗','song-poetry','','[]','世人箇箇學長年，不悟長年在目前。',32,'全唐诗/poet.song.132000.json','["世人箇箇學長年，不悟長年在目前。", "我得宛丘平易法，只將食粥致神仙。"]'),
('8eae3ebc-b461-49b7-8641-c5ab07dccc60','寒夜','陸游','宋','宋诗','song-poetry','','[]','堅冰塞川厚莫測，斷雁叫群聲可哀。',64,'全唐诗/poet.song.132000.json','["堅冰塞川厚莫測，斷雁叫群聲可哀。", "草圍小甕酒未熟，霜壓瘦枝梅不開。", "稚子忍寒守蠹簡，老夫忘睡畫爐灰。", "低頭就世吾所諱，千載伯鸞安在哉。"]'),
('a6538550-9e68-44cb-b833-880c6e6536f3','梅花六首  其一','陸游','宋','宋诗','song-poetry','','[]','五十年間萬事非，放翁依舊掩柴扉。',32,'全唐诗/poet.song.132000.json','["五十年間萬事非，放翁依舊掩柴扉。", "相從不厭閑風月，只有梅花與釣磯。"]'),
('bf157be2-18af-497b-be9f-bca23c653f8a','梅花六首  其二','陸游','宋','宋诗','song-poetry','','[]','山村梅開處處香，醉插烏巾舞道傍。',32,'全唐诗/poet.song.132000.json','["山村梅開處處香，醉插烏巾舞道傍。", "飲酒得仙陶令達，愛花欲死杜陵狂。"]'),
('d5ef5ed3-88c8-465b-90b6-46d00cde94d9','梅花六首  其三','陸游','宋','宋诗','song-poetry','','[]','一花兩花春信回，南枝北枝風日催。',32,'全唐诗/poet.song.132000.json','["一花兩花春信回，南枝北枝風日催。", "爛熳却愁零落近，丁寧且莫十分開。"]'),
('09bd23e4-c20a-4533-a707-bb1f26cf6162','梅花六首  其四','陸游','宋','宋诗','song-poetry','','[]','廣寒宮中第一仙，情深不礙韵超然。',32,'全唐诗/poet.song.132000.json','["廣寒宮中第一仙，情深不礙韵超然。", "勸君莫作兒女態，但向花前傾玉船。"]'),
('a2e9bb65-5772-417d-8e3d-5089ca2a5a31','梅花六首  其五','陸游','宋','宋诗','song-poetry','','[]','秭歸江頭烟雨昏，客舟夜繫梅花村。',32,'全唐诗/poet.song.132000.json','["秭歸江頭烟雨昏，客舟夜繫梅花村。", "相逢萬里各羈旅，不待猿啼已斷魂。"]'),
('46bdf9ac-ccae-4f0e-9ec6-e36ce188a364','梅花六首  其六','陸游','宋','宋诗','song-poetry','','[]','青羊宮前錦江路，曾爲梅花醉十年。',32,'全唐诗/poet.song.132000.json','["青羊宮前錦江路，曾爲梅花醉十年。", "豈知今日尋香處，却是山陰雪夜船。"]'),
('9f0f11f1-b896-4f59-b3b0-0d1b9371dca8','三山卜居今三十有三年矣屋陋甚而地有餘數世之後當自成一村今日病少間作詩以示後人二首  其一','陸游','宋','宋诗','song-poetry','','[]','印累累，綬若若，換君朱顔君不覺。',128,'全唐诗/poet.song.132000.json','["印累累，綬若若，換君朱顔君不覺。", "冠如箕，劍拄頤，蒼頭廬兒笑君癡。", "不如短褐歸鄉舍，上畢租庸下婚嫁。", "橫陂引水蒔禾黍，高陸犁荒種桑柘。", "比鄰畢出觀夜場，老稚相呼作春社。", "雞爭舂米茅簷底，犬吠行人槿籬罅。", "數椽幸可傳子孫，此地它年名陸村。", "藜羹一飽能世守，殊勝養牛并上尊。"]'),
('13ee2102-be95-4750-b4d7-5229f884b29a','三山卜居今三十有三年矣屋陋甚而地有餘數世之後當自成一村今日病少間作詩以示後人二首  其二','陸游','宋','宋诗','song-poetry','','[]','再見封侯未爲快，一擲成盧安用再。',128,'全唐诗/poet.song.132000.json','["再見封侯未爲快，一擲成盧安用再。", "世間得意固多矣，堪笑窮人事常敗。", "我生出仕四十年，寸進恰如船上埭。", "即今卧病茅簷裏，回首窮通竟何在。", "荆山之下玉抵鵲，兩京春薺論斤賣。", "蘇秦煌煌佩六印，尼父栖栖厄陳蔡。", "玄保美官輒見思，東野出門常有礙。", "躬耕至老豈不佳，子孫當以吾爲戒。"]'),
('54e4725c-9890-47c7-8e9b-0414a53ac372','南園觀梅','陸游','宋','宋诗','song-poetry','','[]','小嶺清陂寂寞中，綠樽歲晚與君同。',64,'全唐诗/poet.song.132000.json','["小嶺清陂寂寞中，綠樽歲晚與君同。", "高標賴有詩人識，絕艷真窮造物工。", "正喜參差橫夜月，又驚零落付春風。", "老諳世事寧多嘆，身自人間一轉蓬。"]'),
('eb56ae18-ec6f-4f30-b409-6d1ea2014cb3','歲盡苦寒','陸游','宋','宋诗','song-poetry','','[]','曉寒無賴透重裘，三日江雲暝不收。',64,'全唐诗/poet.song.132000.json','["曉寒無賴透重裘，三日江雲暝不收。", "歲月推移吾輩老，交朋零落此生浮。", "東皋苦潦猶中熟，舊疾雖存亦小瘳。", "禹廟蘭亭俱在眼，剩沽春酒破春愁。"]'),
('74452c9a-558c-4934-a3a0-9897f501e79b','己未新歲','陸游','宋','宋诗','song-poetry','','[]','餞歲愁雖劇，迎年喜亦深。',48,'全唐诗/poet.song.132000.json','["餞歲愁雖劇，迎年喜亦深。", "桃符带草寫，椒酒過花斟。", "車馬久無迹，兒孫聊慰心。", "更欣春意早，處處有鳴禽。"]'),
('97f67d01-b7ce-4aeb-b3cc-c3047e6829cd','歲首書事二首  其一','陸游','宋','宋诗','song-poetry','','[]','東風入律寒猶劇，多稼占祥雪欲成。',64,'全唐诗/poet.song.132000.json','["東風入律寒猶劇，多稼占祥雪欲成。", "鬰壘自書誇腕力，屠蘇不至嘆人情。", "呼盧院落譁新歲，賣困兒童起五更。", "白髮滿頭能且健，剩隨鄰曲樂昇平。"]'),
('bf7ffc00-d905-40f9-916e-a276efe36d32','歲首書事二首  其二','陸游','宋','宋诗','song-poetry','','[]','扶持又度改年時，耄齒侵尋敢自期。',64,'全唐诗/poet.song.132000.json','["扶持又度改年時，耄齒侵尋敢自期。", "中夕祭餘分餺飥，黎明人起換鍾馗。", "春盤未抹青絲菜，壽斝先酬白髮兒。", "聞道城中燈絕好，出門無日嘆吾衰。"]'),
('16f6eee6-88d0-4cab-9429-e25151352a50','初春','陸游','宋','宋诗','song-poetry','','[]','元日人日來聯翩，轉頭又見試燈天。',64,'全唐诗/poet.song.132000.json','["元日人日來聯翩，轉頭又見試燈天。", "且欣一雪壓災瘴，不怕連陰咽管弦。", "陌上漸多酤酒舍，岸邊初理下湖船。", "紫姑擬卜元無事，只問今春幾醉眠。"]'),
('9a640957-b923-4772-ab1a-53ae7dc5a2eb','庵中獨居感懷三首  其一','陸游','宋','宋诗','song-poetry','','[]','身愈龍鍾髮愈稀，流年冉冉迫殘暉。',64,'全唐诗/poet.song.132000.json','["身愈龍鍾髮愈稀，流年冉冉迫殘暉。", "讀書十紙勤雖在，上樹千回事已非。", "仗馬曾鳴宜取斥，牧羝雖乳亦忘歸。", "餘生自笑知何似，萬里遼天老令威。"]'),
('b5c7be0c-02e8-47e9-b8d3-a1db430f730b','庵中獨居感懷三首  其二','陸游','宋','宋诗','song-poetry','','[]','自閉庵門不點燈，惰耕村叟罷參僧。',64,'全唐诗/poet.song.132000.json','["自閉庵門不點燈，惰耕村叟罷參僧。", "一生已是膠黏日，投老安能夏造冰。", "頑面敢辭乾汝唾，蔬餐聊得曲吾肱。", "高舂睡熟無多笑，那有禪師解放鷹。"]'),
('5587346f-fe78-4b55-bf67-878b110200af','庵中獨居感懷三首  其三','陸游','宋','宋诗','song-poetry','','[]','無錢溪女亦留魚，有雨東家每借驢。',64,'全唐诗/poet.song.132000.json','["無錢溪女亦留魚，有雨東家每借驢。", "藜粥數匙晨壓藥，松肪一碗夜觀書。", "黄紬被暖閑無厭，白布衫長樂有餘。", "南陌東阡春事動，放翁作計未全疏。"]'),
('a685089c-73ae-494a-99f4-d4f4fbec7c6f','戲作貧詩二首  其一','陸游','宋','宋诗','song-poetry','','[]','垂老貧彌甚，虛教遇太平。',48,'全唐诗/poet.song.132000.json','["垂老貧彌甚，虛教遇太平。", "竈閑無馬穴，釜冷有魚生。", "妾病常停織，兒饑屢輟耕。", "癡頑惟此老，未廢浩歌聲。"]'),
('eb3e6118-3205-4bca-8d26-696314151415','戲作貧詩二首  其二','陸游','宋','宋诗','song-poetry','','[]','左券頻稱貸，西成少蓋藏。',48,'全唐诗/poet.song.132000.json','["左券頻稱貸，西成少蓋藏。", "苦饑炊稻種，緣病賣桑黄。", "土焙憐烟暖，藜羹愛糝香。", "君看首陽叟，窮死亦何傷。"]'),
('ce5b52f4-95d7-4171-b16d-6b819ad1c36b','春日園中作','陸游','宋','宋诗','song-poetry','','[]','杏花開過尚輕寒，盡日無人獨倚闌。',64,'全唐诗/poet.song.132000.json','["杏花開過尚輕寒，盡日無人獨倚闌。", "久別名山憑夢到，每思舊友取書看。", "塵埃幸已賒腰折，富貴深知欠面團。", "老去逢春都有幾，一杯行復送春殘。"]'),
('bf8a7f9f-54b6-4ccd-8745-f10781e3011b','中春連日得雨雷亦應候','陸游','宋','宋诗','song-poetry','','[]','誰言白首意低摧，老子逢春亦樂哉。',64,'全唐诗/poet.song.132000.json','["誰言白首意低摧，老子逢春亦樂哉。", "犁畔方吹社公雨，壟頭又轉阿香雷。", "睡餘支枕聽鶯語，醉裏題窗記燕來。", "更有山家堪喜事，吾孫上樹欲千回。"]'),
('0adc2fd4-4900-45d9-a88d-11683c2e1725','雨後微陰光景益奇復得長句','陸游','宋','宋诗','song-poetry','','[]','結轍軒車已掃空，揮犀談笑與誰同。',64,'全唐诗/poet.song.132000.json','["結轍軒車已掃空，揮犀談笑與誰同。", "日消淺醉閑吟裏，春在輕陰薄靄中。", "百尺遊絲喜風定，一雙新燕說泥融。", "天工只費須臾力，開遍東闌半丈紅。"]'),
('bb34213b-7142-4b46-b2e7-8dc580650c36','春日小園雜賦二首  其一','陸游','宋','宋诗','song-poetry','','[]','久矣雲霄鎩羽翰，小園聊得賦春寒。',64,'全唐诗/poet.song.132000.json','["久矣雲霄鎩羽翰，小園聊得賦春寒。", "風生鴨綠紋如織，露染猩紅色未乾。", "不向山丘嘆零落，且從兒女話團欒。", "人言麥信春來好，湯餅今年慮已寬。"]'),
('9dc620f9-b347-4304-8f6c-bebb64073997','春日小園雜賦二首  其二','陸游','宋','宋诗','song-poetry','','[]','市塵不到放翁家，繞麥穿桑野徑斜。',64,'全唐诗/poet.song.132000.json','["市塵不到放翁家，繞麥穿桑野徑斜。", "夜雨長深三尺水，曉寒留得一分花。", "悶從鄰舍分春甕，閑就僧窗試露芽。", "自此年光應更好，日驅秧馬聽繅車。"]'),
('749d81aa-396c-4ce0-824e-243681ed6504','簡鄰里','陸游','宋','宋诗','song-poetry','','[]','今年意味報君知，屬疾雖頻未苦衰。',64,'全唐诗/poet.song.132000.json','["今年意味報君知，屬疾雖頻未苦衰。", "獨坐空齋如自訟，小鎸殘俸類分司。", "閑撐野艇漁蓑溼，亂插山花醉帽欹。", "有興行歌便終日，逢人那識我爲誰。"]'),
('2addc140-9e0d-4ffe-be46-60011b5c4069','客叩門多不能接往往獨坐至晚戲作','陸游','宋','宋诗','song-poetry','','[]','貧舍久疏羅酒漿，客來不復倒衣裳。',64,'全唐诗/poet.song.132000.json','["貧舍久疏羅酒漿，客來不復倒衣裳。", "官情已盡詩情在，世味無餘睡味長。", "紅練带飛穿柳去，錦熏籠暖撲簾香。", "蕭然自笑渾無事，漁唱聲中又夕陽。"]'),
('fc527986-b8b6-4022-924a-1d6d59df5947','園中偶題四首  其一','陸游','宋','宋诗','song-poetry','','[]','綠衣粲粲咮微丹，映葉穿枝立畫欄。',32,'全唐诗/poet.song.132000.json','["綠衣粲粲咮微丹，映葉穿枝立畫欄。", "莫戀主人驚不去，五陵年少有金丸。"]'),
('98203132-fdc7-49b3-9424-e04a10ffcd99','園中偶題四首  其二','陸游','宋','宋诗','song-poetry','','[]','春深無處不春風，數樹桃花乃爾紅。',32,'全唐诗/poet.song.132000.json','["春深無處不春風，數樹桃花乃爾紅。", "鶯蝶紛紛自常事，不應也著白頭翁。"]'),
('1b5361c4-69fb-4a16-bec0-48f57f134a5b','園中偶題四首  其三','陸游','宋','宋诗','song-poetry','','[]','憶向彭州取牡丹，蠟封馳騎露初乾。',32,'全唐诗/poet.song.132000.json','["憶向彭州取牡丹，蠟封馳騎露初乾。", "如今歷盡人間事，縱有姚黄亦懶看。"]'),
('a02038cc-bff5-451b-a966-448463496bcb','園中偶題四首  其四','陸游','宋','宋诗','song-poetry','','[]','九日春陰一日晴，不堪風駕浪花生。',32,'全唐诗/poet.song.132000.json','["九日春陰一日晴，不堪風駕浪花生。", "畫船欲解還歸卧，寂寂窗扉聽鳥聲。"]'),
('6ef57b3a-ca5f-476c-8e86-7e78f24d7026','北窗偶題四首  其一','陸游','宋','宋诗','song-poetry','','[]','兩叢香百合，一架粉長春。',24,'全唐诗/poet.song.132000.json','["兩叢香百合，一架粉長春。", "堪笑龜堂老，歡然不記貧。"]'),
('b704caf3-90d2-4578-9f30-7de712dbb97e','北窗偶題四首  其二','陸游','宋','宋诗','song-poetry','','[]','曉晴林鵲喜，晝暖蜜蜂喧。',24,'全唐诗/poet.song.132000.json','["曉晴林鵲喜，晝暖蜜蜂喧。", "我老詩情盡，逢春亦一言。"]'),
('7dfc6ad4-4381-4bad-b782-b2659d47e161','北窗偶題四首  其三','陸游','宋','宋诗','song-poetry','','[]','簾外燕翩翩，歸時在社前。',24,'全唐诗/poet.song.132000.json','["簾外燕翩翩，歸時在社前。", "不辭飛渡海，來看賽豐年。"]'),
('b48fc724-ac45-45f9-bea1-c3d584541378','北窗偶題四首  其四','陸游','宋','宋诗','song-poetry','','[]','烟波兩鸂鶒，肯爲放翁來。',24,'全唐诗/poet.song.132000.json','["烟波兩鸂鶒，肯爲放翁來。", "菰米猶能給，蒼顔得屢開。"]'),
('9694296e-2768-4fc6-b980-d2dd57fc49d8','沈園二首  其一','陸游','宋','宋诗','song-poetry','','[]','城上斜陽畫角哀，沈園非復舊池臺。',32,'全唐诗/poet.song.132000.json','["城上斜陽畫角哀，沈園非復舊池臺。", "傷心橋下春波綠，曾是驚鴻照影來。"]'),
('5bfa0a97-fcc9-4894-baf8-74457eddedd0','沈園二首  其二','陸游','宋','宋诗','song-poetry','','[]','夢斷香消四十年，沈園柳老不吹綿。',32,'全唐诗/poet.song.132000.json','["夢斷香消四十年，沈園柳老不吹綿。", "此身行作稽山土，猶吊遺蹤一泫然。"]'),
('507b208f-8665-402f-a527-6cc144e6864b','戲贈園中花','陸游','宋','宋诗','song-poetry','','[]','橫風疾雨爲花厄，霽日暄風又不禁。',32,'全唐诗/poet.song.132000.json','["橫風疾雨爲花厄，霽日暄風又不禁。", "我欲小施調燮手，酌中寒暖半晴陰。"]'),
('ab9fe5bb-3af6-42a8-984a-a5e718e369b1','春思','陸游','宋','宋诗','song-poetry','','[]','兀兀治聾酒未醒，霏霏潑火雨初晴。',64,'全唐诗/poet.song.132000.json','["兀兀治聾酒未醒，霏霏潑火雨初晴。", "愁看入戶桃花片，閑聽爭巢燕子聲。", "百疾侵陵成老大，一春轉盼又清明。", "蘭亭禹廟渾如昨，回首兒時似隔生。"]'),
('d829c8a3-4846-4015-ae71-21413c4230f1','贈燕','陸游','宋','宋诗','song-poetry','','[]','燕來我何喜，感此中春時。',96,'全唐诗/poet.song.132000.json','["燕來我何喜，感此中春時。", "燕去亦何有，無奈凋年悲。", "四序如循環，萬物更盛衰。", "我亦寓斯世，如客會當歸。", "驪車已在門，戀戀終何爲。", "達人付無心，欣厭兩俱非。", "豈有天壤間，會合無別離。", "對花不爛醉，燕子笑汝癡。"]'),
('a1fe40cc-2224-409b-8511-6f1f62440032','雨悶示兒子','陸游','宋','宋诗','song-poetry','','[]','東吳春雨多，略無三日晴。',120,'全唐诗/poet.song.132000.json','["東吳春雨多，略無三日晴。", "濛濛平野暗，淅淅空階聲。", "百花雨中盡，三月未聞鶯。", "重裘坐奧室，時序真强名。", "亦欲借驢出，泥淖沾衣纓。", "撫事每累欷，濁醪聊獨傾。", "景運今方開，關輔一日平。", "我家本好畤，灞滻可躬耕。", "買酒新豐市，看花下杜城。", "會當與汝輩，藉草作清明。"]'),
('053470f6-c886-4554-b72b-404d2ec64569','讀晉書','陸游','宋','宋诗','song-poetry','','[]','諸公日飫萬錢厨，人乳蒸豚玉食無。',32,'全唐诗/poet.song.132000.json','["諸公日飫萬錢厨，人乳蒸豚玉食無。", "誰信秋風雒城裏，有人歸棹爲蓴鱸。"]'),
('ba132f48-b5ce-4213-9387-05bf21f7d528','春晚苦雨','陸游','宋','宋诗','song-poetry','','[]','垂老卧村墅，餘寒欺病身。',48,'全唐诗/poet.song.132000.json','["垂老卧村墅，餘寒欺病身。", "雞猶未忘旦，雨欲不容春。", "忽忽花時過，茫茫草色勻。", "蓴絲已上市，一飯未傷貧。"]'),
('f3b00077-7144-4c33-bae5-4f8ddf9dd413','燕','陸游','宋','宋诗','song-poetry','','[]','春晝花明映柳纖，燕歸勝事始能兼。',64,'全唐诗/poet.song.132000.json','["春晝花明映柳纖，燕歸勝事始能兼。", "爭梁誶語驚幽夢，掠地斜飛避畫簾。", "雛食得蟲應自喜，巢泥經雨更頻添。", "去來要是知時節，常怪人嘲作附炎。"]'),
('969c57e0-e44a-4570-a782-4f813701c9fe','夜雨','陸游','宋','宋诗','song-poetry','','[]','空階雨聲夜轉急，壁疏窗破凄風入。',64,'全唐诗/poet.song.132000.json','["空階雨聲夜轉急，壁疏窗破凄風入。", "一燈嫋嫋吹欲滅，老生獨傍書架立。", "取書欲讀輒復休，却行出門搔白頭。", "市樓賣酒日千斛，眾人皆樂君胡憂。"]'),
('7c94a29d-e696-4e6a-89c8-711e5f1d6dfb','寒食日九里平水道中','陸游','宋','宋诗','song-poetry','','[]','曉雨絲絲熟食時，泥深轍斷客行遲。',64,'全唐诗/poet.song.132000.json','["曉雨絲絲熟食時，泥深轍斷客行遲。", "亂雲重疊藏山寺，野水縱橫入稻陂。", "馬鬣松陰封舊隴，龜趺道左立新碑。", "扶衰此出知能幾，清泪臨風不自持。"]'),
('b069e5ba-47ed-4f60-bca9-6d61c38e1f67','春晴自雲門歸三山','陸游','宋','宋诗','song-poetry','','[]','乍行春野眼增明，漸減春衣體倍輕。',64,'全唐诗/poet.song.132000.json','["乍行春野眼增明，漸減春衣體倍輕。", "人賣山茶先穀雨，鴉隨墦祭過清明。", "柳塘水滿雙鳧戲，稻隴泥深一犢行。", "晚到三橋泛舟去，掩關不復畏重城。"]'),
('fd1aa1a0-85ff-4a87-83a6-62fbd55b6ee5','予數年不至城府丁巳火後今始見之','陸游','宋','宋诗','song-poetry','','[]','陳迹關心已自悲，劫灰滿眼更增欷。',64,'全唐诗/poet.song.132000.json','["陳迹關心已自悲，劫灰滿眼更增欷。", "山川壯麗昔無敵，城郭蕭條今已非。", "窣堵招提俱昨夢，祝融回祿尚餘威。", "故交減盡新知少，縱保桑榆誰與歸。"]'),
('9b4b9663-6150-4e72-9ecc-4a7c45a1740a','晚自北港泛舟還家','陸游','宋','宋诗','song-poetry','','[]','舒嘯蓬籠底，經行略彴西。',48,'全唐诗/poet.song.132000.json','["舒嘯蓬籠底，經行略彴西。", "水深鵝唼草，雨細犢掀泥。", "醉倚乾坤大，閑知物我齊。", "衡門觸冠過，聊得賦幽棲。"]'),
('e0839e66-bf1e-496a-92be-c56f714e1ebd','書懷','陸游','宋','宋诗','song-poetry','','[]','羸馬常愁趁早朝，斥歸幸復侶漁樵。',64,'全唐诗/poet.song.132000.json','["羸馬常愁趁早朝，斥歸幸復侶漁樵。", "青黄未勝溝中斷，宮徵何殊爨下焦。", "心樂簞瓢同鼎食，身安山澤謝弓招。", "數間茅屋誰知處，烟雨濛濛隔斷橋。"]'),
('601052d5-d2ee-484c-a29d-a30378660f6c','初夏','陸游','宋','宋诗','song-poetry','','[]','淡靄輕颸入夏初，一窗新綠鳥相呼。',64,'全唐诗/poet.song.132000.json','["淡靄輕颸入夏初，一窗新綠鳥相呼。", "出門易倦常歸卧，著句難工但自娛。", "花徑蝶閑無墮蕊，酒樓人散有空壚。", "閩川茶籠猶霑及，肺渴朝來頓欲蘇。"]'),
('51723f37-0b59-45c2-aa0b-f7cbfb65b1e4','小筑','陸游','宋','宋诗','song-poetry','','[]','放翁小筑寄江郊，屋破隨時旋補茅。',64,'全唐诗/poet.song.132000.json','["放翁小筑寄江郊，屋破隨時旋補茅。", "暮看白烟橫水際，曉聽清露滴林梢。", "生來不啜猩猩酒，老去那營燕燕巢。", "目斷鹿門三太息，龐公千載可論交。"]'),
('d9ce9a0f-3051-4064-8637-1b2449bdefe9','喜雨','陸游','宋','宋诗','song-poetry','','[]','幽人睡覺夜未央，四簷懸溜聲浪浪。',96,'全唐诗/poet.song.132000.json','["幽人睡覺夜未央，四簷懸溜聲浪浪。", "樂哉甘澍及時至，九衢一洗塵沙黄。", "明朝鄰曲各歡喜，賽廟沽酒刲豬羊。", "不勞轣轆蹋龍骨，轉盼白水盈陂塘。", "呼兒掃地設菅席，與汝一醉歌時康。", "豈惟磨鐮待收麥，小甑已覺吳粳香。"]'),
('beb1d91e-0cd1-4ad2-800b-72d1af2207f6','晨起','陸游','宋','宋诗','song-poetry','','[]','天公擇地養衰殘，著向桑村麥野間。',64,'全唐诗/poet.song.132000.json','["天公擇地養衰殘，著向桑村麥野間。", "曉色入簾初滉漾，幽禽窺戶已間關。", "酒徒散去稀中聖，詩思衰來愧小山。", "一炷沉烟北窗底，曲肱卧看不勝閑。"]'),
('88ce3179-8c3b-4831-b6d8-95dc4d632437','五月初病體益輕偶書','陸游','宋','宋诗','song-poetry','','[]','世事紛紛了不知，又逢燕乳麥秋時。',64,'全唐诗/poet.song.132000.json','["世事紛紛了不知，又逢燕乳麥秋時。", "經年謝客常因醉，三日無詩自怪衰。", "乘雨旋移西崦藥，留燈重覆北窗棋。", "但將生死俱拈起，造物從來是小兒。"]'),
('6c99f2ca-653a-4fa4-916f-adcb85565c78','己未重五','陸游','宋','宋诗','song-poetry','','[]','門楣束艾作神人，團糭盤中節物新。',32,'全唐诗/poet.song.132000.json','["門楣束艾作神人，團糭盤中節物新。", "安用丹書禳赤口，風波雖惡不關身。"]'),
('0f4d8625-16d1-4875-a061-53c52d5bef79','五月七日拜致仕敕口號二首  其一','陸游','宋','宋诗','song-poetry','','[]','剡曲東歸日醉眠，冰銜屢忝武夷仙。',64,'全唐诗/poet.song.132000.json','["剡曲東歸日醉眠，冰銜屢忝武夷仙。", "恩如長假容居里，官似分司不限年。", "一札疏榮馳廄置，兩兒扶拜望雲天。", "坐糜半俸猶多愧，月費公朝二萬錢。"]'),
('c23c085f-20cb-44ad-add1-6d790c70e12f','五月七日拜致仕敕口號二首  其二','陸游','宋','宋诗','song-poetry','','[]','黄紙東來墨未乾，孤臣恩許挂朝冠。',64,'全唐诗/poet.song.132000.json','["黄紙東來墨未乾，孤臣恩許挂朝冠。", "小兒扶出迎門拜，鄰舍相呼擁路觀。", "白首奉身歸畎畝，清霄無夢接鵷鸞。", "從今剩把花前酒，憂患都空量自寬。"]'),
('d5dd0d3c-17c7-43e4-b1c6-bde3a2c33a5f','致仕後即事十五首  其一','陸游','宋','宋诗','song-poetry','','[]','休官拜命不勝榮，墨溼黄新照眼明。',32,'全唐诗/poet.song.132000.json','["休官拜命不勝榮，墨溼黄新照眼明。", "絡繹交親來作賀，羊腔酒擔擁柴荆。"]'),
('104145f9-0890-46ae-9586-50ae64e8388c','致仕後即事十五首  其二','陸游','宋','宋诗','song-poetry','','[]','敕過鸞臺鳳閣來，清晨初拆驛書開。',32,'全唐诗/poet.song.132000.json','["敕過鸞臺鳳閣來，清晨初拆驛書開。", "繡箱香案迎門拜，身著朝衫止此回。"]'),
('38b71bdb-1ff6-40b8-99fb-a6456a6cfc4c','致仕後即事十五首  其三','陸游','宋','宋诗','song-poetry','','[]','山村處處晴收麥，鄰曲家家午曬絲。',32,'全唐诗/poet.song.132000.json','["山村處處晴收麥，鄰曲家家午曬絲。", "正用此時身得謝，十分壽酒不須辭。"]'),
('9895fcb4-d9af-452d-8e88-af0883ebd290','致仕後即事十五首  其四','陸游','宋','宋诗','song-poetry','','[]','白髮三朝執戟郎，賜骸偶值歲豐穰。',32,'全唐诗/poet.song.132000.json','["白髮三朝執戟郎，賜骸偶值歲豐穰。", "村東已種千畦麥，舍北新添百本桑。"]'),
('15e27881-bb4d-49c5-a663-08e33e3c15d4','致仕後即事十五首  其五','陸游','宋','宋诗','song-poetry','','[]','老民一日脫朝衣，回首平生萬事非。',32,'全唐诗/poet.song.132000.json','["老民一日脫朝衣，回首平生萬事非。", "赤脚婢沽村釀去，平頭奴馭草驢歸。"]'),
('8d964ef9-1a1a-47ba-b154-9a3c9ba1e08d','致仕後即事十五首  其六','陸游','宋','宋诗','song-poetry','','[]','一生病鶴寄樊籠，此去鴻冥萬里空。',32,'全唐诗/poet.song.132000.json','["一生病鶴寄樊籠，此去鴻冥萬里空。", "未論蓴羹與羊酪，新秔要勝太倉紅。"]'),
('f65c059f-70ba-4ea8-8061-85508710f5a5','致仕後即事十五首  其七','陸游','宋','宋诗','song-poetry','','[]','沉綿分已餞餘生，造物苛留未遣行。',32,'全唐诗/poet.song.132000.json','["沉綿分已餞餘生，造物苛留未遣行。", "今日下床還健在，一編來就小窗明。"]'),
('c5912087-8a82-4ff6-b409-33d91aa83f19','致仕後即事十五首  其八','陸游','宋','宋诗','song-poetry','','[]','清靜全勝欲界天，逍遥不減地行仙。',32,'全唐诗/poet.song.132000.json','["清靜全勝欲界天，逍遥不減地行仙。", "眾中莫怪人嫌老，十五年前本命年。"]'),
('c763c842-dd90-400f-9357-6a6fbc9e4fc6','致仕後即事十五首  其九','陸游','宋','宋诗','song-poetry','','[]','一盂麥飯掩柴關，坐久不堪腰脚頑。',32,'全唐诗/poet.song.132000.json','["一盂麥飯掩柴關，坐久不堪腰脚頑。", "拖得瘦藤閑信步，小橋東北望螺山。"]'),
('f6f52559-fab2-42bd-a503-4b8cdd792048','致仕後即事十五首  其一○','陸游','宋','宋诗','song-poetry','','[]','問門前客元無迹，諛墓中人本不工。',32,'全唐诗/poet.song.132000.json','["問門前客元無迹，諛墓中人本不工。", "猶有鄰僧能送米，未妨竊比玉川公。"]'),
('64d1fda4-5fa2-4f97-9bd6-f8edf316835f','致仕後即事十五首  其一一','陸游','宋','宋诗','song-poetry','','[]','歸耕所願雜民編，乍脫朝衫喜欲顛。',32,'全唐诗/poet.song.132000.json','["歸耕所願雜民編，乍脫朝衫喜欲顛。", "但得吾兒能力穡，不請半俸更超然。"]'),
('dd32955b-0b88-4657-b9f2-d1deeb69ab1e','致仕後即事十五首  其一二','陸游','宋','宋诗','song-poetry','','[]','湘湖蓴菜勝羊酪，項里楊梅敵荔枝。',32,'全唐诗/poet.song.132000.json','["湘湖蓴菜勝羊酪，項里楊梅敵荔枝。", "八帙開來今過半，一杯引滿若爲辭。"]'),
('df214bf1-6c2c-47a3-8da5-6c8bdab41d2f','致仕後即事十五首  其一三','陸游','宋','宋诗','song-poetry','','[]','不嫌雞瘦濁醪酸，草草杯盤具亦難。',32,'全唐诗/poet.song.132000.json','["不嫌雞瘦濁醪酸，草草杯盤具亦難。", "食指忽摇方竊喜，小兒來請賽鄱官。"]'),
('5883d4c4-5895-4deb-a467-753cad1d4979','致仕後即事十五首  其一四','陸游','宋','宋诗','song-poetry','','[]','甑中白飯出新舂，甕裏黄齏細芼葱。',32,'全唐诗/poet.song.132000.json','["甑中白飯出新舂，甕裏黄齏細芼葱。", "一飽坐兼南北美，始知造物念衰翁。"]'),
('205bb9b7-1234-4967-8ce5-3aba22252429','致仕後即事十五首  其一五','陸游','宋','宋诗','song-poetry','','[]','多事車前要八騶，老人惟與一藤遊。',32,'全唐诗/poet.song.132000.json','["多事車前要八騶，老人惟與一藤遊。", "未教變化爲龍去，更踏人間萬里秋。"]'),
('0d6b34d0-d043-4fe4-8ebc-7c2ef6d5c547','讀後漢書二首  其一','陸游','宋','宋诗','song-poetry','','[]','賃舂老子吾所慕，垂世文章寧在多。',32,'全唐诗/poet.song.132000.json','["賃舂老子吾所慕，垂世文章寧在多。", "詩不刪來二千載，世間惟有五噫歌。"]'),
('71846ed6-8443-464b-afcb-39ec1508cfa0','讀後漢書二首  其二','陸游','宋','宋诗','song-poetry','','[]','季英行年九十八，猶灌園蔬授六經。',32,'全唐诗/poet.song.132000.json','["季英行年九十八，猶灌園蔬授六經。", "我欲圖之置齋壁，世無顧陸善丹青。"]'),
('1f4a5e5d-d89a-4430-a332-3bf59d8c0131','新裁道帽示帽工','陸游','宋','宋诗','song-poetry','','[]','故帽提携二十霜，別裁要作退居裝。',64,'全唐诗/poet.song.132000.json','["故帽提携二十霜，別裁要作退居裝。", "山人手段雖難及，老子頭圍未易量。", "花插露霑那暇惜，塵侵鼠嚙却須防。", "裹時懶復呼兒問，一匣菱花每在傍。"]'),
('a541355b-cdda-48c6-96fb-6bc8d56e7cbc','新製道衣示衣工','陸游','宋','宋诗','song-poetry','','[]','良工刀尺製黄絁，天遣家君樂聖時。',64,'全唐诗/poet.song.132000.json','["良工刀尺製黄絁，天遣家君樂聖時。", "著上朱門應不稱，裁成烏帽恰相宜。", "客撐小艇招垂釣，僧掃虛窗約對棋。", "寶带貂冠雖看好，定知不入野人詩。"]'),
('38a8c161-6aba-4234-8e40-4e6c742a2857','兩翁歌','陸游','宋','宋诗','song-poetry','','[]','君不見塞上失馬翁，馬去安知不爲福。',130,'全唐诗/poet.song.132000.json','["君不見塞上失馬翁，馬去安知不爲福。", "又不見新豐折臂翁，臂廢身全老鄉國。", "陸翁多難類兩翁，著書滿屋身愈窮。", "十年力耕遇水旱，老不能耕年始豐。", "人言翁窮可閔笑，霍食鶉衣天所料。", "翁方自謂實幸民，對人抱膝惟清嘯。", "即今群公佐明主，長劍拄頤來接武。", "向非老病又不才，縱欲歸休寧見許。"]'),
('1b7fda75-bd99-4ef1-8ffc-e6019861651b','五月中連夕風雨氣候如高秋枕上有賦','陸游','宋','宋诗','song-poetry','','[]','擁被微吟短鬢秋，孤燈殘漏共悠悠。',64,'全唐诗/poet.song.132000.json','["擁被微吟短鬢秋，孤燈殘漏共悠悠。", "雨聲不貸三更夢，酒力寧禁萬里愁。", "身寄湖山鄰剡曲，心遊河嶽過關頭。", "世間可恨知多少，虛弊當年季子裘。"]'),
('ce5cf00b-adb1-43d2-9c8b-6e633fd7645a','前詩感慨頗深猶吾前日之言也明日讀而悔之乃復作此然亦未能超然物外也','陸游','宋','宋诗','song-poetry','','[]','身世今如一老僧，病餘殘髮雪鬅鬙。',64,'全唐诗/poet.song.132000.json','["身世今如一老僧，病餘殘髮雪鬅鬙。", "湖桑埭下漁舟雨，道樹山前野店燈。", "澗水潺湲供洗鉢，松風蕭颯入行縢。", "世人欲覓何由得，覿面相逢喚不應。"]'),
('51a3a54c-01b1-4092-9337-ddd74233d004','雨後過近村','陸游','宋','宋诗','song-poetry','','[]','賦罷淵明歸去來，紵衣桐帽一時裁。',64,'全唐诗/poet.song.132000.json','["賦罷淵明歸去來，紵衣桐帽一時裁。", "歲華新筍初成竹，天氣停雲未斷梅。", "江路醉歸常嵬峨，僧窗閑過即徘徊。", "老人剩有凋年感，寄語城笳莫苦催。"]'),
('b66051c9-69d8-4b9e-bae9-6867ef36e82a','銘座','陸游','宋','宋诗','song-poetry','','[]','天下本無事，庸人實擾之。',96,'全唐诗/poet.song.132000.json','["天下本無事，庸人實擾之。", "吾身本無患，衛養在得宜。", "一毫不加謹，百疾所由滋。", "人生快意事，噬臍莫能追。", "汝顧不少忍，殺身常在斯。", "深居勿妄動，一動當百思。", "每食視本草，此意未可嗤。", "賦詩置座右，終身作元龜。"]'),
('a19bd3b3-db9b-4bac-ad9f-e413605e358f','致仕後述懷六首  其一','陸游','宋','宋诗','song-poetry','','[]','彈冠紹興末，解組慶元中。',48,'全唐诗/poet.song.132000.json','["彈冠紹興末，解組慶元中。", "灧澦危塗過，邯鄲幻境空。", "閑傳相牛法，醉挾鬭雞翁。", "衝雨歸來晚，山花滿笠紅。"]'),
('5b9679c1-61fa-4072-97be-0e0cde6abab4','致仕後述懷六首  其二','陸游','宋','宋诗','song-poetry','','[]','壯歲江湖去，還朝六十餘。',48,'全唐诗/poet.song.132000.json','["壯歲江湖去，還朝六十餘。", "輩流俱已盡，勳業固知疏。", "遽走寧黔突，長閑祇荷鋤。", "如今更何憾，終作愛吾廬。"]'),
('c434234b-7a82-45ef-8f9d-87a605eacbe4','致仕後述懷六首  其三','陸游','宋','宋诗','song-poetry','','[]','生理雖貧甚，胸中頗浩然。',48,'全唐诗/poet.song.132000.json','["生理雖貧甚，胸中頗浩然。", "常辭問字酒，屢却作碑錢。", "寧有駱堪鬻，尚無車可懸。", "小須梅雨霽，散髮醉江天。"]'),
('deb1a60f-97e5-45b3-a6d9-6e2d3f53ce4d','致仕後述懷六首  其四','陸游','宋','宋诗','song-poetry','','[]','昔自臺郎斥，頻年困負薪。',48,'全唐诗/poet.song.132000.json','["昔自臺郎斥，頻年困負薪。", "四叨優老祿，十送故鄉春。", "衰瘁寧知活，蕭條敢厭貧。", "惟思逢樂歲，擊壤學堯民。"]'),
('9e2d090b-2d4c-48a6-9613-dab7db4b6e34','致仕後述懷六首  其五','陸游','宋','宋诗','song-poetry','','[]','韋布還初服，蓬蒿卧故廬。',48,'全唐诗/poet.song.132000.json','["韋布還初服，蓬蒿卧故廬。", "所慚猶火食，更恨未巢居。", "叱叱驅黄犢，行行跨白驢。", "交親各强健，不必問何如。"]'),
('2dff34dd-cc59-4d3b-9280-59e5f6b46b74','致仕後述懷六首  其六','陸游','宋','宋诗','song-poetry','','[]','店店容賒酒，家家可乞漿。',48,'全唐诗/poet.song.132000.json','["店店容賒酒，家家可乞漿。", "白陂時雨足，綠樹午陰凉。", "病爲休官減，門緣謝客荒。", "今朝遇鄰叟，滿意說豐穰。"]'),
('22fc6d2d-a55f-4b83-89eb-9fe29eaae494','蝶','陸游','宋','宋诗','song-poetry','','[]','庭下幽花取次香，飛飛小蝶占年光。',32,'全唐诗/poet.song.132000.json','["庭下幽花取次香，飛飛小蝶占年光。", "幽人爲爾憑窗久，可愛深黄愛淺黄。"]'),
('dce3e5e9-5136-433b-b028-a810372185c6','戲贈酒榼','陸游','宋','宋诗','song-poetry','','[]','老去卧湖海，白髮朝朝新。',48,'全唐诗/poet.song.132000.json','["老去卧湖海，白髮朝朝新。", "賴有小道士，時來中聖人。", "形模雖簡古，風味絕清真。", "何當秋雨夕，傾倒見情親。"]'),
('b9632000-8ed6-4721-bf7e-9e857ce470d4','題庵壁二首  其一','陸游','宋','宋诗','song-poetry','','[]','破屋颼颼雀鼠穿，邇來四壁愈蕭然。',64,'全唐诗/poet.song.132000.json','["破屋颼颼雀鼠穿，邇來四壁愈蕭然。", "錢多孰謂可使鬼，人眾何嘗能勝天。", "禿尾驢遊雲外寺，長鬚奴引竹間泉。", "更餘一事猶當勉，讀易從今十絕編。"]'),
('5575018e-3f2b-4e63-9a73-a5324f7ac20e','題庵壁二首  其二','陸游','宋','宋诗','song-poetry','','[]','孤村寂寂潮生浦，小院昏昏雨送梅。',64,'全唐诗/poet.song.132000.json','["孤村寂寂潮生浦，小院昏昏雨送梅。", "蔬食一簞宜面槁，畏塗九折自心灰。", "古人骨朽有書在，今雨泥多無客來。", "散髮陽狂非寄傲，世間萬事本悠哉。"]'),
('d71d30fb-4c28-4ce6-8885-56e3d971ac05','泛舟澤中夜歸','陸游','宋','宋诗','song-poetry','','[]','無窮烟海接空濛，秦望稽山醉眼中。',64,'全唐诗/poet.song.132000.json','["無窮烟海接空濛，秦望稽山醉眼中。", "虹斷已收千嶂雨，鶴歸正駕九天風。", "漁舟容與橫沙際，水鳥號鳴傍葦叢。", "興盡還家忽三鼓，半輪殘月斗杓東。"]'),
('21cfd640-0cfb-49e5-a5e6-d020300c5411','書懶','陸游','宋','宋诗','song-poetry','','[]','此身不覺老侵尋，殘髮蕭蕭雪滿簪。',64,'全唐诗/poet.song.132000.json','["此身不覺老侵尋，殘髮蕭蕭雪滿簪。", "那有新詩書觸目，亦無閑話問安心。", "塞垣西戍茫如夢，省戶東歸病至今。", "一懶便知生世了，午窗酣枕敵千金。"]'),
('941c87f5-badd-4cbb-9493-d25ac47e6d66','晨起','陸游','宋','宋诗','song-poetry','','[]','清晨推枕起，盥面吾事足。',96,'全唐诗/poet.song.132000.json','["清晨推枕起，盥面吾事足。", "豈無掃灑役，出市待歸僕。", "小餐亦已省，尚進藥盈掬。", "整衣登北堂，危坐巾一幅。", "徐行梧楸陰，愛此雨餘綠。", "幽鳥東山來，鏘鳴若琴筑。", "靜聽興未闌，稚子報飯熟。", "欣然往從之，寧計食不肉。"]'),
('8eaad2cd-e46b-4912-b35d-98e4d10657f6','夜坐','陸游','宋','宋诗','song-poetry','','[]','仲夏苦鬰蒸，既夕熱未解。',96,'全唐诗/poet.song.132000.json','["仲夏苦鬰蒸，既夕熱未解。", "浴罷坐柴門，汲井痛掃灑。", "覆野天穹穹，垂地星磊磊。", "明河落無聲，北斗低飲海。", "三更缺月升，草木盡光彩。", "漁舟在何許，斷續聞欵乃。", "百憂集老境，坐歎雙鬢改。", "誰能擁雕戈，遺虜何足醢。"]'),
('692de48b-5c94-476a-a27f-b17d2ea48ffb','白樂天詩云倦倚繡床愁不動緩垂綠带髻鬟低遼陽春盡無消息夜合花前日又西好事者畫之爲倦繡圖此花以五六月開山中多于茨棘人殊不貴之爲賦小詩以寄感嘆','陸游','宋','宋诗','song-poetry','','[]','王室東遷歲月賒，兩京漠漠暗胡沙。',32,'全唐诗/poet.song.132000.json','["王室東遷歲月賒，兩京漠漠暗胡沙。", "繡床倦倚人何在，風雨漫山夜合花。"]'),
('8763a773-a405-465f-a0bc-2f9d5718b6f8','蜉蝣行','陸游','宋','宋诗','song-poetry','','[]','蜉蝣至細能知時，舂風磑雨占無遺。',64,'全唐诗/poet.song.132000.json','["蜉蝣至細能知時，舂風磑雨占無遺。", "蜻蜓滿空乃不知，庭除一出無歸期。", "樂哉蜻蜓高下飛，蜉蝣未盡何憂饑。", "簷間蜘蛛亦伺汝，吐絲織網腹如鼓。"]'),
('44999ac2-88fc-422a-8570-e26a480d54d4','望霽','陸游','宋','宋诗','song-poetry','','[]','夜雨勿厭空階聲，天公欲作明朝晴。',96,'全唐诗/poet.song.132000.json','["夜雨勿厭空階聲，天公欲作明朝晴。", "明朝甲子最畏雨，榜舟入市聞古語。", "今年雨暘俱及時，麥已入倉雲四垂。", "雨來不駛亦不遲，大點如菽細如絲。", "徐徐雲開見杲日，晚禾吹花早禾實。", "但令有米送官倉，豆飯藜羹甘似蜜。"]'),
('39500963-fee2-4f25-b78b-6724b3305c62','久雨路斷朋舊有相過者皆不能進','陸游','宋','宋诗','song-poetry','','[]','今年風雨多，平陸成沮洳。',96,'全唐诗/poet.song.132000.json','["今年風雨多，平陸成沮洳。", "吾廬地尤下，積水環百步。", "客從城市來，熟視却復去。", "僮奴笑欲倒，繖屐知無路。", "計其各還家，對竈燎衣袴。", "嗟予久退藏，蓬藋生庭戶。", "誰如數子賢，裹飯肯來顧。", "清言雖不接，亦足慰遲暮。"]'),
('bfb1d3a8-fa10-447d-bcfa-51bed07bd155','散步至三家村','陸游','宋','宋诗','song-poetry','','[]','人情簡朴古風存，暮過三家水際村。',64,'全唐诗/poet.song.132000.json','["人情簡朴古風存，暮過三家水際村。", "見說終年常閉戶，仍聞累世自通婚。", "罾船歸處魚餐美，社甕香時黍酒渾。", "記取放翁扶杖處，渚蒲烟草溼黄昏。"]'),
('a1d7e8b1-85d8-4537-9ec5-8e0bc53f7a76','村東晚眺二首  其一','陸游','宋','宋诗','song-poetry','','[]','興來信步過東陂，最愛村東物象奇。',64,'全唐诗/poet.song.132000.json','["興來信步過東陂，最愛村東物象奇。", "藤杖穿雲秋望處，葛衣霑露夜歸時。", "殘聲凄斷蟬移樹，孤影荒寒鵲繞枝。", "自揣今年還得飽，一川新稻已離離。"]'),
('323c18cb-0745-4b64-ac3a-6bc8749eaf8c','村東晚眺二首  其二','陸游','宋','宋诗','song-poetry','','[]','飽食無營過暮年，筇枝到處一蕭然。',64,'全唐诗/poet.song.132000.json','["飽食無營過暮年，筇枝到處一蕭然。", "清秋欲近露霑草，新月未高星滿天。", "遠火微茫沽酒市，叢蒲窸窣釣魚船。", "哦詩每恨工夫少，又廢西窗半夜眠。"]'),
('bdaef5f2-e0d6-47f1-b240-f760aa586b1f','露坐二首  其一','陸游','宋','宋诗','song-poetry','','[]','星稀避月明，河白映天青。',48,'全唐诗/poet.song.132000.json','["星稀避月明，河白映天青。", "入夜蟬逾急，先秋葉自零。", "花枝栖露蝶，簾罅度風螢。", "欲喚鄰翁坐，漁舟醉不醒。"]'),
('5c832548-ea93-4189-a78f-1338137aeee8','露坐二首  其二','陸游','宋','宋诗','song-poetry','','[]','落月無留照，殘河亦已傾。',48,'全唐诗/poet.song.132000.json','["落月無留照，殘河亦已傾。", "墜枝雙鵲裊，黏草一螢明。", "暑令忘三伏，凉颼逼五更。", "爲憐荷瀉露，故起繞池行。"]'),
('d569a484-4a9c-48de-bf1c-b4cedef10a14','致仕後歲事有望欣然賦詩','陸游','宋','宋诗','song-poetry','','[]','聖時恩厚賜餘生，日與鄉閭樂太平。',64,'全唐诗/poet.song.132000.json','["聖時恩厚賜餘生，日與鄉閭樂太平。", "已棄胡床無長物，尚携拄杖有同行。", "新裁烏帽人爭看，小摘青蔬手自烹。", "買得水車無用處，絕知造物相歸耕。"]'),
('86b7f38e-2da9-4784-8d48-340095f6ef81','夜聞姑惡','陸游','宋','宋诗','song-poetry','','[]','湖橋東西斜月明，高城漏鼓傳三更。',96,'全唐诗/poet.song.132000.json','["湖橋東西斜月明，高城漏鼓傳三更。", "釣船夜過掠沙際，蒲葦蕭蕭姑惡聲。", "湖橋南北烟雨昏，兩岸人家早閉門。", "不知姑惡何所恨，時時一聲能斷魂。", "天地大矣汝至微，滄波本自無危機。", "秋菰有米亦可飽，哀哀如此將安歸。"]'),
('02f7500f-e167-475f-b8f9-9b07caed4447','村舍雜書十二首  其一','陸游','宋','宋诗','song-poetry','','[]','我本杞菊家，桑苧亦吾宗。',48,'全唐诗/poet.song.132000.json','["我本杞菊家，桑苧亦吾宗。", "種藝日成列，喜過萬戶封。", "今年夏雨足，不復憂螟蟲。", "歸耕殆有相，所願天輒從。"]'),
('a796b633-bbdd-48ab-964f-f8bce626fdfd','村舍雜書十二首  其二','陸游','宋','宋诗','song-poetry','','[]','中春農在野，蠶事亦隨作。',48,'全唐诗/poet.song.132000.json','["中春農在野，蠶事亦隨作。", "手種臨安青，可飼蠶百箔。", "累累繭滿簇，繹繹絲上篗。", "老子雖安眠，衣帛可無怍。"]'),
('0e07a8c6-99e7-4bbe-8044-47b8ee1d2d40','村舍雜書十二首  其三','陸游','宋','宋诗','song-poetry','','[]','舍北作蔬圃，敢辭灌溉勞。',48,'全唐诗/poet.song.132000.json','["舍北作蔬圃，敢辭灌溉勞。", "輪囷瓜瓠熟，珍愛敵豚羔。", "晨餐戒厨人，全項凈去毛。", "雖云發客笑，亦足慰老饕。"]'),
('f87a9100-7cdf-46c0-85c1-8be7e8cb4a91','村舍雜書十二首  其四','陸游','宋','宋诗','song-poetry','','[]','舍南種胡麻，三日幸不雨。',48,'全唐诗/poet.song.132000.json','["舍南種胡麻，三日幸不雨。", "晨起親按行，已見青覆土。", "窮人如意少，喜色漏眉宇。", "兒童勿惰偷，造物不負汝。"]'),
('6d52d991-c8c0-4733-a803-ddda47afef36','村舍雜書十二首  其五','陸游','宋','宋诗','song-poetry','','[]','五月新麫成，六月甘瓜熟。',48,'全唐诗/poet.song.132000.json','["五月新麫成，六月甘瓜熟。", "作麴及良時，火見金始伏。", "懸知桑落後，醅面醲如粥。", "再拜謝天公，無功叨美祿。"]'),
('985b4e3b-a275-4be6-a4d1-552df83022d8','村舍雜書十二首  其六','陸游','宋','宋诗','song-poetry','','[]','折蓮釀作醯，采豆治作醬。',48,'全唐诗/poet.song.132000.json','["折蓮釀作醯，采豆治作醬。", "開曆揆日時，汲井滌甕盎。", "上奉時祭須，下給春耕餉。", "咨爾後之人，歲事不可曠。"]'),
('d6bc33e3-e055-4b78-b731-1afb79c6cbde','村舍雜書十二首  其七','陸游','宋','宋诗','song-poetry','','[]','東山石上茶，鷹爪初脫韝。',48,'全唐诗/poet.song.132000.json','["東山石上茶，鷹爪初脫韝。", "雪落紅絲磑，香動銀毫甌。", "爽如聞至言，餘味終日留。", "不知葉家白，亦復有此不。"]'),
('dbe62da8-54f3-4e65-a606-c5744a0bbc24','村舍雜書十二首  其八','陸游','宋','宋诗','song-poetry','','[]','逢人乞藥栽，鬰鬰遂滿園。',48,'全唐诗/poet.song.132000.json','["逢人乞藥栽，鬰鬰遂滿園。", "玉芝來天姥，黄精出雲門。", "丹茁雨後吐，綠葉風中翻。", "活人吾豈能，要有此意存。"]'),
('038e40a5-882c-4c5a-ac65-3023c2630eda','村舍雜書十二首  其九','陸游','宋','宋诗','song-poetry','','[]','我居大澤中，一舟不可無。',48,'全唐诗/poet.song.132000.json','["我居大澤中，一舟不可無。", "短篷挾兩槳，疾若波中鳧。", "來往菰蘆村，案行瓜芋區。", "浮家亦可樂，何必愛吾廬。"]'),
('21e586ac-790b-404a-a425-a4312d23f677','村舍雜書十二首  其一○','陸游','宋','宋诗','song-poetry','','[]','軍興尚戎衣，冠带謝褒博。',48,'全唐诗/poet.song.132000.json','["軍興尚戎衣，冠带謝褒博。", "禿巾與小袖，顧影每懷怍。", "及今反士服，始覺榮天爵。", "出入阡陌間，終身有餘樂。"]'),
('08893fbb-f030-4f9d-9c7f-c74d96bf4b4e','村舍雜書十二首  其一一','陸游','宋','宋诗','song-poetry','','[]','讀書乃一癖，我亦不自知。',48,'全唐诗/poet.song.132000.json','["讀書乃一癖，我亦不自知。", "坐書窮至老，更欲傳吾兒。", "吾兒復當傳，百世以爲期。", "君看北山公，太行尚可移。"]'),
('9d170a13-93c2-4d77-bc0c-a691f0a27201','村舍雜書十二首  其一二','陸游','宋','宋诗','song-poetry','','[]','爵祿九鼎重，名義一羽輕。',48,'全唐诗/poet.song.132000.json','["爵祿九鼎重，名義一羽輕。", "人見共如此，吾道何由行。", "湖山有一士，無人知姓名。", "時時風月夕，遥聞清嘯聲。"]'),
('1a365da4-740d-4755-b6e7-c3ecfa34bb0d','逃暑小飲熟睡至暮二首  其一','陸游','宋','宋诗','song-poetry','','[]','桑落香浮槲葉杯，甘瓜綠李亦佳哉。',64,'全唐诗/poet.song.132000.json','["桑落香浮槲葉杯，甘瓜綠李亦佳哉。", "虛堂頓解汗揮雨，高枕俄成鼻殷雷。", "靜聽風聲生檻竹，徐看日影轉庭槐。", "晚凉更動扁舟興，北渚紅蕖已半開。"]'),
('f36f6e22-7d28-4fb8-a896-83640f7c301b','逃暑小飲熟睡至暮二首  其二','陸游','宋','宋诗','song-poetry','','[]','槐影桐陰欲滿廊，綸巾羽扇自生凉。',64,'全唐诗/poet.song.132000.json','["槐影桐陰欲滿廊，綸巾羽扇自生凉。", "新篘玉瀣陳雙榼，平展風漪可一床。", "馳騎遠分丹荔到，大盆寒浸碧瓜香。", "湖邊誰謂幽居陋，也愛迢迢夏日長。"]'),
('b14cf1c8-bfc1-4883-82ef-73f13ab45e3d','夜坐庭中達旦','陸游','宋','宋诗','song-poetry','','[]','老矣常嗟去日遒，病來更覺此生浮。',64,'全唐诗/poet.song.132000.json','["老矣常嗟去日遒，病來更覺此生浮。", "庭花舞影月當午，簷樹有聲風報秋。", "足倦獨行驚踸踔，髮稀久坐怯颼飀。", "雞號日出閑無事，又向清溪弄釣舟。"]'),
('4347d787-92bf-43fc-9175-d0c4d0e8c1fa','讀前輩詩文有感','陸游','宋','宋诗','song-poetry','','[]','我無前輩千鈞筆，造物爭功謝不能。',64,'全唐诗/poet.song.132000.json','["我無前輩千鈞筆，造物爭功謝不能。", "已分文章歸委靡，可憐意氣尚憑陵。", "鸞旗廣殿晨排仗，鐵馬黄河夜踏冰。", "此事要須推大手，蟬嘶分付與吳僧。"]'),
('b74b765d-f763-4d85-838e-dbb04b95ad9f','自嘲','陸游','宋','宋诗','song-poetry','','[]','天公大度一何奇，養此無能老白癡。',64,'全唐诗/poet.song.132000.json','["天公大度一何奇，養此無能老白癡。", "宿疾閑愁俱掃盡，美餐甘寢更無時。", "蛙鳴庭草何曾問，水半門扉亦不知。", "道似嬰兒猶有恨，小軒風月獨哦詩。"]'),
('1373adb4-e576-4781-b74e-14fd665790ab','余讀元次山與瀼溪鄰里詩意甚愛之取其間四句各作一首亦以示予幽居鄰里 峰谷互回映','陸游','宋','宋诗','song-poetry','','[]','北起成孤峰，東蟠作幽谷。',72,'全唐诗/poet.song.132000.json','["北起成孤峰，東蟠作幽谷。", "中有十餘家，蘆藩映茆屋。", "土肥桑柘茂，雨飽麻豆熟。", "比鄰通有無，井稅先期足。", "烟中語相答，月下歌相續。", "兒童不識字，未必非汝福。"]'),
('36c4c8e9-f591-472e-9b43-626cd6a078ff','余讀元次山與瀼溪鄰里詩意甚愛之取其間四句各作一首亦以示予幽居鄰里 誰家無泉源','陸游','宋','宋诗','song-poetry','','[]','泉聲百步聞，泉脈高下通。',72,'全唐诗/poet.song.132000.json','["泉聲百步聞，泉脈高下通。", "潺湲亂雲外，屈曲明月中。", "八月稻登場，引之作機舂。", "羨流灌蔬畦，全家飽芥菘。", "洗沐及澣濯，蚤暮靡不供。", "斗水百憂寬，悲哉杜陵翁。"]'),
('650ddd19-2d0a-462b-b80b-d220f9834c88','余讀元次山與瀼溪鄰里詩意甚愛之取其間四句各作一首亦以示予幽居鄰里 夾路多修行','陸游','宋','宋诗','song-poetry','','[]','黄茆持覆屋，溪石運作垣。',72,'全唐诗/poet.song.132000.json','["黄茆持覆屋，溪石運作垣。", "桑麻有餘地，家家養龍孫。", "春雷初起蟄，切玉供盤餐。", "一朝解風籜，靉霴蒼雲屯。", "我來倚拄杖，恐是辟疆園。", "千畝倘可致，封君何足言。"]'),
('075621a3-f844-4167-b03e-476cf03f98e8','余讀元次山與瀼溪鄰里詩意甚愛之取其間四句各作一首亦以示予幽居鄰里 扁舟皆到門','陸游','宋','宋诗','song-poetry','','[]','千錢買輕舟，不復從人借。',72,'全唐诗/poet.song.132000.json','["千錢買輕舟，不復從人借。", "樵蘇晨入市，鹽酪夕還舍。", "豈惟載春秧，亦足穫秋稼。", "有時醉村場，老稚相枕藉。", "常侵落月行，不畏惡風嚇。", "無爲詫軒車，此樂予豈暇。"]'),
('dacd1c04-9db2-4d26-973f-183da90ddcaa','東山避暑用轆轤體','陸游','宋','宋诗','song-poetry','','[]','避暑穿林隨所之，一奴每負胡床隨。',64,'全唐诗/poet.song.132000.json','["避暑穿林隨所之，一奴每負胡床隨。", "望秋槁葉有先隕，未暮赫日無餘暉。", "輪囷離奇澗松古，鈎輈格磔蠻禽悲。", "北巖竹間最慘慄，清嘯倚石真忘歸。"]'),
('b5d4d953-7e0a-4759-9b57-e5f7786ccbb0','喜雨','陸游','宋','宋诗','song-poetry','','[]','去年禹廟歸梅梁，今年黑虹見東方。',128,'全唐诗/poet.song.132000.json','["去年禹廟歸梅梁，今年黑虹見東方。", "巫言當豐十二歲，父老相告喜欲狂。", "插秧正得十日雨，高下到處水滿塘。", "六月欲盡日杲杲，造物已命摧驕陽。", "夕雲如豚渡河漢，占書共謂雨至祥。", "南山雷車載膏澤，枕上忽送聲淋浪。", "猛思濁酒大作社，更想紅稻初迎霜。", "六十日白最先熟，食新且領晨炊香。"]'),
('0a02fde0-82b5-44bd-acfa-a7fe8daa97a1','得故人書偶題','陸游','宋','宋诗','song-poetry','','[]','小筑稽山下，狂歌剡曲傍。',48,'全唐诗/poet.song.132000.json','["小筑稽山下，狂歌剡曲傍。", "鄉鄰共雞黍，童稚學農桑。", "白首餘年促，青編後日長。", "此心誰復謀，三嘆付書囊。"]'),
('e44f2dd6-f7e0-4f8d-ae06-0e6ea5d155ee','喜雨歌','陸游','宋','宋诗','song-poetry','','[]','不雨珠，不雨玉，六月得雨真雨粟。',64,'全唐诗/poet.song.132000.json','["不雨珠，不雨玉，六月得雨真雨粟。", "十年水旱食半菽，民伐桑柘賣黄犢。", "去年小稔已食足，今年當得厭酒肉。", "斯民醉飽定復哭，幾人不見今年熟。"]'),
('90feebd2-e54b-4bf3-81cc-616f7011986a','老學庵井','陸游','宋','宋诗','song-poetry','','[]','老學庵北井，六月寒如冰。',110,'全唐诗/poet.song.132000.json','["老學庵北井，六月寒如冰。", "大旱不涸雨不增，凜如人以常德稱。", "日濟千人不驕矜，置而不汲渠自澄。", "轆轤三丈青絲繩，對之已足凉肺膺。", "使我終日卧曲肱，顧謂此井真良朋。", "蕩除炎歊却塵垢，宜有鬼神來護守。", "嗚呼涇水一石泥數斗，正使逢時亦何有。"]'),
('f608c6fe-ac80-4812-9f26-189de4b1fac5','長歌行','陸游','宋','宋诗','song-poetry','','[]','我無四目與兩口，但在人間更事久。',96,'全唐诗/poet.song.132000.json','["我無四目與兩口，但在人間更事久。", "死生元是開闔眼，禍福正如翻覆手。", "消磨日月幾緉屐，陶鑄唐虞一杯酒。", "既非狗馬要蓋帷，那計風霜悴蒲柳。", "竈突無烟今又慣，龜蟬與我成三友。", "判知青史無功名，只用忍饑垂不朽。"]'),
('37893557-ea46-44db-a42f-80e409e0a3f9','七月二日夜賦','陸游','宋','宋诗','song-poetry','','[]','鄙人志趨在漁樵，四十年來負聖朝。',64,'全唐诗/poet.song.132000.json','["鄙人志趨在漁樵，四十年來負聖朝。", "本耻彈冠良易挂，未嘗刻印敢煩銷。", "盈盈微月生江渚，嫋嫋清笳下郡譙。", "衰病逢秋真一洗，井牀桐葉已先飄。"]'),
('edbeffac-05a4-453c-90dc-a2987500ac7e','自述二首  其一','陸游','宋','宋诗','song-poetry','','[]','二畝新蔬圃，三間舊草堂。',48,'全唐诗/poet.song.132000.json','["二畝新蔬圃，三間舊草堂。", "病除身小健，秋近夜微凉。", "薄酒時醒醉，殘書半在亡。", "老懷常自笑，無事忽悲傷。"]'),
('6b73a325-4fea-4a10-9496-a55a6575cd7e','自述二首  其二','陸游','宋','宋诗','song-poetry','','[]','睡美不知旦，氣衰先覺秋。',48,'全唐诗/poet.song.132000.json','["睡美不知旦，氣衰先覺秋。", "有時浮小艇，隨意宿滄洲。", "未恨名風漢，惟求拜醉侯。", "更須多種竹，搔首送悠悠。"]'),
('f6286795-90d6-4795-b7f3-d275474162f7','項羽','陸游','宋','宋诗','song-poetry','','[]','八尺將軍千里騅，拔山扛鼎不妨奇。',32,'全唐诗/poet.song.132000.json','["八尺將軍千里騅，拔山扛鼎不妨奇。", "范增力盡無施處，路到烏江君自知。"]'),
('94307bcd-6f46-40c9-a298-3345c9b4e110','曹公','陸游','宋','宋诗','song-poetry','','[]','二袁劉表笑談無，眼底英雄不足圖。',32,'全唐诗/poet.song.132000.json','["二袁劉表笑談無，眼底英雄不足圖。", "赤壁歸來應歎息，人間更有一周瑜。"]'),
('fb4bca02-7a65-40ab-88d0-096d7d9ff1c5','夜雨','陸游','宋','宋诗','song-poetry','','[]','濃雲如潑墨，急雨如飛鏃。',96,'全唐诗/poet.song.132000.json','["濃雲如潑墨，急雨如飛鏃。", "激電光入牖，奔雷勢掀屋。", "漏溼恐敗書，起視自秉燭。", "移併顧未暇，盆盎苦不足。", "不如卷茵席，少忍待其復。", "飛螢方得意，熠熠相追逐。", "姑惡獨何怨，菰叢聲若哭。", "吾歌亦已悲，老死終碌碌。"]'),
('11da9981-180c-4746-acde-3ae39ad7676d','昔人有畫醉僧醉道士醉學究者皆見于傳記及歌詩中予暇日爲各賦一首 醉僧','陸游','宋','宋诗','song-poetry','','[]','殘雪覆枯顱，手扶短楖栗。',56,'全唐诗/poet.song.132000.json','["殘雪覆枯顱，手扶短楖栗。", "送酒無蘇州，一醉未易得。", "青旗獵獵秋風吹，長瓶一吸亦足奇。", "但辦道傍常醉倒，不須解作藏真草。"]'),
('4b874b41-e56a-4a1c-bb54-1ced784c2342','昔人有畫醉僧醉道士醉學究者皆見于傳記及歌詩中予暇日爲各賦一首 醉道士','陸游','宋','宋诗','song-poetry','','[]','落托在人間，經旬不火食。',56,'全唐诗/poet.song.132000.json','["落托在人間，經旬不火食。", "醉後上江樓，橫吹蒼玉笛。", "大口如盆眼如電，九十老人從小見。", "曾携一鶴過岳陽，滿城三日聞酒香。"]'),
('70a290de-d596-4acc-b235-9e7c6eb00b7b','昔人有畫醉僧醉道士醉學究者皆見于傳記及歌詩中予暇日爲各賦一首 醉學究','陸游','宋','宋诗','song-poetry','','[]','聖師飲百觚，儼然常齋莊。',56,'全唐诗/poet.song.132000.json','["聖師飲百觚，儼然常齋莊。", "弟子習禮餘，兕觥躋公堂。", "至今遺風被洙泗，諸生雅歌老儒醉。", "衣冠簡朴未可輕，安知中無魯二生。"]'),
('205a6f56-98bd-4628-8bab-eb70da6e34e9','次季長韵回寄','陸游','宋','宋诗','song-poetry','','[]','野人蓬戶冷如霜，問訊今惟一季長。',64,'全唐诗/poet.song.132000.json','["野人蓬戶冷如霜，問訊今惟一季長。", "舊好自均親骨肉，新知何怪薄心腸。", "開書字字論疇昔，遣使年年有故常。", "萬念知公掃除盡，見哀底事獨難忘。"]'),
('2a9d4465-1dd8-45ac-9a5f-6de10e73c60f','溪上小酌','陸游','宋','宋诗','song-poetry','','[]','岸幘出籬門，投竿俯溪瀨。',48,'全唐诗/poet.song.132000.json','["岸幘出籬門，投竿俯溪瀨。", "魚聚忽千百，鳥鳴時一再。", "新凉杜甕香，亦有雉兔賣。", "歡言洗杯酌，又破止酒戒。"]'),
('73872344-f849-4af5-b0cd-9f1276b2000f','齋中夜賦','陸游','宋','宋诗','song-poetry','','[]','高居終日掩齋扉，幽事常多俗事稀。',64,'全唐诗/poet.song.132000.json','["高居終日掩齋扉，幽事常多俗事稀。", "露重叢篁時自瀉，風高脫葉有先飛。", "秋衣漸製聞砧杵，社肉初分謝蕨薇。", "却笑老身閑不得，一燈明滅亂書圍。"]'),
('57c128b3-a4af-4f78-bf41-af6d54f40184','讀舊稿有感','陸游','宋','宋诗','song-poetry','','[]','我少則嗜書，于道本無得。',120,'全唐诗/poet.song.132000.json','["我少則嗜書，于道本無得。", "譬如昌歜芰，乃自性一癖。", "老來百事廢，惟此尚自力。", "豈惟絕慶吊，乃至忘寢食。", "吟哦雜誦詠，不覺日既夕。", "文辭顧淺懦，望古空太息。", "世俗不可解，更爲著金石。", "收斂固已遲，雖悔終何益。", "君看老農夫，法亦傳后稷。", "持此少自寬，陶然送餘日。"]'),
('918a512d-2eb7-4174-a63d-159a60a4d730','新秋','陸游','宋','宋诗','song-poetry','','[]','秋氣入清笳，旗亭酒可賒。',48,'全唐诗/poet.song.132000.json','["秋氣入清笳，旗亭酒可賒。", "長歌穿小市，短帽插幽花。", "溪女留新蟹，園公餉晚瓜。", "誰知閑老子，解作醉生涯。"]'),
('22bb3f72-7a3c-4842-803c-31bdfb9560c0','陳阜卿先生爲兩浙轉運司考試官時秦丞相孫以右文殿修撰來就試直欲首送阜卿得予文卷擢置第一秦氏大怒予明年既顯黜先生亦幾蹈危機偶秦公薨遂已予晚歲料理故書得先生手帖追感平昔作長句以識其事不知衰涕之集也','陸游','宋','宋诗','song-poetry','','[]','冀北當年浩莫分，斯人一顧每空群。',64,'全唐诗/poet.song.132000.json','["冀北當年浩莫分，斯人一顧每空群。", "國家科第與風漢，天下英雄惟使君。", "後進何人知大老，橫流無地寄斯文。", "自憐衰鈍辜真賞，猶竊虛名海內聞。"]'),
('522df80f-39c9-4419-9b6f-8d67e9d63dd5','書喜二首  其一','陸游','宋','宋诗','song-poetry','','[]','乞得身歸鏡水濱，此生真作葛天民。',64,'全唐诗/poet.song.132000.json','["乞得身歸鏡水濱，此生真作葛天民。", "眼明身健何妨老，飯白茶甘不覺貧。", "甕酒又篘三斗熟，園花時報一枝新。", "挂冠更作黄冠計，多事常嫌賀季真。"]'),
('008ccdaa-0cd7-41c0-a62b-c7143167c192','書喜二首  其二','陸游','宋','宋诗','song-poetry','','[]','已向烟霞著脚深，世間萬事不關心。',64,'全唐诗/poet.song.132000.json','["已向烟霞著脚深，世間萬事不關心。", "舊携鴉觜供鉏藥，新典魚須用買琴。", "井上引藤初滿架，池南移竹漸成陰。", "話行不必須今日，五百年間有賞音。"]'),
('c54508f1-6063-471c-a0a8-e3c89e9d8a58','幽居','陸游','宋','宋诗','song-poetry','','[]','萬家水竹古山陰，揀得幽居愜素心。',64,'全唐诗/poet.song.132000.json','["萬家水竹古山陰，揀得幽居愜素心。", "梁燕委巢知社近，井桐飄葉覺秋深。", "琴緣廢久塵常積，書爲開稀蠹漸侵。", "幸自杜門無一事，不須清夜感衣砧。"]'),
('84fe4783-55cc-452c-b5d8-cf3e51c96de0','雜興四首  其一','陸游','宋','宋诗','song-poetry','','[]','病養精神過服藥，貧知儉約勝營生。',32,'全唐诗/poet.song.132000.json','["病養精神過服藥，貧知儉約勝營生。", "皋夔事業今何有，且與心君致太平。"]'),
('bcfe109e-8d2a-4bfc-8cfa-90540732c922','雜興四首  其二','陸游','宋','宋诗','song-poetry','','[]','東家飯牛月未落，西家打稻雞初鳴。',32,'全唐诗/poet.song.132000.json','["東家飯牛月未落，西家打稻雞初鳴。", "老翁高枕葛幮裏，炊飯熟時猶鼾聲。"]'),
('a33c3d59-fee2-4f9f-bb8e-f0151a7e7758','雜興四首  其三','陸游','宋','宋诗','song-poetry','','[]','暮年常苦睡爲祟，好事新分安樂茶。',32,'全唐诗/poet.song.132000.json','["暮年常苦睡爲祟，好事新分安樂茶。", "更得小瓢吾事足，山家風味似僧家。"]'),
('e983519f-ec8b-4eb1-b85f-8718b664a359','雜興四首  其四','陸游','宋','宋诗','song-poetry','','[]','蛟鰐垂涎歷畏塗，如今歡喜去携鋤。',32,'全唐诗/poet.song.132000.json','["蛟鰐垂涎歷畏塗，如今歡喜去携鋤。", "一生患難休回首，疋似元符曾上書。"]'),
('45a87aad-bc36-4b2f-aec1-198ddc60b378','贈鷺','陸游','宋','宋诗','song-poetry','','[]','雪衣飛去莫匆匆，小住灘前伴釣篷。',32,'全唐诗/poet.song.132000.json','["雪衣飛去莫匆匆，小住灘前伴釣篷。", "禹廟蘭亭三十里，相逢多在暮烟中。"]'),
('706982d9-10fb-4f81-9a13-60aa4d855895','贈鵲','陸游','宋','宋诗','song-poetry','','[]','爲梁星渚自何年，毛羽摧傷不怨天。',32,'全唐诗/poet.song.132000.json','["爲梁星渚自何年，毛羽摧傷不怨天。", "知我齋餘常施食，翩然飛下北窗前。"]'),
('760a5ea1-9052-4bae-a091-56f9a92b64e7','東堂睡起','陸游','宋','宋诗','song-poetry','','[]','置身事外息吾黥，獨卧空堂一榻橫。',64,'全唐诗/poet.song.132000.json','["置身事外息吾黥，獨卧空堂一榻橫。", "簷影漸移知日轉，樹梢微動覺風生。", "每從山寺開經帙，間就園公辨藥名。", "若論胸中淡無事，八珍何得望藜羹。"]'),
('e8a7ff26-8639-4d3a-ac5b-49cd32f10ec5','五鼓起坐待旦','陸游','宋','宋诗','song-poetry','','[]','睡覺初聞雞一鳴，披衣危坐待窗明。',64,'全唐诗/poet.song.132000.json','["睡覺初聞雞一鳴，披衣危坐待窗明。", "殘軀已向閑中老，癡夢猶尋熟處行。", "南北迢迢悲往事，古今莽莽嘆浮生。", "伯倫一鍤君休笑，冢象祁連亦已平。"]'),
('bec6ce7a-824a-413b-b917-5537b83c7cbb','功名','陸游','宋','宋诗','song-poetry','','[]','少年妄意慕功名，老眼看來一髮輕。',64,'全唐诗/poet.song.132000.json','["少年妄意慕功名，老眼看來一髮輕。", "金甲雖如朝邑尉，羊裘終愧富春生。", "連娟落月依山盡，寂寞寒潮蘸岸平。", "要識放翁新得意，蓼花多處釣舟橫。"]'),
('6137d482-1cdd-4c61-b2f4-9a880f028470','搔首','陸游','宋','宋诗','song-poetry','','[]','玩畫無餘易，聞歌已盡詩。',48,'全唐诗/poet.song.132000.json','["玩畫無餘易，聞歌已盡詩。", "古人不可作，此理孰能推。", "白髮秋風裏，青燈夜雨時。", "初心竟當負，搔首嘆吾衰。"]'),
('4451ce06-9474-416c-b077-d42f11ce12e9','小雨釣歸','陸游','宋','宋诗','song-poetry','','[]','雨點鳴叢葦，雲頭冒遠山。',48,'全唐诗/poet.song.132000.json','["雨點鳴叢葦，雲頭冒遠山。", "兒曹出籬望，老子榜舟還。", "潤入園畦裏，凉生窗戶間。", "秋陽方可畏，徙倚一開顔。"]'),
('739f0fbc-9d8d-4809-a1b0-b228dd885140','曉賦','陸游','宋','宋诗','song-poetry','','[]','八月江湖風露秋，時聞脫葉下梧楸。',64,'全唐诗/poet.song.132000.json','["八月江湖風露秋，時聞脫葉下梧楸。", "離離斗柄西南指，爛爛天河今古流。", "人語正讙過古埭，角聲三弄下譙樓。", "百城已共豐年樂，一老猶懷卒歲憂。"]'),
('2defe4b8-6b5f-4f71-85a3-e83f30041694','急雨','陸游','宋','宋诗','song-poetry','','[]','雲從西南興，風自東北至。',72,'全唐诗/poet.song.132000.json','["雲從西南興，風自東北至。", "老農占雨候，速若屈伸臂。", "亂點俄打窗，新凉已生袂。", "經旬苦肺渴，得此亦少慰。", "呼兒持故襦，買酒具一醉。", "薄言煮園蔬，雉兔未可議。"]'),
('c0c42f7c-b6cc-465d-b2d3-412a6715bcdd','遣興四首  其一','陸游','宋','宋诗','song-poetry','','[]','幾看人間歲月新，釣船猶繫鏡湖濱。',64,'全唐诗/poet.song.132000.json','["幾看人間歲月新，釣船猶繫鏡湖濱。", "曾穿高帝朝元仗，却作山陰版籍民。", "留病三分嫌太健，忍饑半日未全貧。", "早知晝繡能爲祟，翁子終身合負薪。"]'),
('7d1ba61e-47f8-4d0c-b331-8cfbc8cd7886','遣興四首  其二','陸游','宋','宋诗','song-poetry','','[]','湖海元爲汗漫遊，誤恩四領幔亭秋。',64,'全唐诗/poet.song.132000.json','["湖海元爲汗漫遊，誤恩四領幔亭秋。", "掃空薄祿始無愧，閉上衡門那得愁。", "湯嫩雪濤翻茗碗，火溫香縷上衣篝。", "床頭亦有閑書卷，信手拈來倦即休。"]'),
('27e6e395-8e74-494e-925a-3e05bcbe92f2','遣興四首  其三','陸游','宋','宋诗','song-poetry','','[]','掃盡衣塵喜不勝，村居終日醉騰騰。',64,'全唐诗/poet.song.132000.json','["掃盡衣塵喜不勝，村居終日醉騰騰。", "閑投鄰父祈神社，戲入群兒鬭草朋。", "幽徑有風偏愛竹，虛堂無暑不憎蠅。", "悠然又見江天晚，隔浦人家已上燈。"]'),
('aec7ba32-5e60-40ad-8131-00042ae39710','遣興四首  其四','陸游','宋','宋诗','song-poetry','','[]','久矣微官絆此身，柴車歸老亦逢辰。',64,'全唐诗/poet.song.132000.json','["久矣微官絆此身，柴車歸老亦逢辰。", "阮咸卧摘孤風在，白墮閑傾一笑新。", "萬里馳驅曾遠戍，六朝涵養忝遺民。", "清閑即是桃源境，常笑淵明欲問津。"]'),
('fcf24bbc-d248-40bc-8ed5-776b1c5ae499','讀林逋魏野二處士詩','陸游','宋','宋诗','song-poetry','','[]','君復仲先真隱淪，筆端亦自斡千鈞。',32,'全唐诗/poet.song.132000.json','["君復仲先真隱淪，筆端亦自斡千鈞。", "閑中一句終難道，何况市朝名利人。"]'),
('e131b4d0-6138-4f5d-91ca-87d758d59509','紙墨皆漸竭戲作','陸游','宋','宋诗','song-poetry','','[]','官庫誰能餉陟釐，漢宮無復賜隃麋。',32,'全唐诗/poet.song.132000.json','["官庫誰能餉陟釐，漢宮無復賜隃麋。", "不如掃盡書生事，閑伴兒童竹馬嬉。"]'),
('ed0ba26f-790f-48fe-b10a-dca46d366cc5','讀隱逸傳','陸游','宋','宋诗','song-poetry','','[]','終南處士入都門，少室山人補諫垣。',32,'全唐诗/poet.song.132000.json','["終南處士入都門，少室山人補諫垣。", "畢竟只供千載笑，石封三品鶴乘軒。"]'),
('db9afc2a-42a4-4715-a3ba-1d6fa1887589','泛舟至東村','陸游','宋','宋诗','song-poetry','','[]','野水如天遠，漁舟似葉輕。',48,'全唐诗/poet.song.132000.json','["野水如天遠，漁舟似葉輕。", "颼颼風漸冷，淡淡月初生。", "沙際樵蘇路，籬間語笑聲。", "還家已薄暮，燈火照柴荆。"]'),
('9f428c1a-4b49-4ee9-af9c-e02534dbc885','自詒','陸游','宋','宋诗','song-poetry','','[]','健忘閑何害，貪眠老正宜。',48,'全唐诗/poet.song.132000.json','["健忘閑何害，貪眠老正宜。", "本心惟泥酒，餘習略存詩。", "未廢春農業，猶堪幼學師。", "微官何所戀，請老五年遲。"]'),
('073012f3-031e-42c1-9bad-60a4d2660eb8','野興','陸游','宋','宋诗','song-poetry','','[]','荷鋤通北澗，腰斧上東峰。',48,'全唐诗/poet.song.132000.json','["荷鋤通北澗，腰斧上東峰。", "秋水清見底，曉雲深幾重。", "鼕鼕傳社鼓，渺渺度樓鐘。", "歸覓村橋路，詩情抵酒濃。"]'),
('bfa8dbee-348a-4f0e-8127-b61732ac5401','讀書','陸游','宋','宋诗','song-poetry','','[]','平生愛客如愛書，力雖不逮意有餘。',96,'全唐诗/poet.song.132000.json','["平生愛客如愛書，力雖不逮意有餘。", "門前車馬久掃迹，老病又與黄卷疏。", "人情冷暖可無問，手不觸書吾自恨。", "今年入秋風雨頻，燈火得凉初可近。", "年過七十眼尚明，天公成就老書生。", "舊業雖衰猶不墜，夜窗父子讀書聲。"]'),
('3e8f0bad-c9f8-4ef2-9b69-556b308426bb','客有見過者既去喟然有作二首  其一','陸游','宋','宋诗','song-poetry','','[]','鬢毛俱白盡，事不補秋毫。',48,'全唐诗/poet.song.132000.json','["鬢毛俱白盡，事不補秋毫。", "去死今無幾，歸耕何足高。", "已如陶止酒，徒勸屈餔糟。", "惟有滄溟去，揚帆觀雪濤。"]'),
('1fdcaa24-18e9-403c-a3c1-0e681bb0966a','客有見過者既去喟然有作二首  其二','陸游','宋','宋诗','song-poetry','','[]','永日安耕釣，餘年迫耄期。',48,'全唐诗/poet.song.132000.json','["永日安耕釣，餘年迫耄期。", "研朱點周易，飲酒和陶詩。", "带箭歸飛鶴，搘床不瞑龜。", "此生君看取，死是出門時。"]'),
('8604f519-c252-4d88-a1d7-73ddfbaffcff','秋陰','陸游','宋','宋诗','song-poetry','','[]','淡日披朝霧，輕雲結暮陰。',48,'全唐诗/poet.song.132000.json','["淡日披朝霧，輕雲結暮陰。", "菰蒲溪路暗，松竹草堂深。", "妙墨雙鈎帖，奇聲百衲琴。", "古人端未遠，一笑會吾心。"]'),
('6c543b28-f73e-4f3f-8645-3cae8e000570','八月九日晚賦','陸游','宋','宋诗','song-poetry','','[]','薄晚悠然下草堂，綸巾鶴氅弄秋光。',64,'全唐诗/poet.song.132000.json','["薄晚悠然下草堂，綸巾鶴氅弄秋光。", "風經樹杪聲初緊，月入門扉影正方。", "一世不知誰後死，四時可愛是新凉。", "從今覓醉其當勉，酒似鵝兒破殼黄。"]'),
('17d6c8bd-7d69-457a-a43f-6645669f0ad4','燕坐','陸游','宋','宋诗','song-poetry','','[]','赫日曈曈湧海門，黄流混混泝河源。',32,'全唐诗/poet.song.132000.json','["赫日曈曈湧海門，黄流混混泝河源。", "功成一日書仙籍，鍊骨成金不足言。"]'),
('62f437ed-94a0-4b50-84d5-beac13d35d7e','村飲四首  其一','陸游','宋','宋诗','song-poetry','','[]','不來東舍即西家，野老逢迎一笑譁。',32,'全唐诗/poet.song.132000.json','["不來東舍即西家，野老逢迎一笑譁。", "試說暮年如意事，細傾村釀聽私蛙。"]'),
('27839537-81c9-4572-9cb7-4a4426f719f6','村飲四首  其二','陸游','宋','宋诗','song-poetry','','[]','無念無營飽即嬉，老翁真箇似嬰兒。',32,'全唐诗/poet.song.132000.json','["無念無營飽即嬉，老翁真箇似嬰兒。", "昏鐘未動先酣枕，日上三竿是起時。"]'),
('b3e789be-3cba-4c2f-8b88-d5fd78e1fc30','村飲四首  其三','陸游','宋','宋诗','song-poetry','','[]','買來新兔不論錢，釣得鮮鱗細柳穿。',32,'全唐诗/poet.song.132000.json','["買來新兔不論錢，釣得鮮鱗細柳穿。", "野店渾頭更醇釅，一杯放手已醺然。"]'),
('ccf48c6c-dae9-4798-be5f-45ea770db580','村飲四首  其四','陸游','宋','宋诗','song-poetry','','[]','淡烟孤榜繫村橋，疊疊沙痕印落潮。',32,'全唐诗/poet.song.132000.json','["淡烟孤榜繫村橋，疊疊沙痕印落潮。", "最是一年秋好處，踏泥沽酒不辭遥。"]'),
('a62ce735-4f71-494e-9707-2a5c43aed39c','秋雨益凉寫興','陸游','宋','宋诗','song-poetry','','[]','秋氣蕭蕭暑已歸，晚雲更送雨霏微。',64,'全唐诗/poet.song.132000.json','["秋氣蕭蕭暑已歸，晚雲更送雨霏微。", "床收珍簟敷菅席，笥疊纖絺換熟衣。", "遣醉縱橫馳筆陣，乘閑談笑解棋圍。", "出門未免流年嘆，又見湖邊木葉飛。"]'),
('687a6ff6-12be-41d1-9d1b-127d9107cc48','薪米偶不繼戲書','陸游','宋','宋诗','song-poetry','','[]','仕官不諧農失業，敗屋蕭蕭書數篋。',64,'全唐诗/poet.song.132000.json','["仕官不諧農失業，敗屋蕭蕭書數篋。", "藜羹不糝未足嗟，爨竈無薪掃枯葉。", "丈夫窮空自其分，餓死吾肩未嘗脅。", "世間大有乞墦人，放翁笑汝驕妻妾。"]'),
('114669a5-cdd2-4ce2-90b9-50914d5f588e','牧牛兒','陸游','宋','宋诗','song-poetry','','[]','溪深不須憂，吳牛自能浮。',48,'全唐诗/poet.song.132000.json','["溪深不須憂，吳牛自能浮。", "童兒踏牛背，安穩如乘舟。", "寒雨山陂遠，參差烟樹晚。", "聞笛翁出迎，兒歸牛入圈。"]'),
('06a101cf-362c-4c07-a77c-0b935c2f38de','與兒子至東村遇父老共語因作小詩','陸游','宋','宋诗','song-poetry','','[]','桑竹穿村巷，衡茅隔土垣。',48,'全唐诗/poet.song.132000.json','["桑竹穿村巷，衡茅隔土垣。", "海氛成物象，秋氣肅川原。", "豆芋行將熟，雞豚亦已繁。", "豐兇歲所有，農事更深論。"]'),
('ce1da230-fcf6-443b-8ebf-e88397fe352b','微雨午寢夢憩道傍驛舍若在秦蜀間慨然有賦','陸游','宋','宋诗','song-poetry','','[]','吳中秋晚雨冥冥，自笑閑愁又爾馨。',64,'全唐诗/poet.song.132000.json','["吳中秋晚雨冥冥，自笑閑愁又爾馨。", "身世已歸南北陌，夢魂猶寄短長亭。", "濁醪可釀樽餘綠，明鏡無情鬢失青。", "賴有釣船堪送老，一汀鷗鷺共忘形。"]'),
('12bb6a56-f477-4fec-8dcb-50e04ca501ab','晨起對鏡','陸游','宋','宋诗','song-poetry','','[]','雙鬢成絲高頰顴，曉窗臨鏡意茫然。',32,'全唐诗/poet.song.132000.json','["雙鬢成絲高頰顴，曉窗臨鏡意茫然。", "朱顔豈是一朝去，暗鑠潜消五十年。"]'),
('2a58e66b-25e6-4beb-a6dc-dec20ca6b49e','村思','陸游','宋','宋诗','song-poetry','','[]','揣分新辭祿，扶衰又度秋。',48,'全唐诗/poet.song.132000.json','["揣分新辭祿，扶衰又度秋。", "已將窮博健，更賴學忘憂。", "船護烟陂鴨，欄歸草徑牛。", "作勞何以慰，茅店問新篘。"]'),
('6f172c27-0a46-4bd3-9a43-28532f6f01d7','秋夜','陸游','宋','宋诗','song-poetry','','[]','倦叟投床早，昏燈落燼頻。',48,'全唐诗/poet.song.132000.json','["倦叟投床早，昏燈落燼頻。", "鵲翻驚缺月，犬吠逐行人。", "未喪詩書業，猶存老病身。", "菊花行可醉，作意插烏巾。"]'),
('68b65b55-ed0f-4e62-972d-2d26a8168004','醉中書懷','陸游','宋','宋诗','song-poetry','','[]','既老心愈空，新凉體差健。',96,'全唐诗/poet.song.132000.json','["既老心愈空，新凉體差健。", "登山每嗔扶，對案亦强飯。", "平生百事懶，惟酒不待勸。", "迨此桑落時，一醉適我願。", "羸然雲水身，本非朱紫楦。", "少猶耻枉尺，老敢欺方寸。", "但令死瞑目，餘事何足論。", "不見鹿門翁，全家事潜遯。"]'),
('2baed07b-20ea-4547-bbb7-73fe1ee9b31a','次韵鄭盱眙見寄并簡其甥劉君','陸游','宋','宋诗','song-poetry','','[]','衣上空嗟京洛塵，故交半作白頭新。',64,'全唐诗/poet.song.132000.json','["衣上空嗟京洛塵，故交半作白頭新。", "眾中初得見吾子，東觀已疑無若人。", "仗馬極知非久斥，沙鷗要是孰能馴。", "兩章英妙同時到，趙壹囊中却未貧。"]'),
('b1e32e15-2eea-451c-b197-5ceecbb25ea5','書齋壁','陸游','宋','宋诗','song-poetry','','[]','平生憂患苦縈纏，菱刺磨成芡實圜。',64,'全唐诗/poet.song.132000.json','["平生憂患苦縈纏，菱刺磨成芡實圜。", "天下不知誰竟是，古來惟有醉差賢。", "過堂未悟鐘將釁，睨柱寧知璧偶全。", "自笑爲農行沒世，尚如驚雁落空弦。"]'),
('3cfb4274-6bfd-4cbf-a962-464f0dfe9295','一老','陸游','宋','宋诗','song-poetry','','[]','太平一老醉騰騰，南陌東阡喜不勝。',64,'全唐诗/poet.song.132000.json','["太平一老醉騰騰，南陌東阡喜不勝。", "民力農桑家自足，士崇名節道方興。", "騎鯨仙去時猶遠，射虎歸來氣頗增。", "莫道幽棲交舊絕，月中亦有打門僧。"]'),
('2cc708ba-ea58-496c-88dd-1091a8c33920','戲用方外語示客','陸游','宋','宋诗','song-poetry','','[]','紅粟青錢一掃空，笊籬行賣學龐翁。',64,'全唐诗/poet.song.132000.json','["紅粟青錢一掃空，笊籬行賣學龐翁。", "身居本地風光裏，愁擲它方世界中。", "剩欲劇談明不二，誰能太息賞無同。", "踞床一喝君聞否，三日猶應覺耳聾。"]'),
('669c5b4a-6f15-41bb-bf2a-fb41f529e4e4','秋晚三首  其一','陸游','宋','宋诗','song-poetry','','[]','西山破曉兩眉青，南浦無風一鏡平。',64,'全唐诗/poet.song.132000.json','["西山破曉兩眉青，南浦無風一鏡平。", "食盡不容添鶴口，身閑且免負鷗盟。", "霜前草樹已無色，雨到菰蒲先有聲。", "只怪勝遊頻入夢，今朝蜀客話青城。"]'),
('0831f5ae-e49b-411d-8fb2-c29b863e3410','秋晚三首  其二','陸游','宋','宋诗','song-poetry','','[]','辭祿始知貧有味，杜門不覺老相催。',64,'全唐诗/poet.song.132000.json','["辭祿始知貧有味，杜門不覺老相催。", "寒鴉已占雁前到，黄菊猶須霜後開。", "團扇塵埃高挂壁，短檠書史亂成堆。", "羸軀自笑癡頑甚，撐拄新寒又一回。"]'),
('a51915a2-8ae9-4f8a-88e4-9158fe00ba11','秋晚三首  其三','陸游','宋','宋诗','song-poetry','','[]','世事無窮似弈棋，不如常采故山芝。',64,'全唐诗/poet.song.132000.json','["世事無窮似弈棋，不如常采故山芝。", "蕭蕭雞犬三家聚，莽莽風烟十里陂。", "幸有濁醪從客醉，常憂黠鬼笑人癡。", "清秋樂處君知否，庭下幽花漸可移。"]'),
('716ec79c-8756-4cce-914d-84ca7cdc5606','次金溪宗人伯政見寄韵','陸游','宋','宋诗','song-poetry','','[]','道義流聞意已傾，豈知晚歲託齊盟。',64,'全唐诗/poet.song.132000.json','["道義流聞意已傾，豈知晚歲託齊盟。", "六經日月未嘗蝕，千載源流終自明。", "汝水家家書有種，吾宗世世士知名。", "讀君長句還增氣，俗耳那聞韶頀聲。"]'),
('3959e440-d3a6-4625-9105-55a7d1407a5c','新寒二首  其一','陸游','宋','宋诗','song-poetry','','[]','碧蝶飛飛過短籬，山薑石竹有殘枝。',32,'全唐诗/poet.song.132000.json','["碧蝶飛飛過短籬，山薑石竹有殘枝。", "誰知老子閑眠處，恰是新寒細雨時。"]'),
('20d88511-06e2-4721-a2ac-3c191ac55dd9','新寒二首  其二','陸游','宋','宋诗','song-poetry','','[]','安石榴房初小坼，南天竺子亦微丹。',32,'全唐诗/poet.song.132000.json','["安石榴房初小坼，南天竺子亦微丹。", "新寒漠漠偏欺老，睡起無風怯倚欄。"]'),
('d31ca972-9917-4c67-b9c6-bfe656da00d5','村鄰會飲','陸游','宋','宋诗','song-poetry','','[]','陸子白首安耕桑，樂事遽數烏能詳。',160,'全唐诗/poet.song.132000.json','["陸子白首安耕桑，樂事遽數烏能詳。", "長羅家家雪作麵，畫楫處處青分秧。", "迎荻船歸潮入浦，祈蠶會散月滿廊。", "有時鄰曲苦招喚，茅簷掃地羅壺觴。", "堆盤珍膾似河鯉，入鼎大臠勝胡羊。", "披綿黄雀麴糝美，斫雪紫蟹椒橙香。", "老人飽食可無患，摩挲酒甕與飯囊。", "兒孫扶侍遞相送，笑語無間歌聲長。", "人間哀樂不可常，掠剩有鬼在汝傍。", "常憂水旱虞螟蝗，力行孝悌招豐穰。"]'),
('a1ce6435-bb50-43ed-a6ac-a59e8a541305','試筆二首  其一','陸游','宋','宋诗','song-poetry','','[]','烹葵飯豆飽還休，弄筆翻書歲又秋。',32,'全唐诗/poet.song.132000.json','["烹葵飯豆飽還休，弄筆翻書歲又秋。", "靈府湛然如止水，擬將何地著閑愁。"]'),
('4df093b7-4ead-4b3b-b7d8-2938a77d6377','試筆二首  其二','陸游','宋','宋诗','song-poetry','','[]','紅絲玉斗紫毫鋩，歲晚相從味更長。',32,'全唐诗/poet.song.132000.json','["紅絲玉斗紫毫鋩，歲晚相從味更長。", "不似樂天歸老日，柳枝駱馬兩堪傷。"]'),
('bd188d27-e482-44a6-bb18-f1ed96a9d39c','孤村','陸游','宋','宋诗','song-poetry','','[]','老寄孤村裏，悠然卧曲肱。',48,'全唐诗/poet.song.132000.json','["老寄孤村裏，悠然卧曲肱。", "算貧先放鶴，嫌鬧併疏僧。", "古戍高秋笛，寒窗半夜燈。", "平生羞詭遇，多獲豈吾能。"]'),
('b4b22451-d7bb-48a5-886e-17d251b0b6a2','絕祿以來衣食愈不繼小兒力圖之殊未有涯予謂不若痛節用爾示以此詩','陸游','宋','宋诗','song-poetry','','[]','處世吾傷拙，營生汝亦疏。',48,'全唐诗/poet.song.132000.json','["處世吾傷拙，營生汝亦疏。", "如謀道邊舍，似信枕中書。", "甕牖居疑泰，藜羹食敢餘。", "晏嬰元學墨，勿負此心初。"]'),
('b0715171-3806-4112-a93e-773fcddedc83','予宿疾多已失去獨氣痛時作賦詩自寬','陸游','宋','宋诗','song-poetry','','[]','疾久難全去，扶持度歲年。',48,'全唐诗/poet.song.132000.json','["疾久難全去，扶持度歲年。", "垣牆完罅隙，匕筯禁芳鮮。", "漸減觀書課，常儲買藥錢。", "鄉人多不識，誰與問沉綿。"]'),
('ffca4e90-b9f8-457d-922f-0baa8e7a9c7e','秋懷十首末章稍自振起亦古義也  其一','陸游','宋','宋诗','song-poetry','','[]','皇天本無心，萬物各有時。',72,'全唐诗/poet.song.132000.json','["皇天本無心，萬物各有時。", "飛鴻何預人，南翔每如期。", "仰看霜露墜，俯觀草木衰。", "英英籬下菊，秀色獨滿枝。", "豈無一樽酒，相與斟酌之。", "耋老天所佚，行歌復何疑。"]'),
('55a52d5f-4a92-419b-ae86-40f593e31bda','秋懷十首末章稍自振起亦古義也  其二','陸游','宋','宋诗','song-poetry','','[]','暑退財幾時，忽已迫霜露。',72,'全唐诗/poet.song.132000.json','["暑退財幾時，忽已迫霜露。", "西風一何厲，落葉紛滿路。", "老翁衰可笑，日夜念墐戶。", "衣裘先關懷，膏火亦當具。", "酒尤不可緩，傾聽糟床注。", "供槃柿栗耳，何敢議雉兔。"]'),
('f0cfd3ef-a402-4ecc-93c6-bb60c481393f','秋懷十首末章稍自振起亦古義也  其三','陸游','宋','宋诗','song-poetry','','[]','雨滴大梧葉，風轉孤蓬窠。',72,'全唐诗/poet.song.132000.json','["雨滴大梧葉，風轉孤蓬窠。", "秋色固凄愴，二物感人多。", "日月行黄道，倏過如飛梭。", "大計百年間，貴賤俱銷磨。", "東家及西舍，更代哭與歌。", "若無杯中物，如此摇落何。"]'),
('b13186d3-cde1-49e3-ad42-51def1d51523','秋懷十首末章稍自振起亦古義也  其四','陸游','宋','宋诗','song-poetry','','[]','身如行脚僧，放包即爲家。',72,'全唐诗/poet.song.132000.json','["身如行脚僧，放包即爲家。", "家如道邊店，蕭然寄天涯。", "居室如小舟，風扉櫓謳啞。", "坐傍陳琴書，庭下栽雜花。", "儉陋雖可笑，在我則已奢。", "何以善吾生，念念思無邪。"]'),
('3cf7566b-a118-46c6-9842-76c94409a3ac','秋懷十首末章稍自振起亦古義也  其五','陸游','宋','宋诗','song-poetry','','[]','遇酒幸一醉，遇飯幸一飽。',72,'全唐诗/poet.song.132000.json','["遇酒幸一醉，遇飯幸一飽。", "或遇空無時，豈復有他巧。", "鄉鄰哀其窮，叩戶饋糜麨。", "欣然出舍傍，菘韭青落爪。", "饑羸曾未起，吟諷已稍稍。", "袖手北窗前，枯腸困搜攪。"]'),
('e9eee96c-dc94-438a-b606-53a7464f8e9d','秋懷十首末章稍自振起亦古義也  其六','陸游','宋','宋诗','song-poetry','','[]','秋高天薄寒，夾衣已出笥。',72,'全唐诗/poet.song.132000.json','["秋高天薄寒，夾衣已出笥。", "團團素紈扇，時至自當棄。", "明年機中練，與我亦何異。", "宮妾感物悲，此豈丈夫事。", "吾曹一出門，所遇皆有義。", "夷齊死千年，高風邈難嗣。"]'),
('1df8a1f4-c6c4-4b59-abf2-1ba55079ccb6','秋懷十首末章稍自振起亦古義也  其七','陸游','宋','宋诗','song-poetry','','[]','辟塵當以犀，濯纓當以水。',72,'全唐诗/poet.song.132000.json','["辟塵當以犀，濯纓當以水。", "龜堂一炷香，世念去如洗。", "人生天地間，太倉一稊米。", "哀哉不自悟，役役以至死。", "孰能從我遊，趺坐燔柏子。", "夜半清磬聲，悠然從定起。"]'),
('193064b1-104c-463f-97ad-beb377e430ba','秋懷十首末章稍自振起亦古義也  其八','陸游','宋','宋诗','song-poetry','','[]','改朔甫再宿，月見西南隅。',72,'全唐诗/poet.song.132000.json','["改朔甫再宿，月見西南隅。", "纖纖一銀鈎，挂空疑有無。", "我行青楓岸，遠水浮雙鳧。", "新寒入短衣，感此風霜初。", "頗欲呼小艇，東村行芋區。", "衣薄且言歸，烟火望吾廬。"]'),
('617fbdb8-3936-457d-a08d-6c49d29fd5c4','秋懷十首末章稍自振起亦古義也  其九','陸游','宋','宋诗','song-poetry','','[]','短蓑榜輕舟，時過野僧舍。',72,'全唐诗/poet.song.132000.json','["短蓑榜輕舟，時過野僧舍。", "長衫挂數珠，亦入法華社。", "平生無揀擇，生死均早夜。", "餘年猶幾何，久已付造化。", "常嫌樂天佞，却肯退之罵。", "君看佛骨表，自是無生話。"]'),
('b45db236-626d-4d26-af87-45520dd8d866','秋懷十首末章稍自振起亦古義也  其一○','陸游','宋','宋诗','song-poetry','','[]','我昔聞關中，水深土平曠。',72,'全唐诗/poet.song.132000.json','["我昔聞關中，水深土平曠。", "涇渭貫其間，沃壤誰與抗。", "桑麻鬰千里，黍林高一丈。", "潼華臨黄河，古出名將相。", "淪陷七十年，北首增慘愴。", "猶期垂老眼，一睹天下壯。"]'),
('a6ab7b8e-5897-4aa2-ae97-bf13f40632de','九月七日子坦子聿俱出斂租穀雞初鳴而行甲夜始歸勞以此詩','陸游','宋','宋诗','song-poetry','','[]','仲秋穀方登，螟生忽告饑。',168,'全唐诗/poet.song.132000.json','["仲秋穀方登，螟生忽告饑。", "艱難冀一飽，俯仰事已非。", "貸糧助耕耘，客主更相依。", "一旦忽如此，欲語涕屢揮。", "共斂螟之餘，存者牛毛稀。", "吾兒廢書出，辛苦幸庶幾。", "夜半聞具舟，憐汝露溼衣。", "既夕不能食，念汝戴星歸。", "手持一杯酒，老意不可違。", "秫瘦酒味薄，食少雞不肥。", "頗聞吳中熟，多稼徹王畿。", "亦欲就飽處，無羽能奮飛。", "官富哀我民，榜笞方甚威。", "渠亦豈得已，撫事增歔欷。"]'),
('6bde8263-97c7-48a0-a1cb-6c49c469570c','醉題埭西酒家二首  其一','陸游','宋','宋诗','song-poetry','','[]','陣陣新寒入布裘，偶乘小醉得閑遊。',64,'全唐诗/poet.song.132000.json','["陣陣新寒入布裘，偶乘小醉得閑遊。", "丹楓落日野橋晚，斷雁溼雲江路秋。", "馬得一鳴何恨斥，金經百鍊豈容柔。", "不知千載塵埃裏，更有吾曹强項不。"]'),
('20483b0c-13ef-4214-bf31-ab5892e83ae0','醉題埭西酒家二首  其二','陸游','宋','宋诗','song-poetry','','[]','桑麻蒙翳不通鄰，耽酒頹然一老民。',64,'全唐诗/poet.song.132000.json','["桑麻蒙翳不通鄰，耽酒頹然一老民。", "遣客方眠那是醉，有衣可典未爲貧。", "曬翎斜日鷗來熟，印迹平沙雁到新。", "君看此間何境界，癡人猶說吐車茵。"]'),
('462e3dd1-a4a0-476e-b90e-037d769b0979','秋晚','陸游','宋','宋诗','song-poetry','','[]','庭草猶殘綠，溪楓已半丹。',48,'全唐诗/poet.song.132000.json','["庭草猶殘綠，溪楓已半丹。", "誰知此翁健，又見一年寒。", "幻境槐安夢，危機竹節灘。", "如今渾過盡，摩腹且加餐。"]'),
('addc4474-8c40-448d-90b4-28bd0872b17a','省事','陸游','宋','宋诗','song-poetry','','[]','省事漸捐書，甘貧學藝蔬。',48,'全唐诗/poet.song.132000.json','["省事漸捐書，甘貧學藝蔬。", "心安閑夢少，病去俗醫疏。", "兀爾遊方外，超然到物初。", "此身猶是幻，况復愛吾廬。"]'),
('4f000cc2-15cd-45ce-aad8-2a4d33447f16','晨起頗寒飲少酒作草數幅','陸游','宋','宋诗','song-poetry','','[]','衣食無多悉自營，今年真箇是歸耕。',64,'全唐诗/poet.song.132000.json','["衣食無多悉自營，今年真箇是歸耕。", "屏居大澤群囂息，乍得清寒百體輕。", "橋北潦收波淺碧，埭西霜近葉微頳。", "一杯弄筆元無法，自愛龍蛇入卷聲。"]'),
('b2d08ab6-81ca-4470-9184-6358ee726eb1','往事','陸游','宋','宋诗','song-poetry','','[]','海內橫流日，吾猶及建炎。',48,'全唐诗/poet.song.132000.json','["海內橫流日，吾猶及建炎。", "眾醫雖共視，久疾固難砭。", "黠虜方觀釁，行宮未解嚴。", "時平逾五紀，話此涕常霑。"]'),
('c17ee935-e277-4c95-a7c4-2581150b05c9','步至東莊','陸游','宋','宋诗','song-poetry','','[]','澤國寒雖晚，霜天已迫冬。',48,'全唐诗/poet.song.132000.json','["澤國寒雖晚，霜天已迫冬。", "蕎花雪無際，稻米玉新舂。", "身已風中葉，人方飯後鐘。", "兒能哀老子，努力事春農。"]'),
('26abaece-bc43-4125-920c-220e92fa7487','秋思二首  其一','陸游','宋','宋诗','song-poetry','','[]','門巷蕭條秋色深，黄花始欲慰孤斟。',64,'全唐诗/poet.song.132000.json','["門巷蕭條秋色深，黄花始欲慰孤斟。", "久貧自笑不妨樂，過足固知非所欽。", "琴調已忘還漸省，詩聯未穩更長吟。", "吾兒西上無多日，安得相從老故林。"]'),
('08bd5064-d8d0-4d5a-8f39-5c4af92dec52','秋思二首  其二','陸游','宋','宋诗','song-poetry','','[]','日落江城聞擣衣，長空杳杳雁南飛。',64,'全唐诗/poet.song.132000.json','["日落江城聞擣衣，長空杳杳雁南飛。", "桑枝空後醅初熟，豆莢成時兔正肥。", "徂歲背人常冉冉，老懷感物倍依依。", "平生許國今何有，且擬梁鴻賦五噫。"]'),
('d26969c7-d30a-40a0-b688-dca964245986','讀退之人不知古今馬牛而襟裾之句有感','陸游','宋','宋诗','song-poetry','','[]','書生獨占世間癡，過計私憂無已時。',32,'全唐诗/poet.song.132000.json','["書生獨占世間癡，過計私憂無已時。", "知盡古今成底事，空將血泪向人垂。"]'),
('3631787a-1318-4aab-85a1-36c08935cf43','病愈看鏡','陸游','宋','宋诗','song-poetry','','[]','鏡中稍復舊朱顔，一笑衰翁乃爾頑。',32,'全唐诗/poet.song.132000.json','["鏡中稍復舊朱顔，一笑衰翁乃爾頑。", "三百甕齏消未盡，不知更著幾年還。"]'),
('5099d14d-4c1c-49fe-9223-9f1514b7d566','讀韓致光詩集','陸游','宋','宋诗','song-poetry','','[]','渺莽江湖萬里秋，玉峰老子弄孤舟。',32,'全唐诗/poet.song.132000.json','["渺莽江湖萬里秋，玉峰老子弄孤舟。", "猶勝宿直金鑾夜，凜凜常懷潑酢憂。"]'),
('915ae4ef-92e6-44b0-86b7-0a0203801a12','逆旅書壁二首  其一','陸游','宋','宋诗','song-poetry','','[]','驢鞍懸酒榼，僮背負衣囊。',48,'全唐诗/poet.song.132000.json','["驢鞍懸酒榼，僮背負衣囊。", "但說市朝變，不知岐路長。", "下程先施藥，拂榻靜焚香。", "明旦又西去，河橋秋葉黄。"]'),
('e000bcf2-eb19-4926-baaa-42b2468bc6b4','逆旅書壁二首  其二','陸游','宋','宋诗','song-poetry','','[]','騎驢萬里行，歲一過秦城。',48,'全唐诗/poet.song.132000.json','["騎驢萬里行，歲一過秦城。", "下杜貰春酒，新豐聞曉鶯。", "綠槐新巷陌，白骨幾公卿。", "欲覓曲江水，連雲禾黍生。"]'),
('6bfe7fc1-5ecc-4643-a05b-10497e8cacb7','初寒老身頗健戲書二首  其一','陸游','宋','宋诗','song-poetry','','[]','一身百病老難支，病減身輕偶此時。',64,'全唐诗/poet.song.132000.json','["一身百病老難支，病減身輕偶此時。", "窗暖不妨聊假寐，囊空久已罷招醫。", "山爐巉絕香生岫，鏊研坡陀墨滿池。", "箇裏生涯君莫厭，癡人至死不曾知。"]'),
('b278a337-1d5c-40df-9ac3-ebfbaf98452f','初寒老身頗健戲書二首  其二','陸游','宋','宋诗','song-poetry','','[]','過雁聲悲落葉稠，孤村景物更禁秋。',64,'全唐诗/poet.song.132000.json','["過雁聲悲落葉稠，孤村景物更禁秋。", "窮諳客路風塵惡，老判人間歲月遒。", "酒號賢人真古語，疾爲豎子豈吾憂。", "山房幸有初寒備，且傍篝爐擁褐裘。"]'),
('8174489c-469f-4c52-a4b1-b7ab78c6c090','子龍求烟雨軒詩口占絕句二首  其一','陸游','宋','宋诗','song-poetry','','[]','烏桕迎霜已半丹，哦詩終日合憑欄。',32,'全唐诗/poet.song.132000.json','["烏桕迎霜已半丹，哦詩終日合憑欄。", "霜高木落應尤好，長挂西窗更怕寒。"]'),
('c7ea7b2d-cb62-4033-96f0-c038005ca442','子龍求烟雨軒詩口占絕句二首  其二','陸游','宋','宋诗','song-poetry','','[]','規模正似釣魚庵，把酒纔容客二三。',32,'全唐诗/poet.song.132000.json','["規模正似釣魚庵，把酒纔容客二三。", "若比東偏參倚室，此中猶自覺耽耽。"]'),
('5bb52e78-668b-410c-a75a-01c281203903','居室甚隘而藏書頗富率終日不出戶二首  其一','陸游','宋','宋诗','song-poetry','','[]','掩關小室動經旬，蠹簡如山伴此身。',64,'全唐诗/poet.song.132000.json','["掩關小室動經旬，蠹簡如山伴此身。", "百億須彌藏粒芥，大千經卷寓微塵。", "危機已過猶驚顧，惡夢初回一欠伸。", "此段神通君會否，聽風聽雪待新春。"]'),
('60ddca66-d1f1-40db-8868-148fbb889a6e','居室甚隘而藏書頗富率終日不出戶二首  其二','陸游','宋','宋诗','song-poetry','','[]','椰子微軀有百窮，平生風際轉枯蓬。',64,'全唐诗/poet.song.132000.json','["椰子微軀有百窮，平生風際轉枯蓬。", "豈知蟬腹龜腸後，更寄蜂房螘穴中。", "學儉久判羹不糝，憚煩惟欲寐無聰。", "積書充棟元無用，聊復吟哦答候蟲。"]'),
('990fbe7e-04b3-4282-904e-12c0e263af0f','無酒嘆','陸游','宋','宋诗','song-poetry','','[]','不用塞黄河，不用出周鼎。',104,'全唐诗/poet.song.132000.json','["不用塞黄河，不用出周鼎。", "但願酒滿家，日夜醉不醒。", "不用冠如箕，不用印如斗。", "但願身强健，朝暮常飲酒。", "造物不少恕，虐戲逐段新。", "坐令古銅榼，經月常生塵。", "平生得酒狂無敵，百幅淋漓風雨疾。", "造物欲以醒困之，此老醒狂君未知。"]'),
('00b57398-612c-4f79-95e6-f2104f27f10c','讀書','陸游','宋','宋诗','song-poetry','','[]','古人已死書獨存，吾曹賴書見古人。',96,'全唐诗/poet.song.132000.json','["古人已死書獨存，吾曹賴書見古人。", "後之視今猶視古，吾書未泯要有取。", "賈生痛哭漢文時，至今讀之有餘悲。", "魏徵嘻笑封德彝，生亦豈責絳灌知。", "窮秋風雨卧孤館，萬世悠悠百年短。", "垂死成功亦未晚，安知無人嘆微管。"]'),
('4cc97579-97d9-4d13-84df-4af3ef1e7fc9','醉賦','陸游','宋','宋诗','song-poetry','','[]','霜楓照茅屋，露菊插紗巾。',48,'全唐诗/poet.song.132000.json','["霜楓照茅屋，露菊插紗巾。", "今古無窮事，江湖未死身。", "直令依馬磨，終勝拜車塵。", "我亦輕餘子，君當恕醉人。"]'),
('ffe81d87-31b1-4c9a-a11d-5b7169d5e2df','掩扉','陸游','宋','宋诗','song-poetry','','[]','久卧空山獨掩扉，迂疏不恨世相違。',64,'全唐诗/poet.song.132000.json','["久卧空山獨掩扉，迂疏不恨世相違。", "新霜巷陌鳥烏樂，小雨園畦菘芥肥。", "驥病極知當伏櫪，鷗閑誰與共忘機。", "一編蠹簡從吾好，又見西窗挂夕暉。"]'),
('756cd922-79b0-4a2c-b6e6-2616c737f594','六經  其一','陸游','宋','宋诗','song-poetry','','[]','六經聖所傳，百代尊元龜。',48,'全唐诗/poet.song.132000.json','["六經聖所傳，百代尊元龜。", "諄諄布方冊，一字不汝欺。", "抱書入家塾，自汝兒童時。", "老乃幸不驗，愚哉死何悲。"]'),
('0960a59b-fd9b-47bb-8778-901dd2de9f28','六經  其二','陸游','宋','宋诗','song-poetry','','[]','秦人燔六經，非與經爲仇。',48,'全唐诗/poet.song.132000.json','["秦人燔六經，非與經爲仇。", "方其勇决時，亦爲子孫謀。", "斂金鑄巨人，豈復畏鉏耰。", "千載惡名在，尚與黄河流。"]'),
('21e35a8b-6bf5-416c-9e2e-56ff622940a8','舟中作','陸游','宋','宋诗','song-poetry','','[]','沙路時晴雨，漁舟日往來。',48,'全唐诗/poet.song.132000.json','["沙路時晴雨，漁舟日往來。", "村村皆畫本，處處有詩材。", "炊黍孤烟晚，呼牛一笛哀。", "終身看不厭，岸幘興悠哉。"]'),
('6521b854-3fac-4d58-b184-ec23208e4740','秋晚二首  其一','陸游','宋','宋诗','song-poetry','','[]','門巷清如水，情懷淡似秋。',48,'全唐诗/poet.song.132000.json','["門巷清如水，情懷淡似秋。", "詩吟唐近體，談慕晉高流。", "託命須長鑱，浮家只小舟。", "江南烟雨岸，何處不堪留。"]'),
('c9b2dc7b-ba0b-4769-83c4-58c25a5262ac','秋晚二首  其二','陸游','宋','宋诗','song-poetry','','[]','木落寺樓出，江平沙渚生。',48,'全唐诗/poet.song.132000.json','["木落寺樓出，江平沙渚生。", "牛羊下殘照，鼓角動高城。", "寒至衣猶質，憂多夢自驚。", "群胡方鬭穴，河渭幾時清。"]'),
('979497fa-7e75-4fbe-89de-f12396626f0b','西窗獨酌','陸游','宋','宋诗','song-poetry','','[]','却掃衡門歲月深，殘骸况復病交侵。',64,'全唐诗/poet.song.132000.json','["却掃衡門歲月深，殘骸况復病交侵。", "平生所學爲何事，後世有人知此心。", "水落枯萍黏破塊，霜高丹葉照橫林。", "一樽濁酒西窗下，安得無功與共斟。"]'),
('3ec735e2-6ef6-44ef-b69f-b69516635543','冬初薄霜病軀益健欣然有賦','陸游','宋','宋诗','song-poetry','','[]','古服追隨野老歡，豎裁布褐縮縫冠。',64,'全唐诗/poet.song.132000.json','["古服追隨野老歡，豎裁布褐縮縫冠。", "霜清頓洗肺肝熱，木落更知山澤寬。", "斗酒敢言嫌魯薄，杯羹聊得學吳酸。", "一貧自是書生分，忍愧看人却似難。"]'),
('1e74c45e-4be3-4f3d-9cfe-334568dd9cd1','一錢','陸游','宋','宋诗','song-poetry','','[]','萬事紛紛不足論，滿庭枯草閉柴門。',32,'全唐诗/poet.song.132000.json','["萬事紛紛不足論，滿庭枯草閉柴門。", "一錢留得終羞澀，持買餦餭引福孫。"]'),
('0fd4a949-00e7-4e7d-af63-7cf26a91255b','燈下讀書戲作','陸游','宋','宋诗','song-poetry','','[]','吾生如蠹魚，亦復類熠耀。',48,'全唐诗/poet.song.132000.json','["吾生如蠹魚，亦復類熠耀。", "一生守斷簡，微火寒自照。", "區區心所樂，那顧世間笑。", "閉門謝俗子，與汝不同調。"]'),
('35111a3d-e96a-4c7a-a476-9ef703264706','遊近山','陸游','宋','宋诗','song-poetry','','[]','羸病知難賦遠遊，尚尋好景送悠悠。',64,'全唐诗/poet.song.132000.json','["羸病知難賦遠遊，尚尋好景送悠悠。", "亂山孤店雁聲晚，一馬二童溪路秋。", "掃壁有僧求醉墨，倚樓無客話清愁。", "殘年敢望常强健，到處臨歸爲小留。"]'),
('3078415b-a8d0-416f-af6a-ee06b9992886','示兒子','陸游','宋','宋诗','song-poetry','','[]','祿食無功我自知，汝曹何以報明時。',64,'全唐诗/poet.song.132000.json','["祿食無功我自知，汝曹何以報明時。", "爲農爲士亦奚異，事國事親惟不欺。", "道在六經寧有盡，躬耕百畝可無饑。", "最親切處今相付，熟讀周公七月詩。"]'),
('a149e262-2ff9-46c7-a829-226f1967e5ef','寄溧陽周丞文璞周寄詩卷殊可喜','陸游','宋','宋诗','song-poetry','','[]','滿握珠璣何自來，晴窗初喜拆書開。',64,'全唐诗/poet.song.132000.json','["滿握珠璣何自來，晴窗初喜拆書開。", "信哉天下有奇作，久矣名家多異才。", "隔闊經年如許進，超騰它日若爲陪。", "山陰道上霜天好，安得相從賦早梅。"]'),
('de474574-f362-4ee6-a381-3005dd2caf3f','旅思','陸游','宋','宋诗','song-poetry','','[]','支遁山前看月明，葛洪井上聽松聲。',64,'全唐诗/poet.song.132000.json','["支遁山前看月明，葛洪井上聽松聲。", "廢亭草滿青騾健，野店燈殘寶劍鳴。", "萬事竟當歸定論，寸心那得愧平生。", "悠然酌罷無人語，寄意孤桐一再行。"]'),
('2bdc2d8b-aaed-40b9-92bd-b0b3e8f48e0b','東村步歸二首  其一','陸游','宋','宋诗','song-poetry','','[]','野渡霜風冷，茆簷夕照明。',48,'全唐诗/poet.song.132000.json','["野渡霜風冷，茆簷夕照明。", "催科醉亭長，聚學老書生。", "山果紛丹漆，村醪任濁清。", "路回家忽近，柳外小橋橫。"]'),
('b4418cf2-2c6d-43e7-8334-864ba118c2ef','東村步歸二首  其二','陸游','宋','宋诗','song-poetry','','[]','風陣鴉翻黑，霜林葉半丹。',48,'全唐诗/poet.song.132000.json','["風陣鴉翻黑，霜林葉半丹。", "筋骸欣小健，裘褐戒初寒。", "代步雞栖足，充饑鶴料寬。", "平生自如許，况已挂吾冠。"]'),
('202b8ea6-a7aa-47ab-9a77-6deeb1aaddc3','觀方外書','陸游','宋','宋诗','song-poetry','','[]','司馬遺書有坐忘，顗翁止觀略相當。',32,'全唐诗/poet.song.132000.json','["司馬遺書有坐忘，顗翁止觀略相當。", "龜堂閉戶常終日，時得相從一炷香。"]'),
('7221e037-e201-4af7-853f-2d8ed67babaf','午睡初起二首  其一','陸游','宋','宋诗','song-poetry','','[]','曲腰桑上午雞鳴，喔喔還如報五更。',32,'全唐诗/poet.song.132000.json','["曲腰桑上午雞鳴，喔喔還如報五更。", "睡起展書摩病眼，油窗喜對夕陽明。"]'),
('1bbd6f9d-36b7-427e-9e77-2435337bc0aa','午睡初起二首  其二','陸游','宋','宋诗','song-poetry','','[]','舍中未報壓新醅，閑弄流塵槲葉杯。',32,'全唐诗/poet.song.132000.json','["舍中未報壓新醅，閑弄流塵槲葉杯。", "得醉固佳醒亦好，了無一事到靈臺。"]'),
('588fcedd-8697-4c5d-a321-71b2e0867eba','暮秋遣興二首  其一','陸游','宋','宋诗','song-poetry','','[]','改盡朱顔白盡頭，杜門亦復弊貂裘。',64,'全唐诗/poet.song.132000.json','["改盡朱顔白盡頭，杜門亦復弊貂裘。", "斷鴻影外玉關月，病驥嘶中青海秋。", "孤坐向空書咄咄，閑吟隨處送悠悠。", "如虹壯氣終難豁，安得雲濤萬里舟。"]'),
('b397f767-fdab-416b-b31d-e6fa0d313154','暮秋遣興二首  其二','陸游','宋','宋诗','song-poetry','','[]','平生南地慣羈遊，放浪常同不繫舟。',64,'全唐诗/poet.song.132000.json','["平生南地慣羈遊，放浪常同不繫舟。", "鼉作夜風經沌口，鸛鳴秋雨宿杭頭。", "方傾意氣輕秦俠，俄困悲傷類楚囚。", "買屋數間聊作戲，豈知真用作菟裘。"]'),
('d5c033f0-bda5-4d2e-aa69-dc011dc09d46','種蔬','陸游','宋','宋诗','song-poetry','','[]','老翁老去尚何言，除却翻書即灌園。',64,'全唐诗/poet.song.132000.json','["老翁老去尚何言，除却翻書即灌園。", "處處移蔬乘小雨，時時拾礫繞頹垣。", "江鄉地暖根常茂，旱歲蟲生葉未繁。", "四壁愈空冬祭近，更催稚子牧雞豚。"]'),
('8e0513d6-281f-464a-87ab-cbef018025c2','起晚戲作','陸游','宋','宋诗','song-poetry','','[]','睡到僧廊響木魚，莊周蝴蝶兩蘧蘧。',64,'全唐诗/poet.song.132000.json','["睡到僧廊響木魚，莊周蝴蝶兩蘧蘧。", "數聲林下華亭鶴，一卷床頭笠澤書。", "雲子甑香炊熟後，露芽甌淺點嘗初。", "若論身逸心無事，臺省諸公恐不如。"]'),
('227b23e2-4f59-49d1-9a9c-9bbc4da062ea','老嘆','陸游','宋','宋诗','song-poetry','','["\u897f\u6e56"]','八十未滿七十餘，山巔水涯一丈夫。',64,'全唐诗/poet.song.132000.json','["八十未滿七十餘，山巔水涯一丈夫。", "長鳴未免似野鶴，生意欲盡如枯株。", "臨安宮闕經營初，銀鞍日日醉西湖。", "不須細數舊酒徒，當時兒童今亦無。"]'),
('78bccb25-78a5-4c08-b279-3712466b3ab4','新治暖室','陸游','宋','宋诗','song-poetry','','[]','小堂穩暖紙窗明，低幌圍爐亦已成。',64,'全唐诗/poet.song.132000.json','["小堂穩暖紙窗明，低幌圍爐亦已成。", "日閱藏經忘歲月，時臨閣帖雜真行。", "詩才退後愁酣戰，酒量衰來喜細傾。", "從此過冬那復事，夜深時聽雪來聲。"]'),
('a476a846-ee35-4245-8625-2d5f6ad448f9','暖閣','陸游','宋','宋诗','song-poetry','','[]','裘軟勝狐白，爐溫等鴿青。',48,'全唐诗/poet.song.132000.json','["裘軟勝狐白，爐溫等鴿青。", "紙屏山字樣，布被隸書銘。", "養目簾稀卷，留香戶每扃。", "日晡濃睡起，盥濯誦黄庭。"]'),
('1d6534b0-b714-4764-aed5-88fcb1e4518d','自詠','陸游','宋','宋诗','song-poetry','','[]','朋舊凋零盡，乾坤偶脫遺。',48,'全唐诗/poet.song.132000.json','["朋舊凋零盡，乾坤偶脫遺。", "食新心竊喜，話舊語多悲。", "泥醉醒常少，貪眠起獨遲。", "閉門誰共處，枕藉樂天詩。"]'),
('401a01c2-5782-4c96-8712-63ae904bbb45','夜坐','陸游','宋','宋诗','song-poetry','','[]','白首仍多病，青燈獨掩扉。',24,'全唐诗/poet.song.132000.json','["白首仍多病，青燈獨掩扉。", "雲低聞雁過，雨急待兒歸。"]'),
('086e7215-63ad-40df-8c96-ab780ff4da9e','初冬有感二首  其一','陸游','宋','宋诗','song-poetry','','[]','衰髮蕭蕭滿鏡絲，情懷非復似平時。',64,'全唐诗/poet.song.132000.json','["衰髮蕭蕭滿鏡絲，情懷非復似平時。", "風霜十月流年感，砧杵三更游子悲。", "閩嶠故人消息惡，蜀江遺老素書遲。", "一簞豆飯休嫌薄，賦分羈窮合自知。"]'),
('11e84c56-c69a-4788-8cb1-2a37e6b13552','初冬有感二首  其二','陸游','宋','宋诗','song-poetry','','[]','峨冠本願致唐虞，白首那知墮腐儒。',64,'全唐诗/poet.song.132000.json','["峨冠本願致唐虞，白首那知墮腐儒。", "碌碌不成千載事，駸駸又見一年徂。", "無僧解輟齋厨米，有吏頻徵瘦地租。", "要信此翁頑到底，只持一笑了窮途。"]'),
('fb07f1bb-5a9f-4419-a3c5-43d9ae50c0fb','題酒家壁','陸游','宋','宋诗','song-poetry','','[]','智若禹行水，道如丁解牛。',48,'全唐诗/poet.song.132000.json','["智若禹行水，道如丁解牛。", "蘧蘧幾春夢，泛泛一虛舟。", "事定憂何益，狂來醉始休。", "青帘誇酒美，且復共登樓。"]'),
('fe6051f9-0910-4065-a0f3-f66f872dba7d','冬初出遊二首  其一','陸游','宋','宋诗','song-poetry','','[]','風聲如雨曉颼飀，萬葉丹楓滿瓦溝。',32,'全唐诗/poet.song.132000.json','["風聲如雨曉颼飀，萬葉丹楓滿瓦溝。", "西望牛頭三十里，一枝柔櫓作閑遊。"]'),
('f6bcf3d0-995f-4b40-981b-5fc627eae716','冬初出遊二首  其二','陸游','宋','宋诗','song-poetry','','[]','蹇驢渺渺涉烟津，十里山村發興新。',32,'全唐诗/poet.song.132000.json','["蹇驢渺渺涉烟津，十里山村發興新。", "青旆酒家黄葉寺，相逢俱是畫中人。"]'),
('12bfb47c-2ae8-4a47-9fce-e140764d23cc','早飯後戲作二首  其一','陸游','宋','宋诗','song-poetry','','[]','湯餅滿盂肥羜香，更留餘地著黄粱。',32,'全唐诗/poet.song.132000.json','["湯餅滿盂肥羜香，更留餘地著黄粱。", "解衣摩腹西窗下，莫怪人嘲作飯囊。"]'),
('8348b6d1-3d10-49ec-911e-20464aafa1e3','早飯後戲作二首  其二','陸游','宋','宋诗','song-poetry','','[]','髯鬚主簿方用事，冰壺先生來解圍。',32,'全唐诗/poet.song.132000.json','["髯鬚主簿方用事，冰壺先生來解圍。", "蠻童取火炷香碗，不讀南華誰與歸。"]'),
('27fc32d7-9c9e-48e6-9c61-c6be67e21104','擬古四首  其一','陸游','宋','宋诗','song-poetry','','[]','牛迹可使圜，羊角可使直。',48,'全唐诗/poet.song.132000.json','["牛迹可使圜，羊角可使直。", "惟使剛者柔，造物不可得。", "世方貴軟熟，剛實不可爲。", "爲剛死道傍，已矣何所悲。"]'),
('41a976e1-5a11-4caa-8737-9602421c066a','擬古四首  其二','陸游','宋','宋诗','song-poetry','','[]','君看一絇絲，能得幾日絡。',48,'全唐诗/poet.song.132000.json','["君看一絇絲，能得幾日絡。", "君思幾州鐵，打此一大錯。", "目前豈不快，後悔將奈何。", "我非通神明，比汝更事多。"]'),
('ee192cf7-8f38-4fb3-ac31-e59b56a32f46','擬古四首  其三','陸游','宋','宋诗','song-poetry','','[]','寧忍千日饑，野葛不可烹。',48,'全唐诗/poet.song.132000.json','["寧忍千日饑，野葛不可烹。", "寧枉百里途，捷徑不可行。", "自古風俗壞，善士亦淪胥。", "橘柚禹包貢，後世稱木奴。"]'),
('14a5ecc8-7b67-404a-bb9b-54b9c426d951','擬古四首  其四','陸游','宋','宋诗','song-poetry','','[]','坐卧北窗下，百事廢不治。',48,'全唐诗/poet.song.132000.json','["坐卧北窗下，百事廢不治。", "脫粟與大布，衣食裁自支。", "溫飽豈不欲，違道予心悲。", "地下見先人，所冀尚有辭。"]'),
('1065ea1e-b879-4b32-9336-e6448ee6675c','東村二首  其一','陸游','宋','宋诗','song-poetry','','[]','野人知我出門稀，男輟鉏耰女下機。',32,'全唐诗/poet.song.132000.json','["野人知我出門稀，男輟鉏耰女下機。", "掘得茈菇炊正熟，一杯苦勸護寒歸。"]'),
('82e5a45c-b39f-4044-8fa6-3fd3841100f1','東村二首  其二','陸游','宋','宋诗','song-poetry','','[]','野人喜我偶閑遊，取酒匆匆勸小留。',32,'全唐诗/poet.song.132000.json','["野人喜我偶閑遊，取酒匆匆勸小留。", "舍後携籃挑菜甲，門前喚擔買梨頭。"]'),
('389351dc-84c2-4d1d-9e62-c46a2da4c3bf','倚闌','陸游','宋','宋诗','song-poetry','','[]','滿庭晴日破朝寒，粥罷披裘小倚欄。',32,'全唐诗/poet.song.132000.json','["滿庭晴日破朝寒，粥罷披裘小倚欄。", "殘菊抱叢香欲盡，一株南燭獨如丹。"]'),
('123524ae-d10d-47e2-82e8-09e9a3c7ea4f','霜寒不能出戶偶書','陸游','宋','宋诗','song-poetry','','[]','垂老仍多病，濃霜得快晴。',48,'全唐诗/poet.song.132000.json','["垂老仍多病，濃霜得快晴。", "猶能挼菊醉，但負探梅行。", "篝火烘裘暖，油窗潑眼明。", "小兒殊可喜，和我讀書聲。"]'),
('f97c53dc-0731-4dc6-82ee-2ec98b90b926','冬晴與子坦子聿遊湖上六首  其一','陸游','宋','宋诗','song-poetry','','[]','湖邊細靄弄霏微，柳下人家晝掩扉。',32,'全唐诗/poet.song.132000.json','["湖邊細靄弄霏微，柳下人家晝掩扉。", "乘暖冬耕無遠近，小舟日晚載犁歸。"]'),
('2e1fbf29-475b-4612-a69f-4578a2e3961b','冬晴與子坦子聿遊湖上六首  其二','陸游','宋','宋诗','song-poetry','','[]','村南村北紡車鳴，打豆家家趁快晴。',32,'全唐诗/poet.song.132000.json','["村南村北紡車鳴，打豆家家趁快晴。", "過盡水邊牛迹路，嶺頭猿鳥伴閑行。"]'),
('79fc952c-999c-4c4a-bbed-5bc153b1b44a','冬晴與子坦子聿遊湖上六首  其三','陸游','宋','宋诗','song-poetry','','[]','道邊白水如牛湩，知是山泉一脈來。',32,'全唐诗/poet.song.132000.json','["道邊白水如牛湩，知是山泉一脈來。", "會挈風爐并石鼎，桃枝竹裏試茶杯。"]'),
('63d7b9de-c568-4db1-a803-67b0e34dcfef','冬晴與子坦子聿遊湖上六首  其四','陸游','宋','宋诗','song-poetry','','[]','海山山下百餘家，垣屋參差一带斜。',32,'全唐诗/poet.song.132000.json','["海山山下百餘家，垣屋參差一带斜。", "我欲往尋疑路斷，試沿流水覓桃花。"]'),
('a84f8452-5d3d-4662-9362-8f1ba335090f','冬晴與子坦子聿遊湖上六首  其五','陸游','宋','宋诗','song-poetry','','[]','老僧八十無童子，禮佛看經總不能。',32,'全唐诗/poet.song.132000.json','["老僧八十無童子，禮佛看經總不能。", "雙手丫叉出迎客，自稱六十六年僧。"]'),
('d6f80634-db55-49f7-be17-436d9b70dfbe','冬晴與子坦子聿遊湖上六首  其六','陸游','宋','宋诗','song-poetry','','[]','一榼無時可醉吟，一藤隨處得幽尋。',32,'全唐诗/poet.song.132000.json','["一榼無時可醉吟，一藤隨處得幽尋。", "先須挽取銀河水，凈洗人間塵霧心。"]'),
('440b6ee3-22a7-485f-88cb-1fbd20446bbb','夢蜀','陸游','宋','宋诗','song-poetry','','[]','夢飲成都好事家，新妝執樂雁行斜。',64,'全唐诗/poet.song.132000.json','["夢飲成都好事家，新妝執樂雁行斜。", "赬肩郫縣千筒酒，照眼彭州百馱花。", "醉帽傾欹歌未闋，罰觥瀲灧笑方譁。", "霜鐘喚覺晨窗白，自怪無端一念差。"]'),
('164f1105-fb69-42b8-9607-3880c09bfa5c','歲晚二首  其一','陸游','宋','宋诗','song-poetry','','[]','無窮世事浩難量，歲晚沉綿卧草堂。',64,'全唐诗/poet.song.132000.json','["無窮世事浩難量，歲晚沉綿卧草堂。", "短褐坼圖移曲折，故書經蠹失偏傍。", "賣刀擬買春耕犢，挾策曾亡舊牧羊。", "點檢生涯還自笑，菜畦殘葉带新霜。"]'),
('73033832-9189-4107-8d5a-5db1a18fe11a','歲晚二首  其二','陸游','宋','宋诗','song-poetry','','[]','扶藤據几久支離，敢料駸駸迫耄期。',64,'全唐诗/poet.song.132000.json','["扶藤據几久支離，敢料駸駸迫耄期。", "面槁自丹天所借，齒摇復住力何施。", "花前鯨吸猶堪酒，窗底蟬嘶未廢詩。", "浮世極知誰不死，比君終校幾年遲。"]'),
('337d189d-f1b4-496f-aef6-99a4c766c893','讀老子','陸游','宋','宋诗','song-poetry','','[]','道德五千言，巍巍眾妙門。',48,'全唐诗/poet.song.132000.json','["道德五千言，巍巍眾妙門。", "管窺那見豹，指染僅嘗黿。", "正爾分章句，誰歟達本源。", "蜀莊猶不死，過我得深論。"]'),
('e5c26bd4-6398-4a68-86de-db3bddec655b','貧病','陸游','宋','宋诗','song-poetry','','[]','窮愁病思兩茫茫，衰髮元知合變霜。',64,'全唐诗/poet.song.132000.json','["窮愁病思兩茫茫，衰髮元知合變霜。", "酒要解酲猶有策，食求祝噎更無方。", "凋零坐上親朋少，寂寞人間歲月長。", "默計有時還自幸，幼安垂老始歸鄉。"]'),
('31f3e33a-017a-45b4-8fdc-785179e4cb3e','洪雅葛仙硯','陸游','宋','宋诗','song-poetry','','[]','異硯出漢嘉，溫潤蒼玉質。',96,'全唐诗/poet.song.132000.json','["異硯出漢嘉，溫潤蒼玉質。", "因形作獸背，得墨如點漆。", "才高德亦全，終月不更筆。", "蠻溪大沱輩，烏敢相甲乙。", "從我歸吳中，略計將萬日。", "摩拂不去手，有若琴在膝。", "名晦知者稀，體重盜計窒。", "惟當草太玄，不污管商術。"]'),
('3187183d-3650-44f0-8eae-ba50b0b83fd6','冬日讀白集愛其貧堅志士節病長高人情之句作古風十首  其一','陸游','宋','宋诗','song-poetry','','[]','君子亦有慕，不慕要路津。',48,'全唐诗/poet.song.132000.json','["君子亦有慕，不慕要路津。", "君子亦有耻，不耻賤與貧。", "風俗未唐虞，詩書非一秦。", "展轉不能瞑，卧聽雞唱晨。"]'),
('4b0bdfde-36f3-4033-9696-5f4dd0e727fd','冬日讀白集愛其貧堅志士節病長高人情之句作古風十首  其二','陸游','宋','宋诗','song-poetry','','[]','天下不難一，孰能凝使堅。',48,'全唐诗/poet.song.132000.json','["天下不難一，孰能凝使堅。", "自古功已成，或散如飛烟。", "惟唐用房魏，規模三百年。", "至今河潼路，過者猶泫然。"]'),
('00059d09-89fd-4a63-8135-b1b4e80407a7','冬日讀白集愛其貧堅志士節病長高人情之句作古風十首  其三','陸游','宋','宋诗','song-poetry','','[]','漢禍始外戚，唐亂基宦寺。',48,'全唐诗/poet.song.132000.json','["漢禍始外戚，唐亂基宦寺。", "小人計已私，頗復指他事。", "公卿恬駭機，關河入危涕。", "草茅豈無人，死抱經世志。"]'),
('d0904ab1-bdc8-49a4-b353-4dbb49179c2f','冬日讀白集愛其貧堅志士節病長高人情之句作古風十首  其四','陸游','宋','宋诗','song-poetry','','[]','成童入鄉校，所願爲善士。',48,'全唐诗/poet.song.132000.json','["成童入鄉校，所願爲善士。", "富貴本邂逅，不遇亦已矣。", "生輕名義重，固守當以死。", "堂堂七尺軀，勿使污青史。"]'),
('234cd8da-ee89-41e5-877d-a647e0ea93d7','冬日讀白集愛其貧堅志士節病長高人情之句作古風十首  其五','陸游','宋','宋诗','song-poetry','','[]','勁風東北來，茆屋吹欲裂。',48,'全唐诗/poet.song.132000.json','["勁風東北來，茆屋吹欲裂。", "出門有奇觀，湖上千峰雪。", "日高炊未具，歲晚衣百結。", "士豈無一長，所要全大節。"]'),
('556714d3-d133-492b-80ad-02a637a2f11e','冬日讀白集愛其貧堅志士節病長高人情之句作古風十首  其六','陸游','宋','宋诗','song-poetry','','[]','吾常慕昔人，石介與王令。',48,'全唐诗/poet.song.132000.json','["吾常慕昔人，石介與王令。", "挑燈讀其文，奮起失衰病。", "吾徒宗六經，崇雅必放鄭。", "人眾何足云，少忍待天定。"]'),
('1491ed26-c7b4-4496-b5b9-8359bf8a4289','冬日讀白集愛其貧堅志士節病長高人情之句作古風十首  其七','陸游','宋','宋诗','song-poetry','','[]','郊居四十年，草木日夜長。',48,'全唐诗/poet.song.132000.json','["郊居四十年，草木日夜長。", "喬松已偃蓋，稚松出蓁莽。", "儒生學仁義，敢廢自培養。", "鬰鬰棟梁姿，拔地當百丈。"]'),
('136bef5b-a251-4ee5-947d-7b97d1dfe2f5','冬日讀白集愛其貧堅志士節病長高人情之句作古風十首  其八','陸游','宋','宋诗','song-poetry','','[]','仕如柳柳州，箋奏典儀曹。',48,'全唐诗/poet.song.132000.json','["仕如柳柳州，箋奏典儀曹。", "君恩篤始終，賜骸老東皋。", "歷觀親黨間，如我亦已遭。", "世世當斂退，里門不須高。"]'),
('56efcf37-a707-4dfb-a99e-5c8e537b4acc','冬日讀白集愛其貧堅志士節病長高人情之句作古風十首  其九','陸游','宋','宋诗','song-poetry','','[]','鏡湖有隱者，莫知何許人。',48,'全唐诗/poet.song.132000.json','["鏡湖有隱者，莫知何許人。", "出與風月遊，居與猿鳥鄰。", "似生結繩代，或是葛天民。", "我欲往從之，烟波浩無津。"]'),
('453fc5c4-823d-47ab-8cab-0caad44180fc','冬日讀白集愛其貧堅志士節病長高人情之句作古風十首  其一○','陸游','宋','宋诗','song-poetry','','[]','卜日家祭竈，牲肥酒香清。',48,'全唐诗/poet.song.132000.json','["卜日家祭竈，牲肥酒香清。", "分胙雖薄少，要是鄰里情。", "眾起壽主人，一觥瀲灧傾。", "氣衰易成醉，睡覺窗已明。"]'),
('5e6bd78e-fe20-4dc2-9fa9-6a3edbed51b3','十一月四日夜半枕上口占','陸游','宋','宋诗','song-poetry','','[]','小室愔愔夜向分，幽人殘睡带殘醺。',64,'全唐诗/poet.song.132000.json','["小室愔愔夜向分，幽人殘睡带殘醺。", "簷間雨滴愁偏覺，枕畔橙香夢亦聞。", "驚雁數聲投野澤，悲笳三疊上霜雲。", "年來萬事俱拋盡，自笑詩中尚策勳。"]'),
('9413058c-0330-4c96-963f-bc82d6a2c5f2','齋中弄筆偶書示子聿','陸游','宋','宋诗','song-poetry','','[]','左右琴樽靜不譁，放翁新作老生涯。',64,'全唐诗/poet.song.132000.json','["左右琴樽靜不譁，放翁新作老生涯。", "焚香細讀斜川集，候火親烹顧渚茶。", "書爲半酣差近古，詩雖苦思未名家。", "一窗殘日呼愁起，裊裊江城咽暮笳。"]'),
('69c2dd3a-8d4c-4f34-9283-61051628df02','饑寒吟','陸游','宋','宋诗','song-poetry','','[]','夜寒每達旦，懷抱安得寬。',96,'全唐诗/poet.song.132000.json','["夜寒每達旦，懷抱安得寬。", "朝饑或過午，忍此良亦難。", "饑寒誠吾憂，憂有甚饑寒。", "彈琴不終曲，推去發永嘆。", "大兒破綠襦，三歲待一官。", "小兒學耕稼，飯牛歌夜闌。", "老翁垂八十，捫壁行蹣跚。", "傍觀勿嘲笑，窮死心所安。"]'),
('fb26c0ee-c14a-4b7d-bc5d-b83c1c3de9da','病愈小健戲作二首  其一','陸游','宋','宋诗','song-poetry','','[]','路入江村跨蹇驢，鞍前分挂兩囊書。',32,'全唐诗/poet.song.132000.json','["路入江村跨蹇驢，鞍前分挂兩囊書。", "興來到處沽新酒，不爲閑愁要破除。"]'),
('36cfb5d3-5d96-4b66-9b08-16f2b97543c6','病愈小健戲作二首  其二','陸游','宋','宋诗','song-poetry','','[]','入市歸村不跨驢，蠅頭細字夜鈔書。',32,'全唐诗/poet.song.132000.json','["入市歸村不跨驢，蠅頭細字夜鈔書。", "身安自勝閑官職，不是虛名暗折除。"]'),
('7eed96fc-e44b-4fad-8bae-204a9c0999df','祭竈與鄰曲散福','陸游','宋','宋诗','song-poetry','','[]','已幸懸車示子孫，正須祭竈請比鄰。',64,'全唐诗/poet.song.132000.json','["已幸懸車示子孫，正須祭竈請比鄰。", "歲時風俗相傳久，賓主歡娛一笑新。", "雪鬢坐深知敬老，瓦盆酌滿不羞貧。", "問君此夕茅簷底，何似原頭樂社神。"]'),
('85c9026a-85b5-4a80-a047-dd0ab0a75801','湖水愈縮戲作','陸游','宋','宋诗','song-poetry','','[]','瓜壟從來幾邵平，鏡湖復有一玄英。',32,'全唐诗/poet.song.132000.json','["瓜壟從來幾邵平，鏡湖復有一玄英。", "今秋雨少烟波窄，堪笑沙鷗也敗盟。"]'),
('7f7493f1-fa6c-45df-a746-402dd13e6580','夜坐','陸游','宋','宋诗','song-poetry','','[]','夜永霜濃睡不成，團欒兒女話無生。',32,'全唐诗/poet.song.132000.json','["夜永霜濃睡不成，團欒兒女話無生。", "金蓮妄想消除盡，一碗松肪徹曉明。"]'),
('6613e138-daa7-4277-9081-b27443e73e1f','夢中作遊山絕句二首  其一','陸游','宋','宋诗','song-poetry','','[]','霜風吹帽江村路，小蹇迢迢委轡行。',32,'全唐诗/poet.song.132000.json','["霜風吹帽江村路，小蹇迢迢委轡行。", "忽到雲山幽絕處，穿林啼鳥不知名。"]'),
('f316a1ee-459d-4956-b532-c0dddfc67469','夢中作遊山絕句二首  其二','陸游','宋','宋诗','song-poetry','','[]','寺樓已斷暮鐘聲，照佛琉璃一點明。',32,'全唐诗/poet.song.132000.json','["寺樓已斷暮鐘聲，照佛琉璃一點明。", "不道溪深待船久，老僧驚怪太遲生。"]'),
('32232f44-0404-4321-bf52-fabbbf3e9047','大侄挽辭','陸游','宋','宋诗','song-poetry','','[]','束髮已青袍，終身州縣勞。',48,'全唐诗/poet.song.132000.json','["束髮已青袍，終身州縣勞。", "一官常骯髒，萬里忽焄蒿。", "竟負昂霄志，空傳擲印豪。", "兩疏心不遂，遺恨寄滔滔。"]'),
('44e013dc-ab35-4335-82ec-f8f3bfce4302','書幸二首  其一','陸游','宋','宋诗','song-poetry','','[]','富貴不可爲，禍機發須臾。',96,'全唐诗/poet.song.132000.json','["富貴不可爲，禍機發須臾。", "貧賤不可爲，饑寒死路衢。", "我亦貧賤者，死期幸少紓。", "春雨兩耕犢，西疇破烟蕪。", "秋風一釣舟，南浦宿菰蒲。", "辛勤異退之，亦復有屋廬。", "堂北鑿明窗，可以陳琴書。", "文章不傳世，自適亦有餘。"]'),
('7da83982-3210-4b74-907c-bebb3c8321e8','書幸二首  其二','陸游','宋','宋诗','song-poetry','','[]','我身匪兕虎，豈是曠野物。',96,'全唐诗/poet.song.132000.json','["我身匪兕虎，豈是曠野物。", "生非洪水時，胡爲在巢窟。", "向來三入朝，薄命不黔突。", "未嘗識許史，况敢交平勃。", "滄波渺黏天，遠逐輕鷗沒。", "今年君恩厚，幸許賜骸骨。", "既逃申公鉗，又異卞和刖。", "放懷歌嗚嗚，寧暇書咄咄。"]'),
('3e842bbe-7ecb-4ef6-a309-50b1e1da5046','退居','陸游','宋','宋诗','song-poetry','','[]','溪烟漠漠弈棋軒，筧水潺潺種藥園。',64,'全唐诗/poet.song.132000.json','["溪烟漠漠弈棋軒，筧水潺潺種藥園。", "醫爲疾平新掃迹，客知睡美罕敲門。", "談餘白拂懸床角，飲散空樽卧壁根。", "賜帛更蒙優老詔，此生何以報君恩。"]'),
('f86d62b3-69b3-42c0-b394-b34d127b7f87','北望感懷','陸游','宋','宋诗','song-poetry','','[]','榮河溫洛帝王州，七十年來禾黍秋。',64,'全唐诗/poet.song.132000.json','["榮河溫洛帝王州，七十年來禾黍秋。", "大事竟爲朋黨誤，遺民空嘆歲時遒。", "乾坤恨入新豐酒，霜露寒侵季子裘。", "食粟本同天下責，孤臣敢獨廢深憂。"]'),
('c893803d-b7cf-41ae-aafc-be0adc033c7d','白髮','陸游','宋','宋诗','song-poetry','','[]','蕭蕭白髮濯滄浪，剡曲西南一草堂。',64,'全唐诗/poet.song.132000.json','["蕭蕭白髮濯滄浪，剡曲西南一草堂。", "飲水讀書貧亦樂，杜門養病老何傷。", "已成五畝扶犁叟，誰記三朝執戟郎。", "正似籬邊數枝菊，歲殘猶復耐冰霜。"]'),
('359bcac1-104b-48ca-824e-ebe6dc0860e8','老嘆','陸游','宋','宋诗','song-poetry','','[]','事與年俱往，心於世轉疏。',48,'全唐诗/poet.song.132000.json','["事與年俱往，心於世轉疏。", "曼膚銷欲盡，鬒髮變無餘。", "野店通賒酒，鄰翁伴荷鉏。", "尚嗟餘習在，夢課吏鈔書。"]'),
('320ebb24-1e9e-436b-bc51-b74481c82d90','作竹籬成因把酒其間戲題四十字','陸游','宋','宋诗','song-poetry','','[]','今日偶暄暖，卧聞林鳥呼。',48,'全唐诗/poet.song.132000.json','["今日偶暄暖，卧聞林鳥呼。", "雖思大白飲，未免小蒼扶。", "柳色動籬外，梅花來座隅。", "夕陽紅滿野，更復倒殘壺。"]'),
('cb3050d3-cf0d-4978-8d4f-896c631e5b63','新養白雞毛羽如玉殊可愛','陸游','宋','宋诗','song-poetry','','[]','赤幘峨峨玉羽明，籬間新織竹籠成。',32,'全唐诗/poet.song.132000.json','["赤幘峨峨玉羽明，籬間新織竹籠成。", "老人從此知昏曉，不用元戎報五更。"]'),
('9bfddc01-a71b-4b1f-8ba1-3498a97a425f','新籬','陸游','宋','宋诗','song-poetry','','[]','新籬三面北通門，藤架陰中細路分。',64,'全唐诗/poet.song.132000.json','["新籬三面北通門，藤架陰中細路分。", "天宇淡青成卵色，水波微皺作靴紋。", "參差村舍穿林出，縹緲漁歌隔浦聞。", "忽覺楚鄉來眼底，欲題幽句吊湘君。"]'),
('9bf6ea3c-b1cb-4b34-9001-9f7ceeb09475','龜堂雜興十首  其一','陸游','宋','宋诗','song-poetry','','[]','朝來地碓玉新舂，雞蹠豚肩異味重。',32,'全唐诗/poet.song.132000.json','["朝來地碓玉新舂，雞蹠豚肩異味重。", "便腹摩挲更無事，老人又過一年冬。"]'),
('c52a1765-05f6-4f3d-bd82-263acb383192','龜堂雜興十首  其二','陸游','宋','宋诗','song-poetry','','[]','曳杖東岡信步行，夕陽偏向竹間明。',32,'全唐诗/poet.song.132000.json','["曳杖東岡信步行，夕陽偏向竹間明。", "丹楓吹盡鴉聲樂，又得霜天一日晴。"]'),
('ff9c00b0-5b19-4837-b5f6-e90bde9f7331','龜堂雜興十首  其三','陸游','宋','宋诗','song-poetry','','[]','閩溪紙被軟於綿，黎峒花紬暖勝氈。',32,'全唐诗/poet.song.132000.json','["閩溪紙被軟於綿，黎峒花紬暖勝氈。", "一夜山中三尺雪，未妨老子日高眠。"]'),
('7c799d00-dbb2-4f62-a1eb-a534fa0b7d41','龜堂雜興十首  其四','陸游','宋','宋诗','song-poetry','','[]','三分带苦檜花蜜，一點無塵柏子香。',32,'全唐诗/poet.song.132000.json','["三分带苦檜花蜜，一點無塵柏子香。", "鼻觀舌根俱得道，悠悠誰識老龜堂。"]'),
('657ce3da-6a7d-41d5-a68b-ad8c94ad3c95','龜堂雜興十首  其五','陸游','宋','宋诗','song-poetry','','[]','方石斛栽香百合，小盆山養水黄楊。',32,'全唐诗/poet.song.132000.json','["方石斛栽香百合，小盆山養水黄楊。", "老翁不是童兒態，無奈庵中白日長。"]'),
('02cb99ba-e54c-4065-a816-90e345196bfc','龜堂雜興十首  其六','陸游','宋','宋诗','song-poetry','','[]','少年身寄市朝中，俗論紛紛聒耳聾。',32,'全唐诗/poet.song.132000.json','["少年身寄市朝中，俗論紛紛聒耳聾。", "清絕寧知有今日，高眠終夜聽松風。"]'),
('60ba8f2f-a73e-4a09-b6e5-1c778002c756','龜堂雜興十首  其七','陸游','宋','宋诗','song-poetry','','[]','二三鄰曲偶相尋，小醉悠然卧竹陰。',32,'全唐诗/poet.song.132000.json','["二三鄰曲偶相尋，小醉悠然卧竹陰。", "醒後自看還自笑，溪雲猶未是無心。"]'),
('78713696-5e61-43c6-ac46-e3b19937fbbe','龜堂雜興十首  其八','陸游','宋','宋诗','song-poetry','','[]','蒲團安坐地爐溫，無位真人出面門。',32,'全唐诗/poet.song.132000.json','["蒲團安坐地爐溫，無位真人出面門。", "世上不知何歲月，斷鐘殘角送黄昏。"]'),
('83e0b959-f27f-411c-b415-8203da2da264','龜堂雜興十首  其九','陸游','宋','宋诗','song-poetry','','[]','道妙從來亦粗聞，閉門方用十年勤。',32,'全唐诗/poet.song.132000.json','["道妙從來亦粗聞，閉門方用十年勤。", "筆端小技深知悔，舊稿如山欲盡焚。"]'),
('470e045c-b716-4054-b9c8-1322fe5e6da4','龜堂雜興十首  其一○','陸游','宋','宋诗','song-poetry','','[]','散樸澆淳萬事新，腐儒空有涕沾巾。',32,'全唐诗/poet.song.132000.json','["散樸澆淳萬事新，腐儒空有涕沾巾。", "唐虞不是終難致，自欠皋夔一輩人。"]'),
('f1265399-fbd3-4f91-a2db-c2101d5239e2','己未冬至','陸游','宋','宋诗','song-poetry','','[]','老人畏添歲，每嘆時序速。',96,'全唐诗/poet.song.132000.json','["老人畏添歲，每嘆時序速。", "今朝陽始生，在易得來復。", "扶衰奉先祭，拜起賴童僕。", "兒曹亦壽我，魚兔隨事足。", "歡言爲一醉，家釀及新熟。", "占年當得稔，喜笑動鄰曲。", "冀從宿麥始，載重車折軸。", "明年秋社時，處處饜酒肉。"]'),
('0f5f5b69-b11e-4ce0-bb2d-b5b2cfcb07df','冬至夜坐作短歌','陸游','宋','宋诗','song-poetry','','[]','一陽萌生從此日，老人堅坐午達夕。',67,'全唐诗/poet.song.132000.json','["一陽萌生從此日，老人堅坐午達夕。", "渾渾上泝河流黄，赫赫內視神珠赤。", "愛如嬰兒未離乳，危若遊絲裊千尺。", "君不見宣房塞河百萬人，一旦橫流由蟻隙。"]'),
('28e5b466-d24b-4037-9193-6ab6ad958dba','新裁短褐接客以代戎服或以爲慢戲作','陸游','宋','宋诗','song-poetry','','[]','世事巧相違，殘年幸許歸。',48,'全唐诗/poet.song.132000.json','["世事巧相違，殘年幸許歸。", "雖云裁兔褐，不擬出漁扉。", "拂石襟靈爽，搘筇氣力微。", "朝衣猶挂却，况遣著戎衣。"]'),
('28f4c2d0-7e2d-4565-800f-d577da343ae9','冬夜','陸游','宋','宋诗','song-poetry','','[]','多病睡眠少，長閑懷抱清。',48,'全唐诗/poet.song.132000.json','["多病睡眠少，長閑懷抱清。", "昏燈照殘夢，寒漏下高城。", "落月澹將沒，棲禽靜復驚。", "誰言冬夜永，輾轉已窗明。"]'),
('12ef7dfa-488b-407a-94aa-187fc3aefe13','書感','陸游','宋','宋诗','song-poetry','','[]','壯歲功名妄自期，晚途流落鬢成絲。',64,'全唐诗/poet.song.132000.json','["壯歲功名妄自期，晚途流落鬢成絲。", "臨風畫角曉三弄，釀雪野雲寒四垂。", "金鎖甲思酣戰地，皂貂裘記遠遊時。", "此心炯炯空添泪，青史它年未必知。"]'),
('6f515c05-9c10-468b-bb63-f0ca1d45ffca','書意','陸游','宋','宋诗','song-poetry','','[]','頷霜久矣不勝耘，殘髮今年白十分。',64,'全唐诗/poet.song.132000.json','["頷霜久矣不勝耘，殘髮今年白十分。", "憂國雖忘嫠婦緯，愛君敢進野人芹。", "床頭酒滴空階雨，爐面香橫出岫雲。", "已向人間齊物我，不教驚起白鷗群。"]'),
('a751321f-2401-46ee-87fd-5328c39cd2da','試茶','陸游','宋','宋诗','song-poetry','','[]','强飯年來幸未衰，睡魔百萬要支持。',64,'全唐诗/poet.song.132000.json','["强飯年來幸未衰，睡魔百萬要支持。", "難從陸羽毀茶論，寧和陶潜止酒詩。", "乳井簾泉方徧試，柘羅銅碾雅相宜。", "山僧剝啄知誰報，正是松風欲動時。"]'),
('b1b52ecd-f132-4f52-a244-86efa75b01ab','對酒懷丹陽成都故人','陸游','宋','宋诗','song-poetry','','[]','勞生常羨髑髏樂，死時却悔生時錯。',128,'全唐诗/poet.song.132000.json','["勞生常羨髑髏樂，死時却悔生時錯。", "花前有酒不肯狂，回首朱顔已非昨。", "君看古來賢達人，終日飲酒全其真。", "世間萬事竟何有，金樽翠杓差關身。", "放翁少日無凡客，飛觴縱樂皆豪傑。", "清歌一曲梁塵起，腰鼓百面春雷發。", "故人仙去蓬萊宮，鸞絲鳳竹醉春風。", "石帆山下孤舟雪，一段清愁付此翁。"]'),
('a7ea2616-2c72-4693-b300-0711b8df854c','三山卜居三十有四年矣老身七十有五兒輩亦頗宦學未爲非吉也偶作五字示諸兒','陸游','宋','宋诗','song-poetry','','[]','買地不占龜，心知百世宜。',48,'全唐诗/poet.song.132000.json','["買地不占龜，心知百世宜。", "西鄰梅福隱，南望項王祠。", "庵小偷僧樣，陂長按古規。", "保家無異法，一念勿萌欺。"]'),
('2de717dc-f06e-42ce-bf33-2b5d71e48417','村興','陸游','宋','宋诗','song-poetry','','[]','身老交情見，孫生口數添。',48,'全唐诗/poet.song.132000.json','["身老交情見，孫生口數添。", "園丁上牛米，村婢博蠶鹽。", "粔籹堆盤白，餦餭出釜甜。", "閉門君勿誚，衰病正相兼。"]'),
('328f0813-ea79-460e-b551-69e35a92f4a8','枕上','陸游','宋','宋诗','song-poetry','','[]','迢遞孤村夜，凄凉半篆香。',48,'全唐诗/poet.song.132000.json','["迢遞孤村夜，凄凉半篆香。", "懷人悲夢短，聽雨怯更長。", "有術乾盤汞，無方掃鬢霜。", "高吟擬排悶，吟罷更倀倀。"]'),
('a9913683-7b7d-4de1-abf7-35cfe136b6ad','得建業倅鄭覺民書言虜亂自淮以北民苦徵調皆望王師之至','陸游','宋','宋诗','song-poetry','','[]','邦命中興漢，天心大討曹。',48,'全唐诗/poet.song.132000.json','["邦命中興漢，天心大討曹。", "風雲助開泰，河渭蕩腥臊。", "日避揮戈勇，山齊積甲高。", "煌煌祖宗業，只在馭群豪。"]'),
('9f79b8aa-6141-4720-8e9d-e17fc856d4d4','雨夜讀書','陸游','宋','宋诗','song-poetry','','[]','農家冬少事，無地肆吾勤。',48,'全唐诗/poet.song.132000.json','["農家冬少事，無地肆吾勤。", "急雨生新健，陳編寄一欣。", "高風感莘渭，善治仰華勳。", "老死今朝夕，何由誦所聞。"]'),
('0c611e61-74be-4421-858a-6edab3cf505e','夢中作','陸游','宋','宋诗','song-poetry','','[]','長堤行盡古河濆，小市人稀霧雨昏。',64,'全唐诗/poet.song.132000.json','["長堤行盡古河濆，小市人稀霧雨昏。", "櫪馬垂頭嚙菅草，驛門移路避槐根。", "斷碑零落苔俱徧，漏壁微茫字半存。", "催喚厨人燎狐兔，强排旅思舉清樽。"]'),
('9e31deaa-60de-4447-b6ff-155d8ffb1a6f','題傳神','陸游','宋','宋诗','song-poetry','','[]','雪鬢蕭然兩頰紅，人間隨處見神通。',64,'全唐诗/poet.song.132000.json','["雪鬢蕭然兩頰紅，人間隨處見神通。", "半醒半醉常終日，非士非農一老翁。", "櫪驥雖存千里志，雲鵬已息九天風。", "巉巉骨法吾能相，難著凌烟劍佩中。"]'),
('b317ae99-bf4c-4673-b2d7-80b6566faa0d','紀懷','陸游','宋','宋诗','song-poetry','','[]','未斸要離冢畔雲，儈牛得食寄鄉枌。',64,'全唐诗/poet.song.132000.json','["未斸要離冢畔雲，儈牛得食寄鄉枌。", "修身本欲善吾死，臨事豈忘尊所聞。", "時序管寧親饋奠，江山龐老上丘墳。", "飾巾家簀從來事，萬種悠悠莫苦分。"]'),
('a0955ff7-2d37-42ec-82d3-b6f175ec4202','新作柴門戲書','陸游','宋','宋诗','song-poetry','','[]','雖設常關果是麽，開門終日有誰過。',64,'全唐诗/poet.song.132000.json','["雖設常關果是麽，開門終日有誰過。", "從來不省多車轍，此際真宜置爵羅。", "尚許漁樵時剝啄，偶逢風月亦婆娑。", "炎炎炙手須臾事，也比柴荆較幾何。"]'),
('98db737e-6841-47f7-839f-682eb01e0794','炊飯','陸游','宋','宋诗','song-poetry','','[]','米分齋鉢供，薪拾墮巢枝。',48,'全唐诗/poet.song.132000.json','["米分齋鉢供，薪拾墮巢枝。", "偶爾成幽事，欣然慰午饑。", "炊時珠瀉甑，嘗處雪翻匙。", "欲作明朝計，還須賣漉籬。"]'),
('f89eaa89-485f-4fe0-8b78-3197fa13f2cc','愛閑','陸游','宋','宋诗','song-poetry','','[]','今日先生病體輕，愛閑猶有舊心情。',64,'全唐诗/poet.song.132000.json','["今日先生病體輕，愛閑猶有舊心情。", "帖看貞觀行間印，琴記中郎爨下聲。", "衣焙溫溫香欲透，雪簷滴滴日初晴。", "客來一笑明窗底，枉道爲農事耦耕。"]'),
('bc1ad86a-11eb-4918-acec-55f848f20db1','與子聿讀經因書小詩示之','陸游','宋','宋诗','song-poetry','','[]','經中固多趣，我老未能忘。',48,'全唐诗/poet.song.132000.json','["經中固多趣，我老未能忘。", "似獲連城璧，如傾九醞觴。", "信能明孔氏，何暇傲羲皇。", "努力晨昏事，躬行味始長。"]'),
('0db538da-062a-441a-bfb4-781916a32c5f','登東山','陸游','宋','宋诗','song-poetry','','[]','老慣人間歲月催，强扶衰病上崔嵬。',64,'全唐诗/poet.song.132000.json','["老慣人間歲月催，强扶衰病上崔嵬。", "生爲柱國細事爾，死畫雲臺何有哉。", "熟計提軍出青海，未如喚客倒金罍。", "明朝日出春風動，更看晴天萬里開。"]'),
('cf448aef-2daa-4a73-a939-80cb136779d1','己未歲暮','陸游','宋','宋诗','song-poetry','','[]','七十六年將到時，龍鍾猶復强支持。',64,'全唐诗/poet.song.132000.json','["七十六年將到時，龍鍾猶復强支持。", "寒燈照影始知瘦，薄酒作酲方覺衰。", "春日尚能持冷餅，花時未礙插繁枝。", "癡頑應有傍觀笑，自課園丁補槿籬。"]'),
('e97742c0-8838-4b60-942a-50362d26fea3','冬夜讀書示子聿八首  其一','陸游','宋','宋诗','song-poetry','','[]','宦途至老無餘俸，貧悴還如筮仕初。',32,'全唐诗/poet.song.132000.json','["宦途至老無餘俸，貧悴還如筮仕初。", "賴有一籌勝富貴，小兒讀遍舊藏書。"]'),
('549e56b7-8083-4696-b350-864ef567566c','冬夜讀書示子聿八首  其二','陸游','宋','宋诗','song-poetry','','[]','易經獨不遭秦火，字字皆如見聖人。',32,'全唐诗/poet.song.132000.json','["易經獨不遭秦火，字字皆如見聖人。", "汝始弱齡吾已耄，要當致力各終身。"]'),
('1057cee4-bf1d-4c46-bf73-8ed5357f7790','冬夜讀書示子聿八首  其三','陸游','宋','宋诗','song-poetry','','["\u52b1\u5fd7", "\u54f2\u7406", "\u8bfb\u4e66"]','古人學問無遺力，少壯工夫老始成。',32,'全唐诗/poet.song.132000.json','["古人學問無遺力，少壯工夫老始成。", "紙上得來終覺淺，絕知此事要躬行。"]'),
('1116be11-28c9-4884-84b0-33ec172d12f5','冬夜讀書示子聿八首  其四','陸游','宋','宋诗','song-poetry','','[]','簡斷編殘字欲無，吾兒不負乃翁書。',32,'全唐诗/poet.song.132000.json','["簡斷編殘字欲無，吾兒不負乃翁書。", "絕勝鎖向朱門裏，整整牙籤飽蠹魚。"]'),
('b1546d0d-92cc-45e3-a722-3620910ff029','冬夜讀書示子聿八首  其五','陸游','宋','宋诗','song-poetry','','[]','聖師雖遠有遺經，萬世猶傳舊典刑。',32,'全唐诗/poet.song.132000.json','["聖師雖遠有遺經，萬世猶傳舊典刑。", "白首自憐心未死，夜窗風雪一燈青。"]'),
('a93cbb6c-2933-43bd-a0b4-3f3ea3751147','冬夜讀書示子聿八首  其六','陸游','宋','宋诗','song-poetry','','[]','殘雪初消薺滿園，糝羹珍美勝羔豚。',32,'全唐诗/poet.song.132000.json','["殘雪初消薺滿園，糝羹珍美勝羔豚。", "吾曹舌本能知此，古學工夫始可言。"]'),
('13779248-f946-4cc8-89b0-5a3ec29f0f7d','冬夜讀書示子聿八首  其七','陸游','宋','宋诗','song-poetry','','[]','讀書萬卷不謀食，脫粟在傍書在前。',32,'全唐诗/poet.song.132000.json','["讀書萬卷不謀食，脫粟在傍書在前。", "要識從來會心處，曲肱飲水亦欣然。"]'),
('16512cfa-5be7-4843-b653-450babdc8e47','冬夜讀書示子聿八首  其八','陸游','宋','宋诗','song-poetry','','[]','世間萬事有乘除，自笑羸然七十餘。',32,'全唐诗/poet.song.132000.json','["世間萬事有乘除，自笑羸然七十餘。", "布被藜羹緣未盡，閉門更讀數年書。"]'),
('98a6d6b3-6dad-464c-aa33-4afbf9d7ee6b','幽興','陸游','宋','宋诗','song-poetry','','[]','午倦便高枕，朝饑美小飧。',48,'全唐诗/poet.song.132000.json','["午倦便高枕，朝饑美小飧。", "時穿幽圃屐，常掩小庵門。", "溪憶鷗盟約，花迷蝶夢魂。", "餘生猶幾許，萬事付乾坤。"]'),
('f8ba46f9-7f68-4ee9-a8a0-c83d47e4e5f8','寓嘆','陸游','宋','宋诗','song-poetry','','[]','眼底誰爲耐久朋，倚肩按膝一烏藤。',64,'全唐诗/poet.song.132000.json','["眼底誰爲耐久朋，倚肩按膝一烏藤。", "虛名但可欺橫目，薄俗何時復結繩。", "浮世百年悲冉冉，閑身萬事付騰騰。", "年來更嘆龍鍾甚，欲探梅花病不能。"]'),
('44b83668-7a13-44f1-8521-7d6b7a4659ca','夢題驛壁','陸游','宋','宋诗','song-poetry','','[]','半生征袖厭風埃，又向關門把酒杯。',64,'全唐诗/poet.song.132000.json','["半生征袖厭風埃，又向關門把酒杯。", "車轍自隨芳草遠，歲華無奈夕陽催。", "驛前歷歷堠雙隻，陌上悠悠人去來。", "不爲途窮身易老，百年回首總堪哀。"]'),
('f5dcc8e6-94d1-41a6-a87e-891940478ef1','新春','陸游','宋','宋诗','song-poetry','','[]','柳淡春初破，梅寒瘦不禁。',48,'全唐诗/poet.song.132000.json','["柳淡春初破，梅寒瘦不禁。", "羈愁醉後減，睡思雨中深。", "閑試新收硯，重尋久廢琴。", "何時見朋舊，細話別來心。"]'),
('740d93c6-b786-43b0-b404-fa01f8cbf312','庚申元日口號六首  其一','陸游','宋','宋诗','song-poetry','','[]','數行晴日照青鴛，春入屠蘇瀲灧樽。',32,'全唐诗/poet.song.132000.json','["數行晴日照青鴛，春入屠蘇瀲灧樽。", "兒報山僧留刺去，未爲無客到吾門。"]'),
('9c1e9440-3ee1-4ebd-87fc-f5e5efe60af3','庚申元日口號六首  其二','陸游','宋','宋诗','song-poetry','','[]','黄絁五丈裁衫穩，黑黍三升作飯香。',32,'全唐诗/poet.song.132000.json','["黄絁五丈裁衫穩，黑黍三升作飯香。", "造物要教無愧怍，一身溫飽出耕桑。"]'),
('4f1bf2f0-e0ce-4466-a4f2-8a01756acc86','庚申元日口號六首  其三','陸游','宋','宋诗','song-poetry','','[]','南陌東阡自在身，耄年喜見歲華新。',32,'全唐诗/poet.song.132000.json','["南陌東阡自在身，耄年喜見歲華新。", "洛中九老非吾侶，且作山陰十老人。"]'),
('f9abe082-2196-4078-8916-7b95c21ab14d','庚申元日口號六首  其四','陸游','宋','宋诗','song-poetry','','[]','晚塗初入長生運，新歲仍當大有年。',32,'全唐诗/poet.song.132000.json','["晚塗初入長生運，新歲仍當大有年。", "剩與鄉鄰同覓醉，市樓酒賤不論錢。"]');
